INSERT INTO public.photos VALUES (25928, 'Ctra. de Valencia c.1970', 'Imagen capturada desde cierta altura con buena perspectiva del tramo de la carretera de Valencia a su paso por el barrio de Casablanca, desde la calle de la Escuela hasta la rotonda donde comenzaba la Vâ”œآ،a de la Hispanidad (antes carretera de los Enlaces), al fondo. Mâ”œأ­s allâ”œأ­, las originales torres de iluminaciâ”œâ”‚n del estadio municipal de la Romareda. A la izquierda, arbolado acceso al Cuartel de Sanidad, del que emerge el bloque de viviendas del nâ”¬â•‘ 1 de la Vâ”œآ،a de la Hispanidad, A la derecha, postes del tendido tranviario y bucle trazado al final de la lâ”œآ،nea 15 para solventar que era un tramo de vâ”œآ،a â”œâ•‘nica. Fuente visual: Nuria Asâ”œآ،n Garcâ”œآ،a, "Recuerdos de Casablanca", Ediciones 94, (2015).', 1970, 1970, 1970, 'Anos 70', 'CASABLANCA', 41.63013700, -0.90653100, '0101000020E6100000F6ECB94C4D02EDBFF17F4754A8D04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/35123028746.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/35123028746.webp', 'https://www.flickr.com/photos/zaragozaantigua/35123028746/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25936, 'C.â”¬آ¬ de Valencia 1954', 'Imagen capturada en la sureâ”œâ–’a tranviaria terminal de la lâ”œآ،nea 15. Casablanca, cuando la unidad 209 entra desde la carretera de Valencia en el bucle establecido alrededor del antiguo bar restaurante El Caserâ”œآ،o Aragonâ”œآ®s (a la izquierda y fuera de plano), para dar la vuelta e iniciar el recorrido de vuelta hacia la norteâ”œâ–’a terminal sita en la plaza de Espaâ”œâ–’a. Este bucle confrontaba con la Fuente de los Incrâ”œآ®dulos.', 1954, 1954, 1954, 'Anos 50', 'CASABLANCA', 41.62833800, -0.90762700, '0101000020E610000052EE3EC7470BEDBFC26A2C616DD04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49875294546.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49875294546.webp', 'https://www.flickr.com/photos/zaragozaantigua/49875294546/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (26026, 'Vâ”œآ،a de la Hispanidad 1991', 'Foto: Archivo Taumar (Irene Taulâ”œآ®s y Rafael Margalâ”œآ®). Vista aâ”œآ®rea de la Vâ”œآ،a Hispanidad, con la Torre de Telecomunicaciones de Telefâ”œâ”‚nica en construcciâ”œâ”‚n. Serâ”œأ­ inaugurada en 1992, convirtiâ”œآ®ndose en la estructura mâ”œأ­s alta de Zaragoza. Su nombre popular es El Pirulâ”œآ،, adaptando el de otras instalaciones similares, como la de Torrespaâ”œâ–’a en Madrid. Fuente: www.facebook.com/photo.php?fbid=1798223467068018&set=...', 1991, 1991, 1991, 'Anos 90', 'CASABLANCA', 41.63951000, -0.91322100, '0101000020E61000003FA7203F1B39EDBF84BBB376DBD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30014200512.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30014200512.webp', 'https://www.flickr.com/photos/zaragozaantigua/30014200512/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (26069, 'Vâ”œآ،a Hispanidad 1994', 'Imagen capturada desde la pronunciada altura de la moderna torre de Telefâ”œâ”‚nica, o "Pirulâ”œآ، de Zaragoza", construida junto a la Vâ”œآ،a de la Hispanidad, con una vista dirigida hacia el entronque con ella y mediante rotonda de la avenida de Gâ”œâ”‚mez Laguna. Destaca en el centro de la escena el esqueleto de obra, paralizado desde los aâ”œâ–’os 70, del que tendrâ”œآ،a que haber sido Hospital Oncolâ”œâ”‚gico de Zaragoza, cuya colocaciâ”œâ”‚n de la primera piedra en 1973 citâ”œâ”‚ a la hija del entonces Generalâ”œآ،simo, al doctor Fernando Cuenca Villoro, y a las principales autoridades locales del Râ”œآ®gimen. Poco despuâ”œآ®s esta estructura serâ”œآ،a derribada y sustituida por una exclusiva parcela de bloques de viviendas en el nâ”¬â•‘ 54 de la Vâ”œآ،a de la Hispanidad. Los solares de primer tâ”œآ®rmino tambiâ”œآ®n serâ”œأ­n urbanizados.', 1994, 1994, 1994, 'Anos 90', 'CASABLANCA', 41.64116000, -0.91396800, '0101000020E61000009BE5B2D1393FEDBF6EC0E78711D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50447493492.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50447493492.webp', 'https://www.flickr.com/photos/zaragozaantigua/50447493492/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21660, 'Rincâ”œâ”‚n de Goya 1927', 'Imagen capturada durante la construcciâ”œâ”‚n en el parque de Buenavista del Rincâ”œâ”‚n de Goya, segâ”œâ•‘n proyecto del arquitecto Fernando Garcâ”œآ،a Mercadal, con el que pretendiâ”œâ”‚ "no honrar a Goya con los manidos recursos: una estatua al pintor, muy bien sentadita en su pedestal esperando el homenaje admirativo de los pazguatos... No. Vanidad, ingenua vanidad, no." Dicho y hecho, esta bocanada de aire fresco arquitectâ”œâ”‚nica fue descalificada por el pazguatismo oficial "de bien" desde que terminaron las obras y fue inaugurado poco despuâ”œآ®s. Bajo el râ”œآ®gimen franquista y en 1945 el edificio fue desfigurado hasta hacerlo irreconocible. Tras la recuperaciâ”œâ”‚n de la democracia municipal fue objeto de otra intervenciâ”œâ”‚n en 1995 que supuso una nueva vuelta de tuerca donde se perdiâ”œâ”‚ la gran oportunidad de recuperar su estado original. Una penica.', 1927, 1927, 1927, 'Anos 20', 'CASABLANCA', 41.63035600, -0.89856500, '0101000020E610000053910A630BC1ECBF2F6B6281AFD04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54121187791.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54121187791.webp', 'https://www.flickr.com/photos/zaragozaantigua/54121187791/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22347, 'Rincâ”œâ”‚n de Goya 1965', 'Foto Gerardo Sancho, 1965. Grupo de muchachas posando en las escaleras de acceso al colegio San Benito, sito en el edificio del Rincâ”œâ”‚n de Goya del parque Primo de Rivera de Zaragoza. Se trata de la clausura de un curso de la Secciâ”œâ”‚n Femenina de la Falange Espaâ”œâ–’ola Tradicionalista y de las Juntas de Ofensiva Nacional Sindicalista, el 21 de junio de 1965. Fuente: Archivo Municipal de Zaragoza.', 1965, 1965, 1965, 'Anos 60', 'CASABLANCA', 41.63035600, -0.89856500, '0101000020E610000053910A630BC1ECBF2F6B6281AFD04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20320369991.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20320369991.webp', 'https://www.flickr.com/photos/zaragozaantigua/20320369991/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23989, 'Miguel Bosâ”œآ® 1986', 'Foto Elena Casaucau, 1986. Instantâ”œأ­nea tomada en el Anfiteatro del Rincâ”œâ”‚n de Goya del Parque Grande de Zaragoza, durante un concierto de Miguel Bosâ”œآ® en 1986. Fuente: www.facebook.com/zgz80s/photos/a.127459403989874.22917.12...', 1986, 1986, 1986, 'Anos 80', 'CASABLANCA', 41.62998900, -0.89930200, '0101000020E6100000CC46E7FC14C7ECBF7DEBC37AA3D04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18673043303.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18673043303.webp', 'https://www.flickr.com/photos/zaragozaantigua/18673043303/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24018, 'Anfiteatro Rincâ”œâ”‚n de Goya 2006', 'Esta zona del antiguo Rincâ”œâ”‚n de Goya en el Parque de Buenavista, a mediados de la dâ”œآ®cada de los aâ”œâ–’os 80 conociâ”œâ”‚ una importante intervenciâ”œâ”‚n cuando el arquitecto municipal Ricardo Usâ”œâ”‚n diseâ”œâ–’â”œâ”‚ un auditorio, al aire libre, e inmediato al proyecto original de Garcâ”œآ،a Mercadal. Se realizaron nuevos accesos, taquillas, quioscos, escenario, graderâ”œآ،o y servicios accesorios, que lo convirtieron en un importante espacio sociocultural para la ciudad del momento. Con el transcurso del tiempo, la apariciâ”œâ”‚n de otros espacios, la intensa circulaciâ”œâ”‚n de la Z-30, entre otras razones, llevaron a su abandono, y acusado deterioro de las instalaciones. En 2005, el Ayuntamiento presentâ”œâ”‚ un proyecto de transformaciâ”œâ”‚n de la zona, que conllevaba desmantelarlo. Se produjeron movilizaciones, recogidas de firmas y apoyos, y un concierto como protesta ante la decisiâ”œâ”‚n, aunque la suerte estaba echada. En la imagen, aspecto de la zona inmediatamente antes del programado derribo. Fuente visual: territoriosonoro.hol.es/', 2006, 2006, 2006, 'Siglo XXI', 'CASABLANCA', 41.63031300, -0.89966500, '0101000020E61000000B630B410ECAECBF309FAC18AED04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24564818620.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24564818620.webp', 'https://www.flickr.com/photos/zaragozaantigua/24564818620/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24050, 'Anfiteatro Rincâ”œâ”‚n de Goya 2006', 'Foto: Juan Carlos Arcos. Aspecto de la ubicaciâ”œâ”‚n del anfiteatro del Rincâ”œâ”‚n de Goya en el parque Primo de Rivera, construido segâ”œâ•‘n proyecto de Ricardo Usâ”œâ”‚n en 1985. Fue derribado en octubre de 2006, y el entorno vuelto a urbanizar como zona verde posteriormente. Fuente: Heraldo de Aragâ”œâ”‚n.', 2006, 2006, 2006, 'Siglo XXI', 'CASABLANCA', 41.63029200, -0.89990400, '0101000020E61000004644317903CCECBF18778368ADD04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31278814154.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31278814154.webp', 'https://www.flickr.com/photos/zaragozaantigua/31278814154/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24952, 'Rincâ”œâ”‚n de Goya ca. 1927', 'Ilustraciâ”œâ”‚n del Rincâ”œâ”‚n de Goya del parque de Buenavista, proyectado por Fernando Garcâ”œآ،a Mercadal en 1926 e inaugurado en 1928. Este dibujo formaba parte de una colecciâ”œâ”‚n de postales editadas por la tipogrâ”œأ­fica del Heraldo de Aragâ”œâ”‚n, con diversas localizaciones de Zaragoza. Fuente: www.todocoleccion.net', 1927, 1927, 1927, 'Anos 20', 'CASABLANCA', 41.63035600, -0.89856500, '0101000020E610000053910A630BC1ECBF2F6B6281AFD04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/36770161586.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/36770161586.webp', 'https://www.flickr.com/photos/zaragozaantigua/36770161586/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25074, 'Ramâ”œâ”‚n Acâ”œآ،n 1930', '"Ramâ”œâ”‚n Acâ”œآ،n, sentado junto a sus esculturas en el Rincâ”œâ”‚n de Goya". En la primavera de 1930 se organizâ”œâ”‚ en el "Rincâ”œâ”‚n de Goya" una exposiciâ”œâ”‚n del multifacâ”œآ®tico artista oscense Ramâ”œâ”‚n Acâ”œآ،n con esculturas, maquetas, impresos y pinturas. En la imagen, capturada en el interior del edificio diseâ”œâ–’ado por Fernando Garcâ”œآ،a Mercadal, las obras "Bailadera", "Baâ”œâ–’ista" y "Maqueta para un monumento a la Paz", ademâ”œأ­s de una jaula con pajarita encerrada, posan junto al sedente autor. Unos meses despuâ”œآ®s, Acâ”œآ،n se involucrarâ”œأ­ en la Sublevaciâ”œâ”‚n de Jaca, aunque su fracaso le hizo exiliarse a Francia. Regresâ”œâ”‚ tras el 14 de abril de 1931, y siguiâ”œâ”‚ compaginando sus actividades artâ”œآ،sticas (entre ellas, "producir" la pelâ”œآ،cula de Luis Buâ”œâ–’uel "Las Hurdes, tierra sin pan"), con su militancia anarquista. Tras el 18 de julio de 1936, fue asesinado por los golpistas de Huesca. Fuente: Foto Abelardo de la Barrera, en servicios3.aragon.es/', 1930, 1930, 1930, 'Anos 30', 'CASABLANCA', 41.63035600, -0.89856500, '0101000020E610000053910A630BC1ECBF2F6B6281AFD04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19978071214.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19978071214.webp', 'https://www.flickr.com/photos/zaragozaantigua/19978071214/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22100, 'Escuela infantil Casablanca 1955', 'Grupo de niâ”œâ–’os y niâ”œâ–’as posando con su maestra doâ”œâ–’a Paquita en la Escuela Infantil del barrio de Casablanca, sita en la manzana entre la calle del Embarcadero (antigua de la Ermita) y de las Escuelas, hacia 1955. Fuente visual: Nuria Asâ”œآ،n Garcâ”œآ،a, "Recuerdos de Casablanca", Ediciones 94, (2015).', 1955, 1955, 1955, 'Anos 50', 'CASABLANCA', 41.62974900, -0.90728400, '0101000020E6100000DAE385747808EDBF27D87F9D9BD04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20439782495.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20439782495.webp', 'https://www.flickr.com/photos/zaragozaantigua/20439782495/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22291, 'Vâ”œآ،a Hispanidad 1969', 'Imagen de la gasolinera de Casablanca, junto a la Vâ”œآ،a Hispanidad (izquierda), y el desemboque de la calle La Vâ”œآ،a en ella (donde el cartel publicitario). Esta calle recuerda, de alguna forma, el antiguo trazado de la lâ”œآ،nea de Cariâ”œâ–’ena a Zaragoza por estos lares, hasta su desmantelamiento en los aâ”œâ–’os 30. Al fondo, los enormes bloques de Isabel la Catâ”œâ”‚lica. A la derecha, los â”œâ•‘ltimos bloques del comienzo de la Vâ”œآ،a Hispanidad. Fuente visual: "Zaragoza viva" (1969)', 1969, 1969, 1969, 'Anos 60', 'CASABLANCA', 41.63346300, -0.90829200, '0101000020E610000065FD6662BA10EDBFEF1CCA5015D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15259370703.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15259370703.webp', 'https://www.flickr.com/photos/zaragozaantigua/15259370703/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22847, 'Rincâ”œâ”‚n de Goya c.1982', 'Edificio del Rincâ”œâ”‚n de Goya, en los aâ”œâ–’os 80. Fuente: www.facebook.com/photo.php?fbid=998861186796393&set=o...', 1982, 1982, 1982, 'Anos 80', 'CASABLANCA', 41.63035600, -0.89856500, '0101000020E610000053910A630BC1ECBF2F6B6281AFD04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15149704803.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15149704803.webp', 'https://www.flickr.com/photos/zaragozaantigua/15149704803/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22859, 'Isabel la Catâ”œâ”‚lica 1987', 'Luis Mâ”œآ،nguez. 1987. Imagen del paseo de Isabel la Catâ”œâ”‚lica desde la torre-mirador de la Feria de Muestras. Al fondo, encuentro de este paseo con la Vâ”œآ،a de la Hispanidad en la denominada "Rotonda ciudad de Toulouse", donde una escultura de â”œأ¼ngel Orensanz (aquâ”œآ، tapada por los â”œأ­rboles) celebra el bimilenario de la ciudad. En el arranque de la Vâ”œآ،a Ibâ”œآ®rica, visual del inicio del barrio de Casablanca. A la izquierda, los gigantes desarrollistas, y un pedacito del Instituto "Miguel Catalâ”œأ­n". A la derecha, un poco antes, el nuevo convento de Jerusalen, trasplantado en 1946 desde el paseo de la Independencia a un entorno en el que pronto quedâ”œâ”‚ como una miniatura constructiva. Este paseo era la entrada/salida natural a la ciudad desde la carretera de Valencia, con todo lo que ello suponâ”œآ،a.', 1987, 1987, 1987, 'Anos 80', 'CASABLANCA', 41.63400000, -0.90307800, '0101000020E61000003A9677D503E6ECBFFED478E926D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15648197229.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15648197229.webp', 'https://www.flickr.com/photos/zaragozaantigua/15648197229/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22903, 'Anfiteatro del Rincâ”œâ”‚n de Goya 1989', 'Desde el inicio de los aâ”œâ–’os 80 se celebraban conciertos en una natural ladera cercana al edificio del Rincâ”œâ”‚n de Goya, y a mediados de la dâ”œآ®cada, durante la eclosiâ”œâ”‚n de la movida, el Ayuntamiento decidiâ”œâ”‚ construir allâ”œآ، el llamado Anfiteatro, con proyecto Ricardo Usâ”œâ”‚n Garcâ”œآ،a y como escenario estable de representaciones y actuaciones al aire libre, sobre todo en las tardes y noches del verano. Por â”œآ®l pasaron algunas seâ”œâ–’eras figuras y grupos de la escena musical contemporâ”œأ­nea. En la imagen aparecen tambiâ”œآ®n las gradas aâ”œâ–’adidas a posteriori. Fue desmantelado en 2007 tras un perâ”œآ،odo de abandono y degradaciâ”œâ”‚n, cuando ya hacâ”œآ،a tiempo que el paso del Cinturâ”œâ”‚n de Ronda, a espaldas del fotâ”œâ”‚grafo, con sus severas afecciones acâ”œâ•‘sticas habâ”œآ،a sentenciado la continuidad de este enclave. Desde entonces perdura como una accidentada extensiâ”œâ”‚n del actual Parque Grande Josâ”œآ® Antonio Labordeta.', 1989, 1989, 1989, 'Anos 80', 'CASABLANCA', 41.62998900, -0.89930200, '0101000020E6100000CC46E7FC14C7ECBF7DEBC37AA3D04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21487482990.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21487482990.webp', 'https://www.flickr.com/photos/zaragozaantigua/21487482990/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22945, 'P.â”¬â•‘ de Isabel la Catâ”œâ”‚lica c.1985', 'Aâ”œآ®rea visual sobre la gran rotonda en la que confluâ”œآ،an el final paseo de Isabel la Catâ”œâ”‚lica y el arranque de la Vâ”œآ،a Hispanidad y la Vâ”œآ،a Ibâ”œآ®rica. En la rotonda destaca la representaciâ”œâ”‚n alegâ”œâ”‚rica "Bimilenario" realizada por el escultor â”œأ¼ngel Orensanz. En primer tâ”œآ®rmino, el cuartel de Sanidad. Fuente visual: AMZ.', 1985, 1985, 1985, 'Anos 80', 'CASABLANCA', 41.63223800, -0.90515800, '0101000020E6100000FFCEF6E80DF7ECBFECA4BE2CEDD04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/37831864185.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/37831864185.webp', 'https://www.flickr.com/photos/zaragozaantigua/37831864185/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23483, 'P.â”¬â•‘ de Ruiseâ”œâ–’ores 1960', 'Dibujo del nuevo colegio de Santo Tomâ”œأ­s de Aquino abierto en el paseo de Ruiseâ”œâ–’ores tras el cierre del prâ”œآ،stino colegio de la calle del Buen Pastor. La que fuera original "Villa Rosita" al principio del siglo XX se encaminâ”œâ”‚ a su sexta dâ”œآ®cada de existencia bien distinta de la que fuera diseâ”œâ–’ada por Manuel Isasi Isasmendi. A la izquierda, las empinadas escaleras de acceso al patio de recreo. A la derecha, fachada e ingreso principal donde destaca el esquinero torreâ”œâ”‚n de aires modernistas. Este colegio cerrarâ”œآ،a sus puertas en 1986 y serâ”œآ،a vendido a una constructora. En consecuencia, las instalaciones fueron remodeladas aâ”œâ–’os despuâ”œآ®s para exclusivas viviendas, e incluso se habilitâ”œâ”‚ un espacio para una fantasmagâ”œâ”‚rica "Fundaciâ”œâ”‚n Manuel Labordeta". Fuente visual: "Grabado en la mente. Historia del Colegio Santo Tomaâ• أ¼s Aquino de Zaragoza", Santiago Sancho Vallestâ”œآ،n.', 1960, 1960, 1960, 'Anos 60', 'UNIVERSIDAD', 41.63651000, -0.88907700, '0101000020E61000007D06D49B5173ECBFDAC9E02879D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/44612525065.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/44612525065.webp', 'https://www.flickr.com/photos/zaragozaantigua/44612525065/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24933, 'Rincâ”œâ”‚n de Goya 1928', 'El Rincâ”œâ”‚n de Goya, cuyo proyecto de Fernando Garcâ”œآ،a Mercadal data de 1926, es obra pionera de la arquitectura moderna en Espaâ”œâ–’a. Finalizado en 1928, estaba dedicado a conmemorar a Goya, en una zona de especial recogimiento, en un jardâ”œآ،n dentro de un anfiteatro natural, bordeado por el râ”œآ،o Huerva, que pasaba cerca de Fuendetodos, y que ejercâ”œآ،a de nexo de uniâ”œâ”‚n entre este lugar, y Zaragoza. Pero lo que los câ”œأ­nones, la tradiciâ”œâ”‚n y el consenso esperaban (una figura de Goya con paleta y pincel, y acompaâ”œâ–’ado por la tropa aragonesa), se convierte en un edificio abierto a un jardâ”œآ،n, con una biblioteca y un museo sobre la vida y obra del pintor. La prensa del momento, ejerciendo de la voz de su amo, oscilâ”œâ”‚ entre rogar que la vegetaciâ”œâ”‚n creciera deprisa para tapar el engendro, o esperar a que alguien lo abriera para dejar salir la estatua que contenâ”œآ،a dentro. La sociedad del orden echâ”œâ”‚ sobre â”œآ®l un velo de olvido, que continâ”œâ•‘a en nuestros dâ”œآ،as, ademâ”œأ­s de transformarlo hasta dejarlo irreconocible. Pasâ”œâ”‚ el 250 aniversario del natalicio de Goya, y no pasâ”œâ”‚ nada. A ver en el aniversario 275. Fuente: "Luces de la ciudad. Arte y Cultura en Zaragoza. 1914-1936", aâ”œâ–’o 1995.', 1928, 1928, 1928, 'Anos 20', 'CASABLANCA', 41.63048000, -0.89870600, '0101000020E6100000DA01D71533C2ECBF1B649291B3D04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15313189589.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15313189589.webp', 'https://www.flickr.com/photos/zaragozaantigua/15313189589/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24935, 'Rincâ”œâ”‚n de Goya 1928', 'Imagen de la inauguraciâ”œâ”‚n oficial del "Rincâ”œâ”‚n de Goya", que tuvo lugar el 16 de abril de 1928, dentro d elos actos de conmemoraciâ”œâ”‚n del centenario de la muerte de Francisco Goya. Fue diseâ”œâ–’ado por Fernando Garcâ”œآ،a Mercadal, en el entorno ordenado a su alrededor del Parque de Buena Vista. Al acto de inauguraciâ”œâ”‚n asistieron autoridades militares, religiosas, y algunas civiles como el Alcalde y el Gobernador Civil, con amenizaciâ”œâ”‚n musical a cargo de "la Banda del Hospicio", que interpretâ”œâ”‚ obras de la â”œآ®poca (de Goya). En aquâ”œآ®l momento se pensaba destinar el edificio a "Biblioteca", y el entorno, "a lugar de evocaciâ”œâ”‚n de la memoria del pintor". Quâ”œآ® cosas. Fuente visual: Foto Palacio para "Aragâ”œâ”‚n : revista grâ”œأ­fica de cultura aragonesa" (Aâ”œâ–’o V, Nâ”¬â•‘ 42, marzo 1929).', 1928, 1928, 1928, 'Anos 20', 'CASABLANCA', 41.63049700, -0.89878400, '0101000020E6100000C860C5A9D6C2ECBFF19C2D20B4D04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15487156048.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15487156048.webp', 'https://www.flickr.com/photos/zaragozaantigua/15487156048/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24939, 'Rincâ”œâ”‚n de Goya 1928', '"Jardines denominados Rincâ”œâ”‚n de Goya, en Zaragoza, que se inaugurarâ”œأ­n con motivo del Centenario". Fuente visual: foto Vidal, en "La Esfera", 21 de abril de 1928.', 1928, 1928, 1928, 'Anos 20', 'CASABLANCA', 41.63035600, -0.89856500, '0101000020E610000053910A630BC1ECBF2F6B6281AFD04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20025226882.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20025226882.webp', 'https://www.flickr.com/photos/zaragozaantigua/20025226882/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25092, 'Rincâ”œâ”‚n de Goya 1930', 'Imagen capturada en el interior del original y vilipendiado edificio del Rincâ”œâ”‚n de Goya en el Parque de Buenavista, con Juan Josâ”œآ® Luis Gonzâ”œأ­lez Bernal, pintor local vanguardista vinculado con la corriente surrealista radical, posando junto a un muestrario de los â”œâ”‚leos, dibujos y guaches que allâ”œآ، exponâ”œآ،a. Fuente visual: "Andalâ”œأ­n, periâ”œâ”‚dico quincenal aragonâ”œآ®s".', 1930, 1930, 1930, 'Anos 30', 'CASABLANCA', 41.63035600, -0.89856500, '0101000020E610000053910A630BC1ECBF2F6B6281AFD04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32630953135.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32630953135.webp', 'https://www.flickr.com/photos/zaragozaantigua/32630953135/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25629, 'Pedro IV 1974', 'Imagen del nuevo polâ”œآ،gono Romareda, centrada en el bloque en construcciâ”œâ”‚n del nâ”¬â•‘ 4 de la calle de Pedro IV el Ceremonioso. A la izquierda, la calle de Juan II de Aragâ”œâ”‚n, donde destaca el bloque del nâ”¬â•‘ 8 de esa calle, y comienzan a emerger en superficie, junto a â”œآ®l, los andamios de obra del futuro nâ”¬â•‘ 6 de Pedro IV. La captura se ha realizado, posiblemente, desde las alturas de la torre con el nâ”¬â•‘ 5 del paseo de Isabel la Catâ”œâ”‚lica. Fuente visual: diario "El Noticiero". Archivo Josâ”œآ® Marâ”œآ،a Ballestâ”œآ،n Miguel.', 1974, 1974, 1974, 'Anos 70', 'CASABLANCA', 41.63392200, -0.90433200, '0101000020E61000009F3D97A949F0ECBF821B295B24D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33564088612.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33564088612.webp', 'https://www.flickr.com/photos/zaragozaantigua/33564088612/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25634, 'Vista suroeste 2011', 'Vista aâ”œآ®rea del eje suroeste de Zaragoza, desde el paseo de Isabel la Catâ”œâ”‚lica hasta Valdespartera, pasando por la Vâ”œآ،a Ibâ”œآ®rica, en abril de 2011. Fuente: Paisajes urbanos residenciales en la Zaragoza contemporâ”œأ­nea, Universidad de Zaragoza, 2012.', 2011, 2011, 2011, 'Siglo XXI', 'CASABLANCA', 41.63265600, -0.90521300, '0101000020E6100000E23FDD4081F7ECBF20CF2EDFFAD04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/40646860472.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/40646860472.webp', 'https://www.flickr.com/photos/zaragozaantigua/40646860472/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21815, 'Radio Zaragoza 1938', 'Portada de un folleto propagandâ”œآ،stico de Radio Zaragoza de FET y de las JONS (EAJ 101), realizado en el III aâ”œâ–’o Triunfal, tras la inauguraciâ”œâ”‚n del nuevo complejo emisor situado en la parte alta de Casablanca, junto al Canal Imperial, representado con un dibujo decorado con sendas y coloristas banderas de la Espaâ”œâ–’a nacionalista, y de Falange. A su lado, un recorte fotogrâ”œأ­fico del Pilar, cuyas torres equilibran las monumentales antenas que permitâ”œآ،an llegar a las ondas hasta el estado norteamericano de Massachusetts. Otro recorte de la puerta del Carmen, completa la composiciâ”œâ”‚n, que es coronada hâ”œأ­bilmente por un micrâ”œâ”‚fono de la emisora, a modo de subliminal sâ”œآ،mil mariano. Fuente visual: www.todocoleccion.net/', 1938, 1938, 1938, 'Anos 30', 'CASABLANCA', 41.63556600, -0.91609100, '0101000020E6100000321EA5129E50EDBF8A39083A5AD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30805857222.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30805857222.webp', 'https://www.flickr.com/photos/zaragozaantigua/30805857222/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21869, 'Canal Imperial 1935', 'Imagen capturada durante el paso del ferrocarril de Caminreal por el reciente puente construido sobre el Canal Imperial, en territorio de Miralbueno el Viejo y muy cerca de los depâ”œâ”‚sitos de agua de Casablanca (al fondo). Hacia la derecha, y tras cruzar el Canal, el recorrido lleva hacia Valdespartera, donde el tendido gira hasta ponerse en paralelo a la carretera de Zaragoza a Valencia. Fuente visual: Revista Blanco y Negro.', 1935, 1935, 1935, 'Anos 30', 'CASABLANCA', 41.63594000, -0.92283000, '0101000020E6100000D690B8C7D287EDBFEF1B5F7B66D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/36520625422.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/36520625422.webp', 'https://www.flickr.com/photos/zaragozaantigua/36520625422/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24813, 'Arrabal c.1900', 'â”œأ´leo de Leopoldo Albesa. Vista de la entrada de la calle Sobrarbe en el barrio del Arrabal, desde el puente de Piedra. Fuente: Heraldo de Aragâ”œâ”‚n.', 1900, 1900, 1900, 'Anos 1900', 'CASCO HISTâ”œأ´RICO', 41.65798400, -0.87492500, '0101000020E6100000567DAEB662FFEBBF48A5D8D138D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/39310535830.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/39310535830.webp', 'https://www.flickr.com/photos/zaragozaantigua/39310535830/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22039, 'Franco 1953', 'Ayuntamiento de Zaragoza/Marâ”œآ،n Chivite. 21 junio 1953. "Despuâ”œآ®s de su recorrido triunfal por tierras de las tres provincias aragonesas, el Jefe del Estado, acompaâ”œâ–’ado de su esposa, permaneciâ”œâ”‚ casi dos dâ”œآ،as en nuestra ciudad, en los que tuvo ocasiâ”œâ”‚n de visitar los principales edificios oficiales que han sido construidos en estos â”œâ•‘ltimos aâ”œâ–’os, los depâ”œâ”‚sitos de abastecimiento de aguas y estaciâ”œâ”‚n de coagulaciâ”œâ”‚n y admirar el desarrollo urbanâ”œآ،stico de Zaragoza. Preocupaciâ”œâ”‚n preferente del Caudillo y de su esposa fuâ”œآ® (sic) la visita al templo del Pilar, para adorar a la Virgen, a la que tantas veces se encomendâ”œâ”‚ y pidiâ”œâ”‚ su protecciâ”œâ”‚n el Generalâ”œآ،simo durante la Cruzada espaâ”œâ–’ola, que tan victoriosamente supo ganar a los enemigos de Espaâ”œâ–’a. En la Diputaciâ”œâ”‚n Provincial fueron obsequiados los insignes huâ”œآ®spedes con una cena de gala, y por todas partes el pueblo de Zaragoza les hizo objeto de las mâ”œأ­s entusiastas aclamaciones." Revista "Aragâ”œâ”‚n", Sindicato de Iniciativa y Propaganda, nâ”œâ•‘m. 227, abril-junio 1953. En la imagen, el Jefe del Estado, Franco, disfrazado de civil visita los nuevos depâ”œâ”‚sitos de agua de Casablanca, acompaâ”œâ–’ado por el camisa azul bajo chaqueta blanca y Alcalde de la ciudad, Josâ”œآ® Marâ”œآ،a Garcâ”œآ،a Belenguer (de 1949 a 1954).', 1953, 1953, 1953, 'Anos 50', 'CASABLANCA', 41.63436900, -0.91677900, '0101000020E6100000501BD5E94056EDBF514CDE0033D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14732077209.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14732077209.webp', 'https://www.flickr.com/photos/zaragozaantigua/14732077209/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23387, 'Embarcadero de Valdefierro 2008', 'Construcciâ”œâ”‚n del embarcadero del Canal Imperial de Aragâ”œâ”‚n en el barrio de Valdefierro, junto al cruce de las calles Centauro y Casiopea. La obra se enmarcaba en un plan abortado para volver a hacer navegable el Canal en Zaragoza, con cuatro embarcaderos: â”œآ®ste, el de la calle â”œأ¼frica, el de La Paz y el de los depâ”œâ”‚sitos de Casablanca, esclusa incluida. Todo ello en el marco del plan de riberas de la Expo 2008. Fuente: Heraldo de Aragâ”œâ”‚n.', 2008, 2008, 2008, 'Siglo XXI', 'CASABLANCA', 41.63475000, -0.93335700, '0101000020E6100000F8C3CF7F0FDEEDBF6891ED7C3FD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31899317773.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31899317773.webp', 'https://www.flickr.com/photos/zaragozaantigua/31899317773/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23413, 'Suroeste 2001', 'Ortofoto de los terrenos en que se irâ”œأ­n construyendo los nuevos barrios del suroeste de Zaragoza. En la imagen, ya edificado el de Montecanal, al sur de Valdefierro y el Canal Imperial de Aragâ”œâ”‚n. A la izquierda, el futuro Arcosur; al norte, lo que serâ”œأ­ Rosales del Canal; al este, Valdespartera. Rodea sinuoso por el sur el trazado del hoy terminado Cuarto Cinturâ”œâ”‚n o Z-40. Fuente visual: www.nacionrotonda.com/', 2001, 2001, 2001, 'Siglo XXI', 'CASABLANCA', 41.62974000, -0.94912300, '0101000020E61000007F349C32375FEEBFD47D00529BD04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/25656822895.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/25656822895.webp', 'https://www.flickr.com/photos/zaragozaantigua/25656822895/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23721, 'Enlace de Carreteras 1965', 'Vista aâ”œآ®rea sobre el Enlace de Carreteras en un dâ”œآ،a de poco trâ”œأ­fico, poco antes de su redenominaciâ”œâ”‚n como Vâ”œآ،a de la Hispanidad. En primer plano, las instalaciones de ARVIN, Aragonesa Vinâ”œآ،cola, S.A., planta embotelladora de caldos provenientes de cooperativas de la provincia, esquinera con el serpenteante y albino camino del Terminillo, que viene de cruzarse, poco antes, con el camino de la Mosquetera. Al fondo, el telâ”œâ”‚n edilicio del suroeste de la ciudad, delimitado por el colegio Mayor Pedro Cerbuna, la Hâ”œآ،pica, el cuartel de Palafox, la Feria de Muestras, y el estadio municipal de la Romareda. Confrontaban con la embotelladora, al otro lado del enlace de Carreteras, los depâ”œâ”‚sitos de agua de Casablanca, y justo a su izquierda, una recta fila de seâ”œâ–’alados mojones anuncia la inminencia de la prolongaciâ”œâ”‚n hasta estos lares de la avenida de San Juan Bosco, pronto denominada alcalde Gâ”œâ”‚mez Laguna. Fuente visual: Arxiu Nacional de Catalunya.', 1965, 1965, 1965, 'Anos 60', 'CASABLANCA', 41.64009600, -0.91379500, '0101000020E61000003DF20703CF3DEDBF74266DAAEED14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31730563856.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31730563856.webp', 'https://www.flickr.com/photos/zaragozaantigua/31730563856/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21074, 'Sindicato de Riego de Miraflores 1871', '"Plano catastral de las fincas que en el Canal Imperial de Aragâ”œâ”‚n componen el Sindicato de Riego de Miraflores", Joaquâ”œآ،n Pâ”œآ®rez de Rozas, Zaragoza, 1871. Comprende las tierras de cultivo del sureste de Zaragoza, entre el râ”œآ،o Ebro y el Canal Imperial. Arriba a la izquierda, entorno del soto de Cantalobos; a la derecha, la Cartuja de Miraflores o Cartuja Baja; abajo a la izquierda, la almenara de San Antonio. Fuente: AMZ.', 1871, 1871, 1871, 'Siglo XIX', 'LA CARTUJA BAJA', 41.60452400, -0.82252600, '0101000020E6100000A182C30B2252EABFD4D2DC0A61CD4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20460366564.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20460366564.webp', 'https://www.flickr.com/photos/zaragozaantigua/20460366564/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21754, 'Cartuja Baja 1933', 'Imagen de la "Procura" de la Cartuja de la Inmaculada Concepciâ”œâ”‚n, edificio destinado a residencia y administraciâ”œâ”‚n del complejo conventual. Construido entre 1686 y 1698, es de planta rectangular, en ladrillo visto, y aires de casona barroca. Posteriormente fue adaptada para viviendas particulares. Se localiza en la gran plaza que centraliza el espacio cartujano y flanquea, junto con la bodega-hospederâ”œآ،a, la gran iglesia. Fuente visual: Archivo Juan Mora Insa (DARA-AHPZ).', 1933, 1933, 1933, 'Anos 30', 'LA CARTUJA BAJA', 41.60509600, -0.82278200, '0101000020E61000005F99B7EA3A54EABF607825C973CD4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22335594219.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22335594219.webp', 'https://www.flickr.com/photos/zaragozaantigua/22335594219/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23377, 'Canal Imperial 1790', '"Plano que manifiesta la situaciâ”œâ”‚n del Canal Ymperial desde la Val de la Cartuja, y paso de ganados hasta la Casa de Paradas, sitio para las tres Ynclusas proyectadas segun la demarcacion hecha anteriormente", Fâ”œآ®lix Guitarte, Zaragoza, 20 de febrero de 1790. Tramo del Canal Imperial de Aragâ”œâ”‚n a la altura de la Cartuja Baja o de la Concepciâ”œâ”‚n (arriba). Fuente: bibliotecavirtual.aragon.es/', 1790, 1790, 1790, 'Siglo XIX', 'LA CARTUJA BAJA', 41.60058000, -0.82539400, '0101000020E610000066118AADA069EABFDB5031CEDFCC4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20569091765.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20569091765.webp', 'https://www.flickr.com/photos/zaragozaantigua/20569091765/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23755, 'La Cartuja Baja 1998', 'La Cartuja Baja o de la Concepciâ”œâ”‚n de Zaragoza, acuarela de Teodoro Pâ”œآ®rez Bordetas, 1998. Fuente: www.aragonesasi.com', 1998, 1998, 1998, 'Anos 90', 'LA CARTUJA BAJA', 41.60452400, -0.82252600, '0101000020E6100000A182C30B2252EABFD4D2DC0A61CD4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19569357092.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19569357092.webp', 'https://www.flickr.com/photos/zaragozaantigua/19569357092/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24025, 'Parque de Buenavista 1940', 'Imagen con alumnas del Colegio Alemâ”œأ­n de la calle de Cervantes, ejecutanto artâ”œآ،sticos ejercicios y danzas folclâ”œâ”‚ricas del Reich, durante la Fiesta del Trabajo (denominaciâ”œâ”‚n nacionalsocialista del 1â”¬â•‘ de mayo) conmemorada por la colonia alemana de la ciudad, con presencia de autoridades locales, y tras el discurso del jefe de la secciâ”œâ”‚n local zaragozana del partido nazi (NSDAP), que tenâ”œآ،a su sede en esa misma ubicaciâ”œâ”‚n. La captura se ha realizado en los jardines del chalet de Las Palmeras, junto al cabezo de Buenavista, en el gran parque originalmente del mismo nombre, luego redenominado en honor al dictador Primo de Rivera.', 1940, 1940, 1940, 'Anos 40', 'UNIVERSIDAD', 41.63358500, -0.89305600, '0101000020E6100000F3E32F2DEA93ECBF3A1E335019D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24762276502.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24762276502.webp', 'https://www.flickr.com/photos/zaragozaantigua/24762276502/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25538, 'Cartuja Baja 1734', 'Grabado de la Cartuja de la Inmaculada Concepciâ”œâ”‚n, extramuros de Zaragoza, cuya fecha de capitulaciâ”œâ”‚n y concordia de fundaciâ”œâ”‚n es la que en â”œآ®l figura (1634), pero cuya construcciâ”œâ”‚n se iniciâ”œâ”‚ en 1651, y se prolongâ”œâ”‚ hasta mediados del siglo XVIII. Su iglesia, por ejemplo, fue consagrada en 1731. Se trata, pues, de un dibujo muy posterior, que no obstante recoge muy bien la planta original del conjunto, que como queda claro, estaba perfectamente orientado hacia el camino principal que pasaba junto a la porterâ”œآ،a de la Cartuja, y no como ahora, que parece que estâ”œآ® al revâ”œآ®s. Realizada en ladrillo, es de planta rectangular, delimitada por una muralla de ladrillo reforzada por cubos circulares. En su centro estâ”œأ­ la iglesia, que articula todo el espacio interior: es de planta latina nave â”œâ•‘nica, testero recto, gran atrio, y poderosa torre visible desde lejos. Estâ”œأ­ decorada con yeserâ”œآ،as y pinturas murales barrocas. Hasta ella, y desde la puerta de acceso, hay un gran patio central flanqueado por la hospederâ”œآ،a y la procura. A ambos lados de la iglesia hay dos claustrillos, y detrâ”œأ­s de ella el gran claustro con el cementerio en su interior, y 36 celdas-residencias de los monjes alrededor, de dos pisos de altura, y cada una con su taller y huerto propio. Fuente visual: La hormiga de Oro, 1928.', 1734, 1734, 1734, 'Siglo XIX', 'LA CARTUJA BAJA', 41.60452400, -0.82252600, '0101000020E6100000A182C30B2252EABFD4D2DC0A61CD4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19153707732.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19153707732.webp', 'https://www.flickr.com/photos/zaragozaantigua/19153707732/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21088, 'Puente de Amâ”œآ®rica 1872', 'Dibujo del Canal Imperial de Aragâ”œâ”‚n centrado en el original puente de Amâ”œآ®rica de un ojo, la imponente estructura del dique de carena o dâ”œأ­rsena del puerto de Miraflores, y algunas embarcaciones de carga en canalina singladura. Desde GAZA, gratis et amore, hemos volteado horizontalmente la composiciâ”œâ”‚n para que se corresponda de forma mâ”œأ­s satisfactoria con el pretâ”œآ®rito acontecido. Fuente: dibujo de Ferrer, en "La vuelta por Espaâ”œâ–’a : viaje histâ”œâ”‚rico, geogrâ”œأ­fico, cientâ”œآ،fico recreativo y pintoresco : historia popular de Espaâ”œâ–’a en su parte geogrâ”œأ­fica, civil y polâ”œآ،tica... / escrita en virtud de los datos adquiridos en las mismas localidades por una sociedad de literatos" (tomo I), Barcelona, 1872.', 1872, 1872, 1872, 'Siglo XIX', 'TORRERO', 41.63326100, -0.88474300, '0101000020E61000007DAD4B8DD04FECBF876A4AB20ED14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34844491606.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34844491606.webp', 'https://www.flickr.com/photos/zaragozaantigua/34844491606/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21201, 'Puente de Amâ”œآ®rica 1894', 'Imagen capturada en el embarcadero recreativo ubicado aguas arriba del decimonâ”œâ”‚nico puente de Amâ”œآ®rica sobre el Canal Imperial de Aragâ”œâ”‚n que daba acceso al camino del Cementerio. Por el alabeado ojo del puente y a la derecha, vista parcial del dique seco para embarcaciones de la empresa del canal, chopera y viveros canalinos. Al fondo y junto a la almenara de Miraflores que derivaba agua del canal en forma de la acequia del Ontanar, figura la gran casa de Pablo Salvador Lâ”œâ”‚pez donde estaba ubicado un prestigioso "restaurant" proyectado por el arquitecto Ricardo Magdalena Tabuenca que contaba con bar, billares y un salâ”œâ”‚n de piano decorado por los artistas plâ”œأ­sticos Dionisio Lasuâ”œآ®n Ferrer y Engenio Yanguas Ortiz.', 1894, 1894, 1894, 'Siglo XIX', 'TORRERO', 41.63325400, -0.88506400, '0101000020E610000001BEDBBC7152ECBFD50792770ED14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54189322967.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54189322967.webp', 'https://www.flickr.com/photos/zaragozaantigua/54189322967/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21212, 'Pasarela del Canal 1900', '"Zaragoza. Canal Imperial, Puente de entrada al Barrio de Venecia". Imagen convertida en tarjeta postal para la Uniâ”œâ”‚n Postal Universal, por la Fototipia de Lucas Escolâ”œأ­, del nuevo puente (peatonal) sobre el Canal Imperial, a la altura de la calle de Venecia (orilla derecha), y el paseo del Canal (orilla izquierda). La imagen estâ”œأ­ tomada desde la orilla derecha. Al fondo, tras la pasarela, la arbolada orilla de plâ”œأ­tanos de sombra recayente a la torre de Julia Arpal. Este puente fue realizado para dar acceso a la nueva barriada de Venecia, uno de esos nuevos barrios particulares, en este caso resultado de la parcelaciâ”œâ”‚n de la torre de Larraz.', 1900, 1900, 1900, 'Anos 1900', 'TORRERO', 41.63373500, -0.88853500, '0101000020E6100000573ECBF3E06EECBF50AA7D3A1ED14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14965110011.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14965110011.webp', 'https://www.flickr.com/photos/zaragozaantigua/14965110011/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21285, 'Puente de Amâ”œآ®rica 1903', 'Interesante imagen del Canal Imperial en un momento de temporal convivencia del antiguo y alabeado Puente de Amâ”œآ®rica, con el nuevo proyectado por Josâ”œآ® Marâ”œآ،a Royo Villanova, cuyas pilastras de canterâ”œآ،a emergen consolidadas desde el canalino cauce. El castrense puente de 1815 habâ”œآ،a sido construido como fiable acceso a los almacenes de pâ”œâ”‚lvora y las canteras de yeso del montecito de Torrero, ademas de para dar comunicacion con los pueblos de la Plana de Zaragoza. El nuevo y modernista puente, como radical nota diferencial, presentaba un gâ”œأ­libo rebajado al nivel de la calle que apostaba por la circulaciâ”œâ”‚n rodada por encima del puente, lo que supuso el final de la navegabilidad del Canal desde este punto, para las grandes embarcaciones. Unos meses despuâ”œآ®s de esta captura fotogrâ”œأ­fica, el viejo puente fue derribado, y el nuevo completado con la decoraciâ”œâ”‚n diseâ”œâ–’ada por Ricardo Magdalena, y las metâ”œأ­licas barandillas por Josâ”œآ® Gonzâ”œأ­lez. Se inaugurâ”œâ”‚ en octubre de ese aâ”œâ–’o. A la izquierda, la imponente figura de la dâ”œأ­rsena para reparaciâ”œâ”‚n de embarcaciones en seco. A la derecha, la "playa" del Canal, como lugar de esparcimiento ciudadano. Fuente visual: Fototipia de Lucas Escolâ”œأ­, en www.ebay.es/', 1903, 1903, 1903, 'Anos 1900', 'TORRERO', 41.63326100, -0.88474300, '0101000020E61000007DAD4B8DD04FECBF876A4AB20ED14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/25917667533.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/25917667533.webp', 'https://www.flickr.com/photos/zaragozaantigua/25917667533/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21308, 'Canal Imperial c.1906', 'Imagen editada como tarjeta postal para la Uniâ”œâ”‚n Postal Universal por la Fototipia de Lucas Escolâ”œأ­, centrada en la reciente pasarela sobre el Canal Imperial construida entre la calle de Venecia (a la izquierda), y el paseo del Canal (derecha). La imagen estâ”œأ­ tomada desde la norteâ”œâ–’a orilla del paseo del Canal. A la izquierda, la torre que se alzaba en el antiguo nâ”¬â•‘ 25 de la vâ”œآ،a de Pignatelli, con trasera a la calle de Royo. Al principio de los aâ”œâ–’os sesenta allâ”œآ، se levantarâ”œآ،an los actuales inmuebles del 53 y 55 de esa calle. Aâ”œâ–’os despuâ”œآ®s la pasarela fue sustituida por un puente con el gâ”œأ­libo rebajado para permitir el trâ”œأ­nsito rodado.', 1906, 1906, 1906, 'Anos 1900', 'TORRERO', 41.63373500, -0.88853500, '0101000020E6100000573ECBF3E06EECBF50AA7D3A1ED14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/35944365064.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/35944365064.webp', 'https://www.flickr.com/photos/zaragozaantigua/35944365064/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24903, 'P.â”¬â•‘ de Ruiseâ”œâ–’ores 1990', 'En marzo de 1994, el hotelito "Villa Alta", de la familia Ostalâ”œآ®, que tenâ”œآ،a adjudicado el nâ”¬â•‘ 37 del paseo de los Ruiseâ”œâ–’ores, fue derribado. Llevada abandonado muchos aâ”œâ–’os, y era un claro ejemplo de "barbecho" urbanâ”œآ،stico, aunque construido, a la espera del pelotazo. El arquitecto responsable argumentâ”œâ”‚ que el derribo "no fue deliberado", que su intenciâ”œâ”‚n era "rehabilitar la casa", pero que su estado de "autâ”œآ®ntico peligro" motivâ”œâ”‚ el derribo "por seguridad". Ante el revuelo levantado, explicâ”œâ”‚ que se dejarâ”œآ،a el edificio "tal como estaba", aunque opinaba que la casa no tenâ”œآ،a ningâ”œâ•‘n valor, porque cuando se construyâ”œâ”‚, segâ”œâ•‘n â”œآ®l en los aâ”œâ–’os 20 del pasado siglo XX, el estilo modernista de sus formas no se correspondâ”œآ،a con el estilo de su tiempo. Otras fuentes estiman, sin embargo, que su construcciâ”œâ”‚n debiâ”œâ”‚ ser entre 1912 y 1915, la edad de oro del modernismo local. Estaba arropado por un frondoso jardâ”œآ،n tapiado, y el nombre de "Villa Alta" le venâ”œآ،a que ni pintado, pues al estar sobre el perfil de una de las terrazas de Cuâ”œآ®llar, quedaba en notable altura respecto al nivel de la calle, y no digamos sobre lo que era la Zaragoza construida en aquellos aâ”œâ–’os. Fue realizado en formas hâ”œآ،bridas, incluyendo decoraciones modernistas de la Sezession, y unos juegos de tejados y chapitel del torreâ”œâ”‚n en estilo eclâ”œآ®ctico y norteâ”œâ–’o. Fue vendido por la familia Ostalâ”œآ® en los aâ”œâ–’os 40, y se convirtiâ”œâ”‚ en otra tarjeta del juego del monopoly local entre emprendedoras oligarquâ”œآ،as casatenientes y especuladoras. Tras el "humanitario" derribo, lo que se construyâ”œâ”‚ en su lugar estâ”œأ­ efectivamente inspirado en lo que habâ”œآ،a, aunque para el Ayuntamiento sâ”œâ”‚lo son merecedores de consideraciâ”œâ”‚n patrimonial la valla de la calle y el templete de acceso: son los â”œâ•‘nicos elementos originales no piqueteados. Fuente visual : "El desaparecido hotel "Villa Alta" de la familia Ostalâ”œآ® en el zaragozano Paseo de Ruiseâ”œâ–’ores", Mâ”¬آ¬ Pilar Poblador Muga, ARTIGRAMA Nâ”¬â•‘ 10, 1993.', 1990, 1990, 1990, 'Anos 90', 'UNIVERSIDAD', 41.63655800, -0.88880800, '0101000020E6100000988A8D791D71ECBFEB0088BB7AD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/17127156654.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/17127156654.webp', 'https://www.flickr.com/photos/zaragozaantigua/17127156654/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21329, 'Puente de Amâ”œآ®rica 1903', 'Notable imagen del Canal Imperial de Aragâ”œâ”‚n capturada durante la temporal convivencia del antiguo y alabeado puente de Amâ”œآ®rica, con el nuevo proyectado por Josâ”œآ® Marâ”œآ،a Royo Villanova, cuyas pilastras de canterâ”œآ،a emergen consolidadas desde el cauce canalino. El castrense puente de 1815 fue construido como fiable acceso a los almacenes de pâ”œâ”‚lvora y las canteras de yeso del montecito de Torrero, ademâ”œأ­s de para dar comunicaciâ”œâ”‚n con los pueblos de la Plana de Zaragoza. El nuevo y modernista puente, como radical nota diferencial, presentaba un gâ”œأ­libo rebajado al nivel de la calle que apostaba por la circulaciâ”œâ”‚n rodada por encima del puente, lo que supuso el final de la navegabilidad del Canal para las grandes embarcaciones aguas abajo. Unos meses despuâ”œآ®s de esta captura fotogrâ”œأ­fica, el viejo puente fue derribado, y el nuevo completado con la decoraciâ”œâ”‚n diseâ”œâ–’ada por Ricardo Magdalena, y las metâ”œأ­licas barandillas por Josâ”œآ® Gonzâ”œأ­lez. Se inaugurâ”œâ”‚ en octubre de ese aâ”œâ–’o. A la izquierda de la imagen y en primer tâ”œآ®rmino, obreros junto a los bloques de piedra del nuevo puente. En el centro y bajo el puente, leve vista de la gran dâ”œأ­rsena para reparaciâ”œâ”‚n de embarcaciones en seco. La "playa" del Canal, como lugar de esparcimiento ciudadano y terminal de la lâ”œآ،nea de tranvâ”œآ،a de Torrero, queda a la izquierda y fuera de plano.', 1903, 1903, 1903, 'Anos 1900', 'TORRERO', 41.63334200, -0.88508600, '0101000020E6100000F6B704E09F52ECBF7497C45911D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50743181346.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50743181346.webp', 'https://www.flickr.com/photos/zaragozaantigua/50743181346/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21370, 'Canal Imperial c.1912', 'A dos kilâ”œâ”‚metros del "centro" de la ciudad, la Playa de Torrero era un centro industrial muy activo. A pesar de tener al Ebro, era en el reciente Canal Imperial de Aragâ”œâ”‚n donde habâ”œآ،a ese portuario movimiento de mercancâ”œآ،as y personas de barrios dinâ”œأ­micos. Subiendo por la avenida del Siglo XX, a la izquierda, quedaba la "Playa", o zona de fiestas y celebraciones varias, muy populosas. El hecho de contar desde el principio con una lâ”œآ،nea de tranvâ”œآ،a, que subâ”œآ،a por el antiguo camino de Torrero por el interior de los jardines de Pignatelli (al lado del muro que lo separa de los Depâ”œâ”‚sitos de Agua), aumentaba el atractivo de la zona. A la derecha, habâ”œآ،a un muelle con un trayecto ferroviario que enlazaba con la lâ”œآ،nea de Torrero. En â”œآ®l se realizaban transbordos de las mercancâ”œآ،as que se transportaban por la vâ”œآ،a fluvial, sobre todo remolacha azucarera, para luego bajarlos en vagonetas por los rieles del ya electrificado tranvâ”œآ،a, hasta las azucareras situadas en la ribera del Ebro. Es lo que la imagen ilustra, en captura fotogrâ”œأ­fica desde el puente de Amâ”œآ®rica. A la izquierda, detrâ”œأ­s del poste elâ”œآ®ctrico, la Almenara de Santa Engracia. Justo enfrente y a la izquierda, el embarcadero recreativo.', 1912, 1912, 1912, 'Anos 10', 'TORRERO', 41.63345500, -0.88589000, '0101000020E6100000614F3BFC3559ECBF6C3EAE0D15D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15108329025.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15108329025.webp', 'https://www.flickr.com/photos/zaragozaantigua/15108329025/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21746, 'Embarcadero Canal 1935', 'Imagen del embarcadero para uso recreativo del Canal Imperial emplazado en la margen derecha, junto a la barriada de Venecia. El Puente de Amâ”œآ®rica, al fondo. A la izquierda, el Cuartel de los Castillejos, incrustado sobre lo que fuera el gran e ilustrado complejo del Puerto de Miraflores. Fuente visual: Foto Marâ”œآ،n Chivite, "Mundo Grâ”œأ­fico" (Madrid).', 1935, 1935, 1935, 'Anos 30', 'TORRERO', 41.63331000, -0.88629700, '0101000020E6100000895FB1868B5CECBF691D554D10D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21973388996.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21973388996.webp', 'https://www.flickr.com/photos/zaragozaantigua/21973388996/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22435, 'Pza. de las Canteras 1969', 'Imagen capturada en una localizaciâ”œâ”‚n multifotografiada: la terminal de la lâ”œآ،nea 5 "Venecia-Delicias" ubicada en la plaza de las Canteras. En esta fotografâ”œآ،a aparece la composiciâ”œâ”‚n M-63+R88. Detrâ”œأ­s de ella, antiguos edificios del principio de la calle de Alicante (antigua de Larraz), luego derribados, como los que habâ”œآ،a en el solar de su derecha, esquinero con el arranque de la calle Fray Juliâ”œأ­n Garcâ”œآ®s, donde al poco tiempo comenzarâ”œآ،a la construcciâ”œâ”‚n del moderno bloque del nâ”¬â•‘ 2-4 de esa calle. Al fondo, edificios de la avenida de Amâ”œآ®rica. Fuente visual: Foto John Scragg, a travâ”œآ®s de www.forotrenes.com/', 1969, 1969, 1969, 'Anos 60', 'TORRERO', 41.63168500, -0.88607100, '0101000020E610000076E3DD91B15AECBFD72FD80DDBD04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30406098873.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30406098873.webp', 'https://www.flickr.com/photos/zaragozaantigua/30406098873/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22788, 'P.â”¬â•‘ de Cuâ”œآ®llar 1973', 'Callejera y bulliosa imagen capturada durante la celebraciâ”œâ”‚n de San Antonio de Padua en las inmediaciones de la homâ”œâ”‚nima iglesia parroquial sita en el paseo de Cuâ”œآ®llar, cuyo caracterâ”œآ،stico almohadillado en piedra aparece a la derecha extrema. Centra la escena la figura de un antropolâ”œâ”‚gico barquillero portando su caracterâ”œآ،stica cesta metâ”œأ­lica o barquillera llena de dulces (barquillos) y con la ruleta de la parte superior para tentar suerte en el juego de El Clavo. En esta festiva fecha se ubicaban tambiâ”œآ®n puestos de venta de hermosas rosquillas junto a la puerta de ingreso al porticado acceso a la iglesia y al Sacrario Militare Italiano. De fondo de la imagen, los bajos del nâ”¬â•‘ 20 del paseo. Fuente visual: Gerardo Sancho Ramo, AMZ.', 1973, 1973, 1973, 'Anos 70', 'TORRERO', 41.63439300, -0.88511800, '0101000020E6100000CD3AE3FBE252ECBFDAE731CA33D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/39812440693.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/39812440693.webp', 'https://www.flickr.com/photos/zaragozaantigua/39812440693/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22892, 'Paseo Cuâ”œآ®llar 1987', 'Imagen capturada desde el CRM del Cuartel de Castillejos, con una mirada hacia el paseo de Cuâ”œآ®llar y las antiguas edificaciones supervivientes de los comienzos del pasado siglo, la franja verde de â”œأ­rboles ribereâ”œâ–’a del Canal Imperial, y los enormes y modernos bloques de vivienda de Venecia, con la curiosa coincidencia axial del remate de la neomedieval torrecilla del Hospital de San Juan de Dios, y el de un antiguo (ya desaparecido) quiosco del paseo. Fuente visual: Luis Mâ”œآ،nguez.', 1987, 1987, 1987, 'Anos 80', 'TORRERO', 41.63439300, -0.88511800, '0101000020E6100000CD3AE3FBE252ECBFDAE731CA33D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20370981281.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20370981281.webp', 'https://www.flickr.com/photos/zaragozaantigua/20370981281/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24937, 'Parque Grande 1969', 'Archivo Municipal. Gerardo Sancho Ramo. Abril 1969. Desde la torre-mirador de la Feria de Muestras, una panorâ”œأ­mica de la entrada al Parque Primo de Rivera a travâ”œآ®s del puente "13 de septiembre". Al fondo, a la izquierda, emerge la chimenea de la fâ”œأ­brica de harinas "La Imperial", entre el paseo de Ruiseâ”œâ–’ores, el paseo de Colâ”œâ”‚n, y el paseo de Mariano Renovales. Estarâ”œأ­ activa, primero de Monares, luego de Rubio, luego de Margalejo, hasta los aâ”œâ–’os 90, en que se convierta en una alienâ”œآ،gena colonia-urbanizaciâ”œâ”‚n de unifamiliares adosados. Se conserva una fachada del edificio proyectado por Miguel â”œأ¼ngel Navarro en 1920, y un salto de agua del Canal Imperial que se oye, pero no se ve.', 1969, 1969, 1969, 'Anos 60', 'UNIVERSIDAD', 41.63477000, -0.89476300, '0101000020E61000009677D503E6A1ECBFB03DB32440D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15546818998.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15546818998.webp', 'https://www.flickr.com/photos/zaragozaantigua/15546818998/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23042, 'Canal Imperial 1994', 'Imagen capturada en la margen izquierda del Canal Imperial de Aragâ”œâ”‚n, en el ascendente tramo inmediato al puente de Amâ”œآ®rica, cuando el grupo municipal del Partido Aragonâ”œآ®s Regionalista en pleno visita esta ribereâ”œâ–’a zona para denunciar el impresentable y riesgoso estado de la barandilla que, literalmente desaparecida, ha sido parcheada con vallas que dan un aspecto poco agraciado, ni para la seguridad, ni para la estâ”œآ®tica. Tras ellos, uno de los entraâ”œâ–’ables quioscos que jalonaban el paseo de Cuâ”œآ®llar desde el parque de Pignatelli y hasta el puente de Amâ”œآ®rica, luego retirados en posteriores intervenciones urbanâ”œآ،sticas. Una pintada en este quiosco recuerda la campaâ”œâ–’a en solidaridad con el preso Pablo Serrano. Al fondo y hacia la derecha, la estructura del helipuerto dentro del Centro regional de Mando.', 1994, 1994, 1994, 'Anos 90', 'TORRERO', 41.63336600, -0.88536500, '0101000020E6100000BEBC00FBE854ECBFFD32182312D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50381749071.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50381749071.webp', 'https://www.flickr.com/photos/zaragozaantigua/50381749071/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23064, 'Plaza de las Canteras 1991', 'Imagen capturada durante las obras de remodelaciâ”œâ”‚n de la plaza de las Canteras que, realizada para aumentar la superficie peatonal, limitar la circulatoria a un solo sentido, y la supresiâ”œâ”‚n de la zona de aparcamiento, incluyâ”œâ”‚ ademâ”œأ­s un conjunto monumental en memoria del maestro Manuel de Villanueva ampliado con una escultura que homenajea a la profesiâ”œâ”‚n de cantero. En la imagen, la estructura del muro que formaba parte del conjunto ya era objeto de una campaâ”œâ–’a de oposiciâ”œâ”‚n por vecinos del entorno, como indica la pancarta que pende detrâ”œأ­s, sobre el arranque de la calle de Alicante. En la versiâ”œâ”‚n definitiva de este muro se rebajarâ”œآ،a en altura la zona mâ”œأ­s inmediata al paso de peatones de la derecha.', 1991, 1991, 1991, 'Anos 90', 'TORRERO', 41.63158600, -0.88626600, '0101000020E6100000C8D0B1834A5CECBF444E5FCFD7D04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50510973582.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50510973582.webp', 'https://www.flickr.com/photos/zaragozaantigua/50510973582/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23357, 'Canal Imperial 1934', 'â”¬آ½Revistiâ”œâ”‚ gran brillantez el homenaje a Pignatelli celebrado el domingoâ”¬â•—, El Noticiero (Zaragoza, 16-X-1934, p. 5). El 14 de octubre tuvo lugar una gran fiesta nâ”œأ­utica en la Playa de Torrero. Surcaron las aguas 9 barcazas decoradas con sâ”œآ،mbolos agrâ”œآ،colas, barrios de la ciudad y de pueblos ribereâ”œâ–’os del Canal, como "Alagâ”œâ”‚n", "Bajo Aragâ”œâ”‚n", "Rabal", "Lumpiaque"... Mâ”œâ•‘sica, rondallas, jotas, flores, dos aeroplanos volando por los cielos... Y todo dentro del programa de actos festivos en homenaje al gran impulsor de la obra del Canal Imperial, en el aniversario 200 de su natalicio. Otro acto fue el proyecto de realizaciâ”œâ”‚n de un monumento en su honor en el Hogar del mismo nombre, cuya primera y â”œâ•‘nica piedra se colocâ”œâ”‚ en estas fechas. Fuente visual: archivo Heraldo de Aragâ”œâ”‚n, en "Padre Ebro. El râ”œآ،o Ebro y el siglo XX".', 1934, 1934, 1934, 'Anos 30', 'TORRERO', 41.63341800, -0.88673100, '0101000020E6100000172EABB01960ECBF4F594DD713D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15060741460.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15060741460.webp', 'https://www.flickr.com/photos/zaragozaantigua/15060741460/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23359, 'Pasarela del Canal 1934', 'El 14 de octubre de 1934 tuvo lugar una gran fiesta nâ”œأ­utica en el Canal Imperial, dentro de un festivo programa de actos en homenaje a Ramâ”œâ”‚n Pignatelli, en el aniversario 200 de su natalicio. En la imagen, aspecto del Canal Imperial desde la pasarela peatonal de la calle Ruiz Tapiador, desmontada dâ”œآ®cadas despuâ”œآ®s para poner un paso para los coches. Al fondo, a la derecha, el embarcadero. Mâ”œأ­s al fondo, el Puente de Amâ”œآ®rica. Fuente visual: www.facebook.com/photo.php?fbid=953416374686481&set=g...', 1934, 1934, 1934, 'Anos 30', 'TORRERO', 41.63362300, -0.88773600, '0101000020E61000005D6BEF535568ECBF287FF78E1AD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15138070513.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15138070513.webp', 'https://www.flickr.com/photos/zaragozaantigua/15138070513/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23373, 'Puente de Amâ”œآ®rica 1833', '"El puente de Amâ”œآ®rica", litografâ”œآ،a de Faramundo Blanchard. Puente de Amâ”œآ®rica del Canal Imperial. A la derecha, la dâ”œأ­rsena. Fuente visual: "Memoria histâ”œâ”‚rica del Canal imperial de Aragon: noticia sobre las utilidades que produce, y esplicacion de lo que contienen las lâ”œأ­minas que se publican", Madrid, 1833.', 1833, 1833, 1833, 'Siglo XIX', 'TORRERO', 41.63307000, -0.88480700, '0101000020E61000002DB308C55650ECBF130A117008D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20162787040.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20162787040.webp', 'https://www.flickr.com/photos/zaragozaantigua/20162787040/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23379, 'Puente de Amâ”œآ®rica 1933', 'Puente de Amâ”œآ®rica, Canal Imperial de Aragâ”œâ”‚n, draga, y Torre de Pina, al fondo. Fuente visual: Foto Conrado Barlâ”œآ®s, donada por Daniel Barlâ”œآ®s y digitalizada por Josâ”œآ® Luis Cintora para www.rafaelcastillejo.com', 1933, 1933, 1933, 'Anos 30', 'TORRERO', 41.63329300, -0.88504400, '0101000020E61000003BAC70CB4752ECBF93E4B9BE0FD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22614681504.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22614681504.webp', 'https://www.flickr.com/photos/zaragozaantigua/22614681504/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23381, 'Canal Imperial 1933', 'Canal Imperial desde la metâ”œأ­lica pasarela de Venecia. Al fondo, el embarcadero, el Puente de Amâ”œآ®rica y la Torre de Pina. A la derecha, barcazas de transporte de ladrillos. Fuente visual: Foto Conrado Barlâ”œآ®s, donada por Daniel Barlâ”œآ®s y digitalizada por Josâ”œآ® Luis Cintora para www.rafaelcastillejo.com', 1933, 1933, 1933, 'Anos 30', 'TORRERO', 41.63347700, -0.88694300, '0101000020E6100000EC504D49D661ECBF54E23AC615D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22947139610.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22947139610.webp', 'https://www.flickr.com/photos/zaragozaantigua/22947139610/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23392, 'Canal Imperial c.1933', 'Imagen del Canal Imperial capturada desde la metâ”œأ­lica pasarela que conducâ”œآ،a, hacia la derecha, a la calle de Ruiz Tapiador de la barriada de Venecia. Hacia el fondo, el embarcadero, el Puente de Amâ”œآ®rica y la Torre de Pina. A la izquierda, el frecuentado paseo del Canal y el tramo despejado de edificios entre Villa Rosario y la almenara de Santa Engracia y la nueva acequia del Plano. A la derecha, grandes barcazas de transporte de ladrillos, y en la orilla, montones de ellos apilados. Las barcas recreativas rememoran que el Canal Imperial, lejos de constituirse en trinchera o frontera, fue concebido tambiâ”œآ®n como una eficiente vâ”œآ،a de comunicaciâ”œâ”‚n mediante la navegaciâ”œâ”‚n que, a diferencia del principal de los râ”œآ،os de la ciudad, conllevaba un dragado regular. Fuente visual: postal editada y comercializada por la Editorial Arribas.', 1933, 1933, 1933, 'Anos 30', 'TORRERO', 41.63347700, -0.88694300, '0101000020E6100000EC504D49D661ECBF54E23AC615D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/36593606222.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/36593606222.webp', 'https://www.flickr.com/photos/zaragozaantigua/36593606222/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23395, 'P.â”¬â•‘ del Canal c.1926', 'Invernal imagen capturada en el paseo del Canal y centrada en la pasarela peatonal que enlazaba con la calle de Venecia, y que habâ”œآ،a sido construida con un alto gâ”œأ­libo para favorecer la navegaciâ”œâ”‚n canalina. En la pasarela destaca el tremendo comercial de los Almacenes de calzado de Antonio Mas, sitos en la calle de Don Jaime I nâ”¬â•‘ 54, junto al Hotel Universo y Cuatro Naciones de Pedro Durio. A la izquierda, despejada vista de la Vâ”œآ،a de Pignatelli, con imagen posiblemente de las traseras del inmueble unifamiliar del nâ”¬â•‘ 7 de la calle de Royo. Hacia el fondo y tras la pasarela, el embarcadero recreativo inmediato al puente de Amâ”œآ®rica, y mâ”œأ­s al fondo, en la curva del Canal Imperial de Aragâ”œâ”‚n hacia el cabezo Cortado, la gran casa de Dâ”œأ­maso Pina.', 1926, 1926, 1926, 'Anos 20', 'TORRERO', 41.63350300, -0.88856200, '0101000020E6100000BDFC4E93196FECBF7D7555A016D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/48520811962.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/48520811962.webp', 'https://www.flickr.com/photos/zaragozaantigua/48520811962/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23397, 'Canal Imperial de Aragâ”œâ”‚n 1996', 'Imagen centrada en uno de los antiguos quioscos que flanqueaban el ingreso al puente de Amâ”œآ®rica desde el paseo de Cuâ”œآ®llar, habilitado como oficina de informaciâ”œâ”‚n de Disminuidos Fâ”œآ،sicos de Aragâ”œâ”‚n. Al fondo y a la derecha destaca la torre del Sacrario Militare Italiano. La situaciâ”œâ”‚n de abandono de estas instalaciones, asâ”œآ، como de las riberas del Canal Imperial de Aragâ”œâ”‚n, eran denunciadas de forma regular por vecinos y representantes institucionales, sin demasiado â”œآ®xito.', 1996, 1996, 1996, 'Anos 90', 'TORRERO', 41.63351100, -0.88525700, '0101000020E610000026C3F17C0654ECBF005471E316D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50510452268.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50510452268.webp', 'https://www.flickr.com/photos/zaragozaantigua/50510452268/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23494, 'P.â”¬â•‘ de Colâ”œâ”‚n 1947', 'Imagen capturada en el paseo de Colâ”œâ”‚n del que fuera hotel de Basilio Palomar Labal reformado y ampliado por el arquitecto Josâ”œآ® Yarza Garcâ”œآ،a para adaptarlo como clâ”œآ،nica operatoria del doctor Francisco Seral Casas (mâ”œآ®dico-cirujano del Hospital de la Cruz Roja), con el aspecto que tenâ”œآ،a el dâ”œآ،a de su bendiciâ”œâ”‚n e inauguraciâ”œâ”‚n bajo el nombre de "Clâ”œآ،nica de San Francisco", con capacidad de veinte camas. La ceremonia de bendiciâ”œâ”‚n corriâ”œâ”‚ a cargo de Hernâ”œأ­n Cortâ”œآ®s Pastor, vicario general de la archidiâ”œâ”‚cesis y deâ”œأ­n del Cabildo Metropolitano, y al acto asistiâ”œâ”‚ numerosa y selecta representaciâ”œâ”‚n de la Zaragoza de la â”œآ®poca, que fue obsequiada con una copa de vino espaâ”œâ–’ol.', 1947, 1947, 1947, 'Anos 40', 'TORRERO', 41.63376700, -0.88584700, '0101000020E6100000904FC8CEDB58ECBF5B24ED461FD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54218918367.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54218918367.webp', 'https://www.flickr.com/photos/zaragozaantigua/54218918367/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24230, 'Canal Imperial 1947', 'Las fiestas mayores de octubre de ese aâ”œâ–’o estuvieron trufadas, no podâ”œآ،a ser de otra forma, de hispanidad y advenimiento, y ungidas de fe y patriâ”œâ”‚tico estâ”œآ،mulo, aunque parece que, en tâ”œآ®rminos prâ”œأ­cticos, una modesta "cabalgata" fluvial organizada en el Canal Imperial se convirtiâ”œâ”‚ en el evento mâ”œأ­s destacado del espartano programa fiestero. Aâ”œâ•‘n no se habâ”œآ،an inventado la ofrenda floral-frutâ”œآ،cola de aâ”œâ–’os despuâ”œآ®s. Esta "cabalgata" consistiâ”œâ”‚ en un descenso, desde el chalet de Buenavista, y hasta el Puente de Amâ”œآ®rica, de varios pontones sobre los que se emplazaron reproducciones en bulto redondo de elementos del pasado de la ciudad, como la estatua de Pignatelli, la Fuente de los Incrâ”œآ®dulos, y la Puerta del Carmen, modeladas por el escultor local Armando Ruiz Lorda con materiales efâ”œآ،meros. En otro pontâ”œâ”‚n, un cuadro de jota representaba en directo un homenaje a la jota. Mucha gente se congregâ”œâ”‚ para seguir en vivo a esta oficial bajada del Canal, con un tiempo mâ”œأ­s bien fresco. Unos dâ”œآ،as antes, el Canal habâ”œآ،a sido escenario de una no menos fresca "travesâ”œآ،a" a nado, pero a lo largo, durante 2500 metros, y de una carrera de piraguas sobre esa misma distancia. En la imagen, tramo del Canal entre la pasarela de la calle Ruiz Tapiador (a la izquierda, fuera de plano), y el puente de Amâ”œآ®rica, con el ilustrado pontâ”œâ”‚n de las reproducciones de la estatua de Ramâ”œâ”‚n Pignatelli, y la Fuente que dedicâ”œâ”‚ amablemente a los zaragozanos incrâ”œآ®dulos del Canal. Conducen el artefacto, soldados del ramo pontonero. Fuente visual: Gerardo Sancho Ramo, Archivo Municipal de Zaragoza.', 1947, 1947, 1947, 'Anos 40', 'TORRERO', 41.63347700, -0.88694300, '0101000020E6100000EC504D49D661ECBF54E23AC615D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27649259434.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27649259434.webp', 'https://www.flickr.com/photos/zaragozaantigua/27649259434/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24254, 'â”œأ¼ngel Cortâ”œآ®s Gracia 1936', 'Imagen de â”œأ¼ngel Cortâ”œآ®s Gracia, alias Skogler, con indumentaria falangista de campaâ”œâ–’a en las inmediaciones del cuartel de Castillejos o Torrero, donde terminaba la avenida del Siglo XX. Al fondo, poste de suministro elâ”œآ®ctrico de los tranvâ”œآ،as de las lâ”œآ،neas 5. Torrero y 8. Cementerio, y el paseo del Canal. Antiguo operario del estudio fotogrâ”œأ­fico de Carlos Skogler Fredikson, â”œأ¼ngel Cortâ”œآ®s Gracia mantuvo bajo la denominaciâ”œâ”‚n Foto Skogler una mâ”œأ­s que interesante actividad profesional que, gracias a su pionera militancia en Falange Espaâ”œâ–’ola, desde el triunfo de la rebeliâ”œâ”‚n armada contra la Repâ”œâ•‘blica en julio de 1936 le convirtiâ”œâ”‚ en privilegiado notario de la Zaragoza de la â”œآ®poca.', 1936, 1936, 1936, 'Anos 30', 'TORRERO', 41.63385600, -0.88494600, '0101000020E6100000863B17467A51ECBFCB2F833122D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51367473994.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51367473994.webp', 'https://www.flickr.com/photos/zaragozaantigua/51367473994/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24469, 'Fâ”œأ­brica Larraz 1945', 'Dibujo de la fâ”œأ­brica de gâ”œآ®neros de punto Viuda de Rudesindo Larraz, en los nâ”œâ•‘meros 1 al 5 de la calle de Ruiz Tapiador, junto al Canal Imperial (a la izquierda, fuera del encuadre).', 1945, 1945, 1945, 'Anos 40', 'TORRERO', 41.63332500, -0.88845500, '0101000020E61000003CF71E2E396EECBF9E5E29CB10D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20141251123.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20141251123.webp', 'https://www.flickr.com/photos/zaragozaantigua/20141251123/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25036, 'Sacrario Militare 1942', 'Imagen capturada durante la ceremonia de colocaciâ”œâ”‚n y bendiciâ”œâ”‚n de la primera piedra del mausoleo dedicado a los legionarios italianos muertos durante su intervenciâ”œâ”‚n en la guerra de Espaâ”œâ–’a 1936-39, apoyando a los nacionalistas. Ya en febrero de ese aâ”œâ–’o se habâ”œآ،a bendecido la primera piedra de la nueva iglesia de los capuchinos, y en mayo tuvo lugar la del Sacrario Militare, con el esplendor propio de la tradiciâ”œâ”‚n "imperial y romana" del râ”œآ®gimen fascista italiano. El entorno habâ”œآ،a sido adornado con abundante banderâ”œآ،a italoespaâ”œâ–’ola, un piquete de "carabineri", una compaâ”œâ–’â”œآ،a del ejâ”œآ®rcito espaâ”œâ–’ol, un altar presidido por imagen de San Antonio de Padua, y la maqueta del proyecto. El Nuncio de Su Santidad estaba acompaâ”œâ–’ado por las mâ”œأ­s altas autoridades militares, religiosas, e institucionales de la ciudad y provincia, ademâ”œأ­s de numerosa presencia de jerarcas del Râ”œآ®gimen, y de la Orden de los capuchinos. A la santa misa le siguiâ”œâ”‚ la bendiciâ”œâ”‚n de la primera piedra, y la colocaciâ”œâ”‚n de la misma, junto con un pergamino que literalmente rezaba "Reinando Vâ”œآ،ctor Manuel III, mientras Roma pugna contra los enemigos del derecho y de la fe, bajo los auspicios de Mussolini y Franco, con la bendiciâ”œâ”‚n del Romano Pontâ”œآ،fice Pâ”œآ،o XII, esta obra de paz, a la costumbre de los Padres, para el incremento de la religiâ”œâ”‚n y la memoria de los legionarios italianos caâ”œآ،dos en Espaâ”œâ–’a, se levanta con romana grandeza el dâ”œآ،a 3 de mayo de 1942". Fuente visual: Los Capuchinos en Zaragoza, IV centenario (1598-1998).', 1942, 1942, 1942, 'Anos 40', 'TORRERO', 41.63469100, -0.88530900, '0101000020E6100000C5573B8A7354ECBF6308008E3DD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32024226495.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32024226495.webp', 'https://www.flickr.com/photos/zaragozaantigua/32024226495/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25739, 'Iglesia de San Antonio 1988', 'Foto Eduardo Zamarripa, 1988. Vista aâ”œآ®rea de la iglesia de San Antonio. Fuente: Aragâ”œâ”‚n desde el aire, Ministerio de Defensa, 1988.', 1988, 1988, 1988, 'Anos 80', 'TORRERO', 41.63469100, -0.88530900, '0101000020E6100000C5573B8A7354ECBF6308008E3DD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20319654525.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20319654525.webp', 'https://www.flickr.com/photos/zaragozaantigua/20319654525/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25943, 'Puente de Amâ”œآ®rica 1976', 'Nada mâ”œأ­s cruzar el Puente de Amâ”œآ®rica, y a la derecha, la actual Vâ”œآ،a Ramâ”œâ”‚n Pignatelli es una denominaciâ”œâ”‚n bastante reciente para una calle que no ha tenido nombre durante muchas mâ”œأ­s dâ”œآ®cadas. Era una calle del barrio de Venecia junto al Canal, y eso era suficiente, bastante antes de que a alguien se le ocurriera lo de utilizar "Venecia" como comodâ”œآ،n de expansiâ”œâ”‚n urbanâ”œآ،stica hasta la Plana de Zaragoza. En la imagen, captura del Puente de Amâ”œآ®rica desde la Playa de Torrero, sita en el barrio de S. Josâ”œآ®. El edificio de viviendas que hace esquina es una exquisita supervivencia de comienzos del siglo XX (1904), y hace el nâ”¬â•‘ 1 de la calle, entonces con publicidad de la academia "Tuga". El nâ”¬â•‘ 3, ya es de 1960, sobre unos anteriores corrales. En la foto aâ”œâ•‘n estaban en pie las parcelas de los viejos nâ”œâ•‘meros 2 y 3, que junto con sus traseros huertos serâ”œأ­n demolidas, y sobre ellas construidos los nuevos nâ”¬â•‘ 5 (1977) y nâ”¬â•‘ 7 (1978). El enorme bloque de los nâ”œâ•‘meros 11 y 13 ya estaba en pie desde 1969. A esa altura, aproximadamente, estaba situado el embarcadero del Canal que aparece recogido en bastantes fotos de principios de siglo XX. Fue tambiâ”œآ®n derruido, y en su lugar se ha puesto un monolito que lo recuerda, y que nadie lee, porque hay que pasar por allâ”œآ، para enterarte de que estâ”œأ­. Como no estâ”œأ­ relacionado con Los Sitios, pues nada. Mâ”œأ­s hacia la derecha, las sombras de los altos bloques de viviendas de los nâ”œâ•‘meros 21 (1962), 25 (1963), 29 (1966), y 33 (1962) de la misma calle Vâ”œآ،a Ramâ”œâ”‚n Pignatelli. En primer plano, prâ”œأ­ctica de la pesca que se mantiene en el tiempo, a la busca de carpas y alburnos, y algâ”œâ•‘n ocasional pez fraile. Lo nuevo son las anâ”œأ­tidas, palomas, cotorras. Fuente visual: AVV. San Josâ”œآ®.', 1976, 1976, 1976, 'Anos 70', 'TORRERO', 41.63321400, -0.88494600, '0101000020E6100000863B17467A51ECBF47AF06280DD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19631973063.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19631973063.webp', 'https://www.flickr.com/photos/zaragozaantigua/19631973063/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25945, 'Puente de Amâ”œآ®rica 1979', 'Puente de Amâ”œآ®rica despojado de esa imagen româ”œأ­ntica asociada al Canal Imperial navegable. La antigua gran dâ”œأ­rsena ha sido sustituida por funcionalistas oficinas de la administraciâ”œâ”‚n del Canal. Erradicado el tranvâ”œآ،a, quedan las vâ”œآ،as y parte del adoquinado, que se van difuminando con cada parcheo del vial. El puente, sometido al vasallaje del trafico rodado. A la derecha, en un cartel de las las elecciones generales del 1 de marzo de ese aâ”œâ–’o, Felipe Gonzâ”œأ­lez anuncia "Un Gobierno firme para vencer el paro". Fuente visual: AVV. San Josâ”œآ®', 1979, 1979, 1979, 'Anos 70', 'TORRERO', 41.63307000, -0.88480700, '0101000020E61000002DB308C55650ECBF130A117008D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20352048936.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20352048936.webp', 'https://www.flickr.com/photos/zaragozaantigua/20352048936/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25951, 'Puente de Amâ”œآ®rica 1975', 'Imagen capturada desde el Sacrario Militare Italiano, con panorâ”œأ­mica del puente de Amâ”œآ®rica y sus entraâ”œâ–’ables quioscos, el Canal Imperial y las modernas instalaciones de la CHE, y algunos de los nuevos bloques de viviendas de los barrios de Torrero y la Paz. Fuente visual: Gerardo Sancho Ramo, AMZ.', 1975, 1975, 1975, 'Anos 70', 'TORRERO', 41.63326100, -0.88474300, '0101000020E61000007DAD4B8DD04FECBF876A4AB20ED14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30179240966.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30179240966.webp', 'https://www.flickr.com/photos/zaragozaantigua/30179240966/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (20869, 'El Barranco de la Muerte 1118', 'El Barranco de la Muerte. Agustâ”œآ،n Salinas, 1892. Palacio de Sâ”œأ­stago, Diputaciâ”œâ”‚n de Zaragoza. Segâ”œâ•‘n la leyenda, Alfonso I el Batallador (en el centro de la imagen) hizo que el ejâ”œآ®rcito de los musulmanes que habitaban Saraqusta se congregara en el Barranco de la Muerte, supuestamente llamado asâ”œآ، desde que ocurriâ”œâ”‚ este episodio bâ”œآ®lico en 1118. Serâ”œآ،a uno de los episodios mâ”œأ­s sangrientos de la campaâ”œâ–’a de asedios que terminâ”œâ”‚ con la conquista cristiana de la ciudad. En primer plano, unos cuantos muertos del bando musulmâ”œأ­n, que acudiâ”œâ”‚ engaâ”œâ–’ado al lugar y fue exterminado en el fondo del barranco por los soldados cristianos que esperaban agazapados, segâ”œâ•‘n cuenta el ancestral relato. Al fondo a la izquierda, Saraqusta humeante. El barranco en cuestiâ”œâ”‚n se halla al sur de la ciudad, en los montes de Torrero, entre el cementerio y el Canal Imperial.', 1118, 1118, 1118, 'Siglo XIX', 'TORRERO', 41.62021300, -0.87905100, '0101000020E6100000DC8310902F21ECBFEBC6BB2363CF4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14814731538.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14814731538.webp', 'https://www.flickr.com/photos/zaragozaantigua/14814731538/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24934, 'Puente Trece de Septiembre 1928', 'Proyectado por Miguel â”œأ¼ngel Navarro sobre el râ”œآ،o Huerva, a la entrada del Parque de Buenavista, comenzaron las obras en marzo de 1928, siendo inaugurado en junio por el dictador Primo de Rivera. Se considera una construcciâ”œâ”‚n singular dentro de la estâ”œآ®tica de la â”œآ®poca, con tendencias eclâ”œآ®cticas e historicistas. La obra fue acometida por la empresa â”œأ¼ngel Aisa y Hermano. En homenaje al dictador fue bautizado como Puente del Trece de septiembre sobre el râ”œآ،o Huerva, por la fecha del Golpe de Estado realizado en 1923 con el consentimiento y respaldo del rey Alfonso XIII. Con la llegada de la democracia republicana, el puente fue redenominado del Catorce de Julio. Tras el golpe de 1936 fue redenominado del Trece de Septiembre. En 1991 se le redenominâ”œâ”‚ Puente del Parque, y en 2012 como Puente de los Cantautores. Fuente visual: Zaragoza, dos milenios de agua.', 1928, 1928, 1928, 'Anos 20', 'UNIVERSIDAD', 41.63730400, -0.89775100, '0101000020E610000004711E4E60BAECBF14CE6E2D93D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15366774293.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15366774293.webp', 'https://www.flickr.com/photos/zaragozaantigua/15366774293/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21355, 'Vista desde el Canal 1900', 'Imagen capturada desde el campo de cereal propiedad de Alejandro Palomar de la Torre e inmediato en cota superior al Canal Imperial de Aragâ”œâ”‚n en la gran curva previa al Cabezo Cortado. En la margen izquierda del Canal discurre el terroso camino de la Quinta Julieta que conduce a esa torre recreativa de Enrique Sagols Ferrer. A continuaciâ”œâ”‚n, baldâ”œآ،os y desniveles hacia el barrio de Colâ”œâ”‚n a la izquierda y al de Cuber en el centro, donde destaca la Torre de Cuber y su fâ”œأ­brica de aprestos, ademâ”œأ­s de la fâ”œأ­brica de tejas de Constantin en el espacio entre la acequia del Plano y el camino del Puente del Virrey. Algo mâ”œأ­s hacia la derecha y hacia el fondo emerge la gran estructura del Asilo de las Hermanitas de los Ancianos Desamparados sito en el arranque del camino de San Josâ”œآ®. Sobre el caserâ”œآ،o de la ciudad de Zaragoza despuntan, como telâ”œâ”‚n de fondo y de izquierda a derecha, la câ”œâ•‘pula de San Ildefonso en el templo dedicado entonces a la advocaciâ”œâ”‚n del Sagrado Corazâ”œâ”‚n, la torre de San Pablo, las câ”œâ•‘pulas y torre del templo del Pilar, la torre y el cimborrio de la Seo, la torre de Santa Marâ”œآ،a Magdalena y la desmochada torre de San Agustâ”œآ،n del complejo castrense de las factorâ”œآ،as militares allâ”œآ، ubicadas.', 1900, 1900, 1900, 'Anos 1900', 'TORRERO', 41.63051200, -0.87683500, '0101000020E6100000029F1F46080FECBF27DE019EB4D04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54780076645.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54780076645.webp', 'https://www.flickr.com/photos/zaragozaantigua/54780076645/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22155, 'Alto Carabinas 1953', 'Imagen del interior de una infravivienda establecida en la zona de cuevas de Alto Carabinas. En la dâ”œآ®cada de los aâ”œâ–’os 50, con el inicio del gran "boom" urbano y el denominado "desarrollismo", varias zonas de la periferia de la ciudad se fueron convirtiendo en barriadas donde se instalaron algunos centenares de las familias inmigrantes mâ”œأ­s empobrecidas llegadas durante el â”œآ®xodo interior provocado por la extrema miseria y buscando una oportunidad de tener un futuro mâ”œأ­s digno. Se asentaron en precarios enclaves caracterizados por una tipologâ”œآ،a de infraviviendas que incluâ”œآ،a tanto chabolas de superficie, en materiales reciclados de mala calidad constructiva, como cuevas habilitadas en las antiguas graveras, o canteras de extracciâ”œâ”‚n de â”œأ­ridos, como es el caso. La de la imagen, es una familia de trabajadores proveniente de la provincia de Câ”œâ”‚rdoba, identificada de forma inâ”œآ®dita para el Gran Archivo Zaragoza Antigua gracias a la amable y fundamental colaboraciâ”œâ”‚n de Cristina Paracuellos Ontiveros.', 1953, 1953, 1953, 'Anos 50', 'TORRERO', 41.62887400, -0.87914300, '0101000020E6100000083C3080F021ECBF01A777F17ED04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/29981453610.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/29981453610.webp', 'https://www.flickr.com/photos/zaragozaantigua/29981453610/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22330, 'Graveras de La Paz 1960', 'Imagen de la barriada de chabolas instalada en las graveras del barrio de La Paz de Zaragoza. Al fondo, inicio de la construcciâ”œâ”‚n de los grandes bloques de edificios de las Terrazas de Cuâ”œآ®llar. En primer plano, un equino.', 1960, 1960, 1960, 'Anos 60', 'TORRERO', 41.62887400, -0.87914300, '0101000020E6100000083C3080F021ECBF01A777F17ED04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18646679574.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18646679574.webp', 'https://www.flickr.com/photos/zaragozaantigua/18646679574/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23390, 'Parque Vâ”œآ،ctimas del Terrorismo 2008', 'Dentro de las obras de acompaâ”œâ–’amiento de la Expo 2008, se ejecutâ”œâ”‚ un plan de acondicionamiento de las riberas del Ebro, el Gâ”œأ­llego, el Huerva y el Canal Imperial de Aragâ”œâ”‚n. A la margen derecha de este â”œâ•‘ltimo curso fluvial pertenece la obra que muestra la foto, en el barrio de La Paz, prolongando el paseo de Tierno Galvâ”œأ­n con un parque, que serâ”œأ­ denominado Vâ”œآ،ctimas del Terrorismo. Abajo, la subida al Cabezo Cortado y la margen izquierda del Canal, que en ese largo tramo josefino no fue objeto de acondicionamiento alguno. Fuente visual: Heraldo de Aragâ”œâ”‚n.', 2008, 2008, 2008, 'Siglo XXI', 'TORRERO', 41.63001100, -0.87482000, '0101000020E610000003603C8386FEEBBF658F5033A4D04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32557592702.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32557592702.webp', 'https://www.flickr.com/photos/zaragozaantigua/32557592702/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24741, 'Puente del Ferrocarril 1966', 'Imagen de una familia de la comunidad gitana, posando junto a su infravivienda ubicada bajo el puente del ferrocarril tendido entre la Almozara, y la Ortilla, entre los pilares de apoyo de la margen izquierda. Al fondo, un peatâ”œâ”‚n accede por la empinada rampa natural al puente, y se disponde a cruzarlo, si bien el paso era bastante aventurero. A la derecha de la escena se encontraba la piscina de los Baâ”œâ–’os Pâ”œâ•‘blicos, muy frecuentada. Fuente visual: Gerardo Sancho Ramo, AMZ.', 1966, 1966, 1966, 'Anos 60', 'TORRERO', 41.62835400, -0.87922700, '0101000020E61000007E5358A9A022ECBFC82764E76DD04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15532855267.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15532855267.webp', 'https://www.flickr.com/photos/zaragozaantigua/15532855267/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25749, 'Canal Imperial 1948', 'Imagen del Canal Imperial en la zona de la curva que conduce al acceso al Cabezo Cortado. La imagen estâ”œأ­ capturada volviendo desde las esclusas de Valdegurriana, de forma que el Cabezo, y el "Sanatorio de Nuestra Seâ”œâ–’ora del Pilar" para niâ”œâ–’os tuberculosos, quedarâ”œآ،an a la derecha, ya sobrepasados. Al fondo, una visual de las parcelas de las barriadas de la zona: Colâ”œâ”‚n, ademâ”œأ­s de la Argentina, y Cuber. A la izquierda, las graveras y terraplenes que caracterizaban esa orilla del Canal, hasta llegar al campo de Torrero, y casi la avenida de Amâ”œآ®rica. Mientras el objetivo se acerca a la ciudad, varias personas pasean en direcciâ”œâ”‚n contraria, a la derecha, por una estrecha cinta de concreto que aâ”œâ•‘n perdura como espacio por el que deben ir los peatones. Fuente visual: fotografâ”œآ،a de Mariano Lacruz Berdejo, amablemente aportada por Mariano Lacruz Pâ”œآ®rez (Archivo Familia Lacruz Pâ”œآ®rez).', 1948, 1948, 1948, 'Anos 40', 'TORRERO', 41.63072000, -0.87501100, '0101000020E6100000FA7C94111700ECBF7077D66EBBD04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20427003085.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20427003085.webp', 'https://www.flickr.com/photos/zaragozaantigua/20427003085/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25770, 'Neptuno 1977', 'Imagen del tramo del antiguo barrio de Colâ”œâ”‚n denominado "Torre-Honda", con primer plano de la calle Neptuno en el punto donde desemboca, a la derecha, la del Tres de Agosto (antigua del 31 de julio), luego redenominada Mohammed Alâ”œآ، Amar (vulgo Nanym). Este antiguo entorno parcelario estaba encajonado entre la inmediata fâ”œأ­brica ALUMALSA (a la derecha, fuera de plano), y los taludes tras los que, al fondo, fluye el Canal Imperial, que podâ”œآ،a ser cruzado por la pasarela de San Viator. Paralela a esta calle, tras ella, finaliza de forma abrupta la calle Zaragoza la Vieja, de una forma que no puede ser explicada salvo por el impacto del Canal Imperial, cuya construcciâ”œâ”‚n dejâ”œâ”‚ cortado el antiguo camino del Puente del Virrey. Cuarenta aâ”œâ–’os despuâ”œآ®s, esta zona sigue siendo, mayormente, otro barbecho urbanâ”œآ،stico a diez minutos del "centro", y uno de los tramos del Canal Imperial que no se sometieron a la intervenciâ”œâ”‚n de embellecimiento con motivo de la Expo 2008. Fuente visual: Banco de Imâ”œأ­genes/Asociaciâ”œâ”‚n de Vecinos Barrio de San Josâ”œآ®, amablemente cedida para el', 1977, 1977, 1977, 'Anos 70', 'TORRERO', 41.63090700, -0.87807800, '0101000020E61000006DC9AA083719ECBFA3E8818FC1D04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33219076216.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33219076216.webp', 'https://www.flickr.com/photos/zaragozaantigua/33219076216/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25790, 'Calle de Sagunto 1977', 'Invernal imagen capturada en la calle de Sagunto y centrada en la soleada fachada del inmueble nâ”¬â•‘ 19 duplicado de la misma, inmediato al escalonado acceso excavado artesanalmente en el talud de cascajera por donde subir al paseo del Canal. Allâ”œآ، destaca un cartel que orienta hacia la piscina de la "Ciudad Deportiva Martâ”œآ،n Celimâ”œآ®ndiz" del Arenas S.D. situada a la izquierda, a los pies del Cabezo Cortado. Tras el cartel se cruza el Canal Imperial de Aragâ”œâ”‚n por el puentecillo metâ”œأ­lico de San Viator que daba nombre a la "calle" que a continuaciâ”œâ”‚n flanqueaba por ese lado las graveras de la Paz. La foto se ha tomado a espaldas de la gran factorâ”œآ،a de Alumalsa, todavâ”œآ،a activa desde mediados de los aâ”œâ–’os 40 en esta ubicaciâ”œâ”‚n del antiguo barrio de Colâ”œâ”‚n.', 1977, 1977, 1977, 'Anos 70', 'TORRERO', 41.62999800, -0.87872300, '0101000020E6100000B9C667B27F1EECBFD04543C6A3D04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52714330011.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52714330011.webp', 'https://www.flickr.com/photos/zaragozaantigua/52714330011/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25940, 'Andrâ”œآ® Labarrâ”œآ؟re 1986', 'Momento en el que el alcalde socialista de Pau entre 1971 y 2006, Andrâ”œآ® Labarrâ”œآ؟re (1928-2006), inaugura la calle Villa de Pau, hoy rotonda. Estâ”œأ­ situado en la isleta que reparte el trâ”œأ­fico rodado de las calles Palma de Mallorca, San Viator y rotonda Villa de Pau. Le flanquean dos emplumados funcionarios del Ayuntamiento de Zaragoza, ciudad hermanada con la de Pau desde 1970. Fuente: AMZ.', 1986, 1986, 1986, 'Anos 80', 'TORRERO', 41.62837900, -0.87766900, '0101000020E610000018D1764CDD15ECBF213F1BB96ED04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15890462606.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15890462606.webp', 'https://www.flickr.com/photos/zaragozaantigua/15890462606/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25952, 'La Paz 1980', 'Imagen capturada en Las Graveras del â”œأ¼rea 37 o zona de chabolas y subviviendas del barrio de La Paz, configurada como uno de los puntos de concentraciâ”œâ”‚n de la marginada poblaciâ”œâ”‚n gitana de la ciudad. Fue desalojado a comienzos de la dâ”œآ®cada, y sus habitantes reubicados en el poblado de Quinta Julieta. Sobre este degradado entorno de antiguas canteras o cascajeras fue trazado el nuevo parque de La Paz, inaugurado en 1988. Al fondo, modernos bloques en el entorno de la plaza de Gallur. Fuente visual: "Andalâ”œأ­n, periâ”œâ”‚dico quincenal aragonâ”œآ®s".', 1980, 1980, 1980, 'Anos 80', 'TORRERO', 41.62887400, -0.87914300, '0101000020E6100000083C3080F021ECBF01A777F17ED04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31880391504.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31880391504.webp', 'https://www.flickr.com/photos/zaragozaantigua/31880391504/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21207, 'Gâ”œâ”‚ndola Pignatelli 1900', '1900. Tal vez la gâ”œâ”‚ndola "Sta. Cecilia" sea la mâ”œأ­s famosa de las que surcaron el Canal Imperial en el trâ”œأ­nsito del XIX al XX, por su reconocible y caracterâ”œآ،stica proa en forma de cisne blanco que, tirada desde la orilla por caballerâ”œآ،as, llevaba a los viajeros desde la playa de Torrero hasta la Quinta Julieta. La Quinta de Julieta Sagols, arbolada, con cuevas artificiales, dos lagos para remar y una pequeâ”œâ–’a plaza de toros, era un turâ”œآ،stico destino de la burguesâ”œآ،a zaragozana del momento, que entonces se conformaba con merendar y pasar una buena tarde de domingo cerca del Cabezo Cortado. No como ahora. Esta barca se guardaba en uno de los diques de Miraflores, tambiâ”œآ®n en la Playa de Torrero, entre el Puente de Amâ”œآ®rica y el actual de la prolongaciâ”œâ”‚n de la Avenida S. Josâ”œآ®. Existieron ademâ”œأ­s otros barcos que hacâ”œآ،an ese recorrido canalesco, con interiores aterciopelados y adamascados (en el interior), y sin apenas oleaje (en el exterior), como el "S. Fernando", "Nâ”¬آ¬ Sâ”¬آ¬ del Pilar", "Isabel II", "Sta. Engracia" y "D. Ramâ”œâ”‚n Pignatelli". En la imagen, la gâ”œâ”‚ndola "D. Ramâ”œâ”‚n Pignatelli", arrastrada por un tiro de dos mulos conducido por un arriero, en uno de esos viajes, en este caso, de vuelta. La de la derecha es la ribera del "Camino de Sirga". La navegaciâ”œâ”‚n del Canal fue bastante anterior a la Expo 2008, en que se prometiâ”œâ”‚ recuperarla. Otra promesa incumplida, hasta la fecha. Ahora parece mâ”œأ­s trascendente el Bronce de Botorrita, del siglo I antes de la Era, que con poner un monumento gratis, ya estâ”œأ­ la foto garantizada. Sin embargo, hay noches de invierno en que una espectral gâ”œâ”‚ndola parece recorrer el Canal hacia la Quinta Julieta, dejâ”œأ­ndose llevar por la corriente. Son cosas de la niebla.', 1900, 1900, 1900, 'Anos 1900', 'TORRERO', 41.63011900, -0.88059000, '0101000020E610000092E86514CB2DECBF4BCB48BDA7D04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14857887301.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14857887301.webp', 'https://www.flickr.com/photos/zaragozaantigua/14857887301/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24878, 'P.â”¬â•‘ del General Mola 1972', 'Foto Luis Serrano. 1972. En el paseo del General Mola perduraba el impresionante hotelito de Emerenciano Garcâ”œآ،a, una joya modernista con mayâ”œâ•‘sculas en el nâ”¬â•‘ 54, erigida siguiendo el proyecto firmado en 1909 por Manuel Martâ”œآ،nez de Ubago, autor tambiâ”œآ®n del precioso Quiosco de la Mâ”œâ•‘sica levantado para la Exposiciâ”œâ”‚n Hispano-Francesa de 1908. Al igual que la verja del jardâ”œآ،n, su mirador en el chaflâ”œأ­n presentaba unas preciosas labores con motivos vegetales de forja y la esquina estaba rematada por un torreâ”œâ”‚n, en origen cubierta por un cupulâ”œآ،n posteriormente eliminado, aportando una graciosa asimetrâ”œآ،a a su remate aterrazado, completada por un piâ”œâ–’â”œâ”‚n escalonado de ritmos curvos de ecos gaudinianos, inspirados en obras como la barcelonesa casa Calvet, destacando en la planta noble una ventana bajo un arco parabâ”œâ”‚lico tan caracterâ”œآ،sticos en la obra de Gaudâ”œآ، (a la derecha). Habilitado como Ambulatorio del paseo del General Mola de la Seguridad Social, fue clausurado de esa funciâ”œâ”‚n a finales de 1972 con motivo de la apertura del nuevo Ambulatorio de San Josâ”œآ®. La casa fue derribada en 1976, a pesar de que se trataba de uno de los mejores y mâ”œأ­s bellos ejemplos del Modernismo zaragozano. La demoliciâ”œâ”‚n fue comenzada sin licencia municipal y, aunque el Ayuntamiento ordenâ”œâ”‚ su paralizaciâ”œâ”‚n inmediata, finalmente fue derribado, por la polâ”œآ،tica de los hechos consumados, y levantado lo que hoy podemos contemplar cuando pasamos por esa zona. La imagen muestra tambiâ”œآ®n el edificio que ocupaba el nâ”¬â•‘ 50, menos vistoso y llamativo, pero que hoy figurarâ”œآ،a en cualquier guâ”œآ،a arquitectâ”œâ”‚nica como a preservar. Fue piqueteado, y sustituido por otro mastodonte del montâ”œâ”‚n. Y en medio, el nâ”¬â•‘ 52, abandonado, pero menos intimidado por sus vecinos como pocos aâ”œâ–’os despuâ”œآ®s, cuando quede emparedado entre bloques de cemento, cristal y postmodernez, hasta que tambiâ”œآ®n sea piqueteado a finales de los aâ”œâ–’os 90.', 1972, 1972, 1972, 'Anos 70', 'UNIVERSIDAD', 41.64144900, -0.88656100, '0101000020E6100000FD169D2CB55EECBFA58636001BD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14839400996.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14839400996.webp', 'https://www.flickr.com/photos/zaragozaantigua/14839400996/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21500, 'Piscina Iberia F.C. 1926', 'En el verano de 1926, la deportiva "Sociedad Iberia F.C." inaugurâ”œâ”‚ en sus instalaciones de Torrero, junto al Canal Imperial, una piscina "de medidas reglamentarias" para uso y regocijo de la gente asociada. Esta piscina se localizaba junto al terreno de juego de fâ”œâ•‘tbol, que acababa de ser reformado (con campo de hierba, nueva tribuna, y numerosas gradas de cemento). Ademâ”œأ­s, en lo que hasta hace poco era el campo de entrenamiento de fâ”œâ•‘tbol, se estaba construyendo una pista de carreras ciclistas, para uso de la secciâ”œâ”‚n ciclista de la Sociedad, que pronto sustituirâ”œآ،a al clausurado "Velâ”œâ”‚dromo Elâ”œآ،seos". En la imagen, visual de la piscina del Iberia F.C. El campo de fâ”œâ•‘tbol queda a la izquierda, y la nueva pista de ciclismo, a la derecha (inmediata al Canal Imperial). Al fondo, tras los muros, la calle Lasierra Purroy, y mâ”œأ­s al fondo, la avenida del Puente de Amâ”œآ®rica al Cementerio (luego, de Amâ”œآ®rica, a secas) Fuente visual: "Aragâ”œâ”‚n: revista grâ”œأ­fica de cultura aragonesa" (Aâ”œâ–’o II, Nâ”¬â•‘ 15, diciembre 1926).', 1926, 1926, 1926, 'Anos 20', 'TORRERO', 41.63053100, -0.88306600, '0101000020E610000085B4C6A01342ECBF9D0E643DB5D04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15474069709.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15474069709.webp', 'https://www.flickr.com/photos/zaragozaantigua/15474069709/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21511, 'Mausoleo de Costa 1926', 'Extramuros del lâ”œآ،mite norte (es decir, al sur geogrâ”œأ­fico) del denominado "Cementerio Viejo" del Cementerio de Torrero, fue erigido en 1914-16 por suscripciâ”œâ”‚n popular este mausoleo al polâ”œآ،tico, economista, antropâ”œâ”‚logo y referente del Regeneracionismo espaâ”œâ–’ol, Joaquâ”œآ،n Costa. El busto, obra de Dionisio Lasuâ”œآ®n, corona una obra coral concebida como una escarpada y râ”œâ•‘stica montaâ”œâ–’a llena de elementos simbâ”œâ”‚licos alusivos a su ideario. En la imagen, Mausoleo con fondo de vales y montes de Torrero. Fuente visual: "Aragâ”œâ”‚n : revista grâ”œأ­fica de cultura aragonesa" (Aâ”œâ–’o II, Nâ”¬â•‘ 5, febrero 1926).', 1926, 1926, 1926, 'Anos 20', 'TORRERO', 41.62031800, -0.88575000, '0101000020E6100000F2D24D621058ECBF608F899466CF4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15661606415.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15661606415.webp', 'https://www.flickr.com/photos/zaragozaantigua/15661606415/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21621, 'Lasierra Purroy 1929', 'Posado de la selecciâ”œâ”‚n absoluta de foot-ball de la repâ”œâ•‘blica de Francia, antes del encuentro amistoso que la enfrentâ”œâ”‚ con la selecciâ”œâ”‚n del reino de Espaâ”œâ–’a en el flamante campo de la Sociedad Iberia F.C, sito en la calle de Lasierra Purroy (Torrero), un luminoso 14 de abril de 1929, dâ”œآ،a domingo. Parece ser que este fue el primer encuentro internacional de esta disciplina deportiva que tuvo lugar en la ciudad. Tras el seleccionado galo dirigido por Gastâ”œâ”‚n Barreau, la porterâ”œآ،a de gol sur del campo. Figuran en la imagen: Henrie (portero), Vallet, Bertrant, Paul Nicolas (capitâ”œأ­n), Dauphin, Bastide, Alex Villaplane, Dutheil, Lieb, Reinante y Galley. El resultado final fue de 8-1 a favor del seleccionado espaâ”œâ–’ol. Alex Villaplane, el jugador de pie a la derecha extrema, con la cabeza agachada, entre 1941 y 1944 fue oficial de la Carlingue o rama francesa de la "Gestapo", colaboracionista con los alemanes ocupantes de su paâ”œآ،s durante la Segunda Guerra Mundial. Fuente visual: www.todocoleccion.net/', 1929, 1929, 1929, 'Anos 20', 'TORRERO', 41.62984600, -0.88316500, '0101000020E61000005019FF3EE342ECBF1AC231CB9ED04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33374785194.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33374785194.webp', 'https://www.flickr.com/photos/zaragozaantigua/33374785194/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21657, 'Calle de Larraz 1927', 'Imagen capturada en el final del segundo tramo de la arbolada calle de Larraz (actual de Alicante), a espaldas de la homâ”œâ”‚nima y antigua torre que fue pionera en esta perifâ”œآ®rica zona que a finales del siglo XIX fue comenzada a parcelar como barrio de Venecia. A la izquierda, tramo de los nâ”œâ•‘meros pares de la calle, con construcciones de dos, tres y una altura, incluyendo la enorme torre de Bardavio, esquinera con la calle de Marqueta (actual de Castellâ”œâ”‚n de la Plana). A la derecha, parcelas de una y dos alturas hasta el emboque a las calles de San Marcial y de Almerâ”œآ،a.', 1927, 1927, 1927, 'Anos 20', 'TORRERO', 41.63179500, -0.88866900, '0101000020E61000003F027FF8F96FECBF5E6397A8DED04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52361851755.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52361851755.webp', 'https://www.flickr.com/photos/zaragozaantigua/52361851755/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21686, 'Câ”œأ­rcel de Torrero c.1932', 'Abierta en 1928, en 2005 se demoliâ”œâ”‚ parcialmente. Mâ”œأ­s informaciâ”œâ”‚n: lacalledelamemoria.es/la-carcel-de-torrero/', 1932, 1932, 1932, 'Anos 30', 'TORRERO', 41.62743600, -0.88681700, '0101000020E6100000BA2D910BCE60ECBFA22AA6D24FD04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14946131346.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14946131346.webp', 'https://www.flickr.com/photos/zaragozaantigua/14946131346/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21741, 'Velâ”œâ”‚dromo de Torrero 1935', 'Entre el 29 de abril y el 15 de mayo de 1935 tuvo lugar la "1â”¬آ¬ Vuelta Ciclista a Espaâ”œâ–’a", cuya 5â”¬آ¬ etapa se desarrollâ”œâ”‚ entre las ciudades de San Sebastiâ”œأ­n y Zaragoza, el sâ”œأ­bado 4 de mayo. En la imagen, y tras nueve horas de pedaleo, celebrada llegada a la lâ”œآ،nea de meta del ganador de la etapa, Mariano Caâ”œâ–’ardo, en el velâ”œâ”‚dromo de Torrero, inaugurado en 1928 para sustituir al antiguo de los Campos Elâ”œآ،seos. Esta importante instalaciâ”œâ”‚n deportiva estaba ubicada en la calle de Lasierra Purroy, junto a la piscina y el campo de fâ”œâ•‘tbol donde jugaba el Zaragoza F.C. Al tâ”œآ®rmino de esta Iâ”¬آ¬ Vuelta Ciclista a Espaâ”œâ–’a, Mariano Caâ”œâ–’ardo quedâ”œâ”‚ en el segundo lugar de la clasificaciâ”œâ”‚n general, por detrâ”œأ­s del belga Gustaaf Deloor. Fuente visual: A. de la Barrera, Diario As (Madrid).', 1935, 1935, 1935, 'Anos 30', 'TORRERO', 41.63153000, -0.88353000, '0101000020E6100000BD1DE1B4E045ECBFB0389CF9D5D04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21816310259.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21816310259.webp', 'https://www.flickr.com/photos/zaragozaantigua/21816310259/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21803, 'Los Alifantes 1935', 'Formaciâ”œâ”‚n del Real Zaragoza Club de Fâ”œâ•‘tbol en la temporada 1934-1935, en la piscina del campo de Torrero. Eran apodados "Los Alifantes". Fuente: Heraldo de Aragâ”œâ”‚n.', 1935, 1935, 1935, 'Anos 30', 'TORRERO', 41.63053100, -0.88306600, '0101000020E610000085B4C6A01342ECBF9D0E643DB5D04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26456329417.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26456329417.webp', 'https://www.flickr.com/photos/zaragozaantigua/26456329417/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21968, 'Campo de Torrero 1941', 'Imagen de la inauguraciâ”œâ”‚n oficial del XXIII Campeonato de Espaâ”œâ–’a de "Cross" en el campo de football de Torrero, con presencia en la tribuna de autoridades del general Moscardâ”œâ”‚, ademâ”œأ­s de otros representantes y jerarcas del Râ”œآ®gimen, hacia donde se dirigen los saludos, reglamentariamente fascistas, de los atletas, que son correspondidos por los de la asistencia. Hasta el 11-S de 1945, unos dâ”œآ،as despuâ”œآ®s de la rendiciâ”œâ”‚n incondicional del Imperio del Japâ”œâ”‚n, este saludo fue obligatorio en todos los actos pâ”œâ•‘blicos del Reino, como este. Al acabar el ceremonial, los 87 participantes del campeonato se encaminaron, corriendo campo traviesa, hacia los cercanos pinares de Venecia. Al fondo, tras el Canal Imperial, silueta del monumental torreâ”œâ”‚n de la antigua Torre de Dâ”œأ­maso Pina. Fuente: Archivo Celedonio Garcâ”œآ،a (celedoniogarcia.blogspot.com.es)', 1941, 1941, 1941, 'Anos 40', 'TORRERO', 41.62984600, -0.88316500, '0101000020E61000005019FF3EE342ECBF1AC231CB9ED04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22476267046.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22476267046.webp', 'https://www.flickr.com/photos/zaragozaantigua/22476267046/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22027, 'Cementerio de Torrero 1941', 'Imagen capturada en el cementerio de la "Aviazione Legionaria" fascista italiana de Torrero (inaugurado en 1940 en el homâ”œâ”‚nimo cementerio catâ”œâ”‚lico), cuando la Delegaciâ”œâ”‚n Nacional del Servicio Exterior de Falange, en colaboraciâ”œâ”‚n con la Secciâ”œâ”‚n Femenina del Partido, realizaban un acto simbâ”œâ”‚lico que inauguraba la obra "Madrinas de tumbas de caâ”œآ،dos italianos", como memorial recuerdo a "la ayuda del Fascismo y la sangre generosamente derramada en nuestros frentes por los combatientes del Imperio italiano". En este caso, la madrina fue ni mâ”œأ­s ni menos que Pilar Primo de Rivera, Delegada nacional de la Secciâ”œâ”‚n Femenina que asistiâ”œâ”‚ a la ceremonia y asumiâ”œâ”‚ el cuidado y embellecimiento de la tumba de Pietro Barresi, considerado primer "caâ”œآ،do" italiano en tierra aragonesa, si bien posteriormente se situâ”œâ”‚ su muerte en Esquivias (Toledo). La ceremonia contâ”œâ”‚ con la asistencia de los altos mandos militares de la regiâ”œâ”‚n, autoridades civiles y militares de la provincia, el Ayuntamiento y los representantes de los embajadores de Italia y Alemania. Durante la preceptiva misa se colocaron coronas ofrecidas por Falange, Aviaciâ”œâ”‚n y el Fascio Italiano de Zaragoza ante el supuesto sepulcro de Barresi. Ximâ”œآ®nez de Sandoval, jefe del Gabinete Diplomâ”œأ­tico del Ministro de Asuntos Exteriores, pronunciâ”œâ”‚ un vibrante monâ”œâ”‚logo donde no faltaron referencias a la Virgen del Pilar. Cerrâ”œâ”‚ el acto el canto, brazo en alto, del himno fascista y del Cara al Sol a los acordes de las bandas militares, y un postrero desfile.', 1941, 1941, 1941, 'Anos 40', 'TORRERO', 41.62338200, -0.88386200, '0101000020E61000003BAB05F69848ECBF21753BFBCACF4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50388822032.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50388822032.webp', 'https://www.flickr.com/photos/zaragozaantigua/50388822032/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22040, 'Paseo del Canal c.1954', 'Imagen del Canal Imperial de Aragâ”œâ”‚n capturada en el tramo de la gran curva que traza en las terrazas de Pina, donde deriva agua a travâ”œآ®s de la acequia de Ontonar, que poco mâ”œأ­s adelante surte a la fâ”œأ­brica textil de Pina. Al fondo, edificios del Canal Imperial inmediatos al cuartel de Torrero (a la izquierda, fuera de plano). A la derecha, la antigua gran torre del nâ”¬â•‘ 340 del paseo, que todavâ”œآ،a supervive, abandonada y en barbecho urbanâ”œآ،stico, como nâ”¬â•‘ 23-25. Junto a ella, transita un prâ”œآ،stino Seat 1400. Como sucede con regular periodicidad, el Canal baja sin agua para acometer tareas de limpieza y mantenimiento. En la zona del estrechamiento y salto de agua canalino, tiempo despuâ”œآ®s se colocarâ”œآ،a una pasarela peatonal de paso Fuente visual: archivo Heraldo de Aragâ”œâ”‚n, en "Padre Ebro. El râ”œآ،o Ebro y el siglo XX".', 1954, 1954, 1954, 'Anos 50', 'TORRERO', 41.63225400, -0.88158700, '0101000020E61000002385B2F0F535ECBFF261F6B2EDD04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14740164988.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14740164988.webp', 'https://www.flickr.com/photos/zaragozaantigua/14740164988/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22051, 'Canal Imperial 1956', 'Foto: Josâ”œآ® Antonio Duce. Invierno de 1956. El Canal Imperial de Aragâ”œâ”‚n, helado.', 1956, 1956, 1956, 'Anos 50', 'TORRERO', 41.63034300, -0.89211300, '0101000020E61000002FC4EA8F308CECBF9B215514AFD04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14894292836.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14894292836.webp', 'https://www.flickr.com/photos/zaragozaantigua/14894292836/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22173, 'Barrio de Nâ”¬آ¬ Sâ”¬آ¬ 1954', 'Dibujo publicitario con que se ilustraba el proyecto del "Nuevo Barrio de Nuestra Seâ”œâ–’ora", autoproclamado como "La soluciâ”œâ”‚n verdad al problema de la vivienda". 1200 pisos proyectados a la â”œâ•‘ltima, en cuanto a equipamientos, lo convertâ”œآ،an en "el barrio mâ”œأ­s moderno de Zaragoza", y los comerciales insertos en prensa ya introducâ”œآ،an la coletilla "a diez minutos de la plaza de Espaâ”œâ–’a" (en tranvâ”œآ،a, lâ”œآ،nea 5 "Venecia-Delicias"). Ubicado entre el Campo de Deportes de Torrero (al fondo) y el Canal Imperial (en primer plano), junto a la calle Lasierra Purroy (derecha), este desarrollo urbanâ”œآ،stico aparece imaginativamente desarrollado en el dibujo, incluyendo torres de 15-16 alturas, nuevos puentes sobre el Canal, y amplios nuevos viales sospechosamente sin circulaciâ”œâ”‚n rodada. La realizaciâ”œâ”‚n prâ”œأ­ctica dejarâ”œأ­ las torres a mitad de altura, una densidad edilicia bastante menor, y los puentes y nuevas avenidas en modo espera, por unas cuantas dâ”œآ®cadas. A veces, la realidad no se ajusta a la publicidad de las promotoras. Fuente visual: diario "El Noticiero". Archivo Josâ”œآ® Marâ”œآ،a Ballestâ”œآ،n Miguel.', 1954, 1954, 1954, 'Anos 50', 'TORRERO', 41.63129200, -0.88366800, '0101000020E6100000FFB1101D0247ECBFFC1C1F2DCED04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31475502252.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31475502252.webp', 'https://www.flickr.com/photos/zaragozaantigua/31475502252/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22303, 'Misa en Torrero 1968', 'Archivo Municipal. Gerardo Sancho Ramo. 1968. "Misa en la câ”œأ­rcel de Torrero." Han pasado 28 aâ”œâ–’os y estamos en el mismo escenario, pero ni siquiera el guiâ”œâ”‚n es ya el mismo. Ha llovido tanto acero, tanta sangre, que la tierra estâ”œأ­ empapada, y ya no es necesaria la parafernalia de antaâ”œâ–’o. El retrato del conductor, del guâ”œآ،a, del lâ”œآ،der, anda en algâ”œâ•‘n desvâ”œأ­n cogiendo polvo. Los "vivas" ya no son necesarios para garantizar la longevidad del râ”œآ®gimen. El exceso de metros cuadrados de banderas nacionalistas ya sâ”œâ”‚lo se saca cuando el contubernio actâ”œâ•‘a, y hay que marcar territorio. Los saludos fascistas incomodan a la tecnocracia que se aferra con esperanza al prâ”œآ،ncipe para que todo siga igual. Ya no hay tantos inquilinos como antaâ”œâ–’o, y las ropas, los cortes de pelo, la estâ”œآ®tica, se ha relajado en las formas. Ha pasado mucho tiempo, pero todos saben perfectamente lo que ha pasado, y lo que no va a pasar. En la imagen, misa en el interior de la câ”œأ­rcel de Torrero, como podâ”œآ،a serlo en una parroquia catâ”œâ”‚lica al uso, de la â”œآ®poca. Pero sâ”œâ”‚lo para malos hombres.', 1968, 1968, 1968, 'Anos 60', 'TORRERO', 41.62731500, -0.88698400, '0101000020E6100000906802452C62ECBF27A5A0DB4BD04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15613426538.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15613426538.webp', 'https://www.flickr.com/photos/zaragozaantigua/15613426538/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22487, 'RNE 1968', 'Aâ”œآ®rea visual centrada, en primer tâ”œآ®rmino, en las novâ”œآ،simas instalaciones (inauguradas oficialmente el 18 de julio de ese aâ”œâ–’o) del centro emisor y estudios de Radio Nacional de Espaâ”œâ–’a en Zaragoza. La vista incluye una interesante panorâ”œأ­mica de la zona sur del barrio de Venecia, entre el antiguo camino de Cuarte y los pinares de Venecia, a la izquierda, y el cementerio catâ”œâ”‚lico de Torrero, en el extremo inferior derecho, incluyendo en ella, entre otros elementos urbanos, el Grupo de Viviendas Hogar Cristiano, la terrosa calle de Fray Juliâ”œأ­n Garcâ”œآ®s (antiguo camino de las Canteras), el Centro Penitenciario de Detenciâ”œâ”‚n o Prisiâ”œâ”‚n Provincial de Zaragoza, el moderno colegio Domingo Miral, los depâ”œâ”‚sitos de aguas de Las Canteras (construidos en el inicio de los aâ”œâ–’os treinta), y la enorme extensiâ”œâ”‚n recreativa del reciente Stadium Venecia. Al fondo, descendiendo las sucesivas terrazas, la ciudad de Zaragoza. Fuente visual: exposiciâ”œâ”‚n أ”أ‡أ–50 aâ”œâ–’os RNE Aragâ”œâ”‚nأ”أ‡أ–.', 1968, 1968, 1968, 'Anos 60', 'TORRERO', 41.62358500, -0.89040600, '0101000020E61000008C3045B9347EECBF59A31EA2D1CF4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/43033376230.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/43033376230.webp', 'https://www.flickr.com/photos/zaragozaantigua/43033376230/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22526, 'Campo de Torrero 1975', 'A la izquierda de la avenida de Amâ”œآ®rica, ribera derecha del Canal donde el Puente de Amâ”œآ®rica, justo despuâ”œآ®s de las instalaciones de la Confederaciâ”œâ”‚n Hidrogrâ”œأ­fica del Ebro y de las primeras parcelitas, habâ”œآ،a un terreno la verdad es que muy poco propicio. Las acusadas irregularidades y la pobre composiciâ”œâ”‚n del suelo (derrubios y gravas acumuladas), hacâ”œآ،an que apenas si agarraran unos pocos y sufridos terrenos de viâ”œâ–’edo. Mejor se daban los abejares, y mucho mâ”œأ­s los "eriales" y las caracterâ”œآ،sticas "graveras" (lugar de extracciâ”œâ”‚n de gravas) de la zona. La calle Lasierra Purroy marcaba el fin del incipiente barrio de Torrero, cuando en esta zona se construyâ”œâ”‚ un velâ”œâ”‚dromo que venâ”œآ،a a sustituir al que hasta entonces existâ”œآ،a donde el actual cine Elâ”œآ،seos. Se excavâ”œâ”‚ a su lado, ademâ”œأ­s, una gran piscina, y en 1923 el "Iberia Sport Club" levantâ”œâ”‚ un nuevo campo de fâ”œâ•‘tbol, que serâ”œأ­ el campo del Real Zaragoza de 1932 a 1957. Con la mudanza al nuevo y municipal campo allâ”œأ­ donde la acequia de la Romareda, el campo de Torrero fue decayendo hasta que a finales de los 80 del siglo pasado fue derruido, y la zona comenzâ”œâ”‚ a ser urbanizada y reordenada con nuevos bloques de viviendas ademâ”œأ­s de, ya en 1998, el Centro Câ”œآ،vico "Torrero". En la imagen, captura de los restos del campo de Torrero desde la ribera del Canal. Mâ”œأ­s allâ”œأ­ del Canal se perciben claramente las irregularidades del terreno, y el comienzo de la zona de las graveras. La destacable grada de cemento, de 10 metros de altura, habâ”œآ،a sido aâ”œâ–’adida como ampliaciâ”œâ”‚n de aforo en 1943. Los bloques de viviendas de la derecha, terminados en el aâ”œâ–’o 1976, se corresponden con los nâ”œâ•‘meros 6, 8, 10, 12 y 14 de la calle de Honorio Garcâ”œآ،a Condoy, abierta ese mismo aâ”œâ–’o. Una vez derribado el campo de Torrero, justo donde termina el bloque central se abrirâ”œأ­ la nueva calle Doctor Pascual Oliver, y poco a poco se empezarâ”œأ­n a levantar bloques de viviendas sobre el solar: el nâ”¬â•‘ 2 en 1987, el nâ”¬â•‘ 4 en 1989, el nâ”¬â•‘ 6 en 2000, y el nâ”¬â•‘ 8 en 2001. Lo mismo suced', 1975, 1975, 1975, 'Anos 70', 'TORRERO', 41.63115300, -0.88113200, '0101000020E6100000B8B06EBC3B32ECBFDAE21A9FC9D04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14669307568.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14669307568.webp', 'https://www.flickr.com/photos/zaragozaantigua/14669307568/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22588, 'Câ”œأ­rcel de Torrero 1977', 'Imagen de la cara sur de la câ”œأ­rcel provincial de Torrero, desde la Avenida de Amâ”œآ®rica. Los bloques de vivienda del fondo, del casi final de la calle Fray Juliâ”œأ­n Garcâ”œآ®s. Es visible una de las torrecillas de vigilancia situadas en las esquinas del complejo carcelario, y dos guardianes. La entrada por la Avenida de Amâ”œآ®rica queda fuera de plano, a la derecha. Esta câ”œأ­rcel fue construida en 1928, y desmantelada parcialmente en 2005.', 1977, 1977, 1977, 'Anos 70', 'TORRERO', 41.62741600, -0.88738200, '0101000020E6100000EBE3A1EF6E65ECBF5A7EE02A4FD04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15727426296.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15727426296.webp', 'https://www.flickr.com/photos/zaragozaantigua/15727426296/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22608, 'Calle Cuarte 1971', 'La calle de Cuarte en el barrio de Venecia, desde la altura del nâ”¬â•‘ 2 de la calle de Loarre. A la izquierda y en primer tâ”œآ®rmino, aspecto del moderno colegio El â”œأ¼ngel de la Guarda, inaugurado en 1968 sobre la parcela que desde desde 1955 se ofrecâ”œآ،an clases particulares a niâ”œâ–’os pequeâ”œâ–’os, y que en 1958 se abriâ”œâ”‚ ya como colegio en la esquina con la calle del Pinar, que linda con los Pinares de Venecia. A la derecha, inmueble esquinero del nâ”¬â•‘ 52 de la calle del Parque, luego derribado y sustituido por otro nuevo. Al fondo a la izquierda, las torres del Pilar. En el centro, la del Sacrario Militare Italiano.', 1971, 1971, 1971, 'Anos 70', 'TORRERO', 41.62973300, -0.89064400, '0101000020E6100000B01D8CD82780ECBF221B48179BD04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19088636666.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19088636666.webp', 'https://www.flickr.com/photos/zaragozaantigua/19088636666/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22662, 'Calle Jenaro Checa 1977', 'Actuaciâ”œâ”‚n de cabra en escalera en la calle de Jenaro Checa de Zaragoza. Al fondo a la derecha, esquina con la calle de Juan Aguas. Fuente: www.facebook.com/photo.php?fbid=10207153958624292&set...', 1977, 1977, 1977, 'Anos 70', 'TORRERO', 41.63216200, -0.88638500, '0101000020E61000005A475513445DECBF11E335AFEAD04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22545869215.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22545869215.webp', 'https://www.flickr.com/photos/zaragozaantigua/22545869215/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22772, 'Pl. de las Canteras 1971', 'Imagen capturada en la terminal de la lâ”œآ،nea 5 "Venecia-Delicias" ubicada en la plaza de las Canteras, con la composiciâ”œâ”‚n M+R 109 en posiciâ”œâ”‚n descanso. Tras ella, edificios del principio de la calle de Alicante (antigua de Larraz), luego derribados y sustituidos por bloques mâ”œأ­s modernos, si bien no tan verticales como el que ya se alzaba a su derecha, esquinero con el arranque de la calle Fray Juliâ”œأ­n Garcâ”œآ®s, de la que era su nâ”¬â•‘ 2-4. Al fondo, a la derecha, edificios de la avenida de Amâ”œآ®rica. A finales de este aâ”œâ–’o de 1971, la lâ”œآ،nea 5 fue suprimida, y esta unidad, en servicio desde 1944, pasâ”œâ”‚ a otras funciones, hasta 1976, cuando el cierre de la â”œâ•‘ltima lâ”œآ،nea. Fuente visual: foto Josâ”œآ® Marâ”œآ،a Valero', 1971, 1971, 1971, 'Anos 70', 'TORRERO', 41.63168500, -0.88607100, '0101000020E610000076E3DD91B15AECBFD72FD80DDBD04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33659395855.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33659395855.webp', 'https://www.flickr.com/photos/zaragozaantigua/33659395855/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22817, 'Calle de â”œأ¼frica 1974', 'Inâ”œآ®dita imagen capturada en la calle de â”œأ¼frica y centrada en el chaflâ”œأ­n ocupado por el bar El Pinar junto a las viviendas mancomunadas construidas entre esta calle y la del Tiro, que se abre a la izquierda. A la derecha, pinos en la margen derecha del Canal Imperial de Aragâ”œâ”‚n. Mâ”œأ­s adelante y a la izquierda, principio de las calles de Jaâ”œآ®n y de Roger de Lauria, en torno a las cuales perduraban las originales parcelas de esta zona del barrio de Venecia, salvo el mâ”œأ­s reciente inmueble del nâ”¬â•‘ 21, y el modernâ”œآ،simo bloque del nâ”¬â•‘ 1 de la calle del Pinar, al fondo. En el momento de tomar esta fotografâ”œآ،a este veterano barrio surgido entre la avenida de Amâ”œآ®rica y el Canal contaba con unas 6.000 familias, y la Asociaciâ”œâ”‚n de Cabezas de Familia se esforzaba por reivindicar servicios pâ”œâ•‘blicos como una guarderâ”œآ،a infantil (ninguna en el barrio), un "club" de jubilados (ninguno en el barrio), y un centro cultural (ninguno en el barrio). De la pavimentaciâ”œâ”‚n de las calles, terrosas como ilustra la imagen, ni se hablaba. Mientras tanto, el câ”œآ®ntrico paseo de Marina Moreno estaba siendo "embellecido"...', 1974, 1974, 1974, 'Anos 70', 'TORRERO', 41.63156200, -0.89113700, '0101000020E61000007B2DE8BD3184ECBFBCB20B06D7D04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51601889686.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51601889686.webp', 'https://www.flickr.com/photos/zaragozaantigua/51601889686/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22822, 'Barrio de Begoâ”œâ–’a 1974', 'Inâ”œآ®dita imagen capturada desde el paseo del Canal y orientada hacia la margen derecha del Canal Imperial de Aragâ”œâ”‚n (visible en primer tâ”œآ®rmino), donde desde mediados de los aâ”œâ–’os 50 se levantâ”œâ”‚ el "nuevo barrio de N.â”¬آ¬ S.â”¬آ¬ de Begoâ”œâ–’a" vertebrado entre las calles de Sancho Ramâ”œآ،rez y Lasierra Purroy, ademâ”œأ­s de dos nuevas calles sin nombre denominadas "A" (actual de N.â”¬آ¬ S.â”¬آ¬ de Monlora) y "D" (actual del Doctor Pascual Oliver). A la derecha, vista de las fincas 2, 3, 6, 7 y 8 de este "barrio" vertebradas en torno a la referida calle "A". Delante de ellas, una "pluma" de obra anuncia la pronta construcciâ”œâ”‚n de los mâ”œأ­s modernos bloques recayentes a la calle "B" (actual de Honorio Garcâ”œآ،a Condoy") y a la de Sancho Ramâ”œآ،rez. Al fondo destaca la gran grada de cemento del veterano campo de Torrero construida en 1943, y tras ella algunos edificios de vivienda de la calle de Monzâ”œâ”‚n a la altura de la calle del Râ”œآ،o Jalâ”œâ”‚n.', 1974, 1974, 1974, 'Anos 70', 'TORRERO', 41.63177100, -0.88346600, '0101000020E61000000D18247D5A45ECBFD6C743DFDDD04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51638184775.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51638184775.webp', 'https://www.flickr.com/photos/zaragozaantigua/51638184775/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22829, 'Campo de Torrero 1973', 'Imagen capturada desde la grada norte del campo de fâ”œâ•‘tbol de Torrero y centrada en la antigua piscina en desuso situada junto a â”œآ®l. Hacia el fondo, edificios del entorno de la calle de Santa Gema, al otro lado del Canal Imperial de Aragâ”œâ”‚n. Poco despuâ”œآ®s el terreno de la piscina serâ”œآ،a reurbanizado para dar paso a un nuevo vial entre el campo y el barrio de N.â”¬آ¬ S.â”¬آ¬ de Begoâ”œâ–’a, que queda justo a la izquierda y fuera de plano.', 1973, 1973, 1973, 'Anos 70', 'TORRERO', 41.63091300, -0.88397000, '0101000020E6100000D3A414747B49ECBF85CFD6C1C1D04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/53531400662.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/53531400662.webp', 'https://www.flickr.com/photos/zaragozaantigua/53531400662/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22973, 'Avenida Amâ”œآ®rica 1997', '1997. Concentraciâ”œâ”‚n en la puerta de la câ”œأ­rcel de Torrero en protesta por la muerte en su interior de un insumiso preso, Kike Mur, que hoy da nombre al Centro Social Okupado que utiliza el edificio administrativo de la antigua prisiâ”œâ”‚n. Fuente: Zaragoza Rebelde', 1997, 1997, 1997, 'Anos 90', 'TORRERO', 41.62756900, -0.88658700, '0101000020E61000004CE141B3EB5EECBFE17D552E54D04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15016754711.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15016754711.webp', 'https://www.flickr.com/photos/zaragozaantigua/15016754711/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23635, 'Eloy Fernâ”œأ­ndez Clemente 1975', 'En junio de 1975 Eloy Fernâ”œأ­ndez Clemente, en su calidad de director de la revista "Andalâ”œأ­n", fue ingresado preso en la câ”œأ­rcel de Torrero durante una semana. Desde sus comienzos, esta revista habâ”œآ،a sufrido numerosos avatares: secuestros (en 1974 se retirâ”œâ”‚ el nâ”œâ•‘mero dedicado al derrocamiento de Allende; igual suerte corriâ”œâ”‚ el dossier sobre la batalla de Teruel, o el cartel del Gobernador Civil de Huesca con casco prusiano), expedientes, declaraciones en el juzgado, presiones policiales, boicots econâ”œâ”‚micos... Entre las personalidades que intervinieron para pedir la libertad del director de la revista, llamâ”œâ”‚ la atenciâ”œâ”‚n la del arzobispo Cantero Cuadrado, que se ofreciâ”œâ”‚ para mediar ante las autoridades civiles. No fue aceptado este gesto, y la condena fue cumplida. En la imagen, Eloy Fernâ”œأ­ndez Clemente con su compaâ”œâ–’era, ademâ”œأ­s de amigos y amigas del entorno de "Andalâ”œأ­n", a la salida de la câ”œأ­rcel de Torrero.', 1975, 1975, 1975, 'Anos 70', 'TORRERO', 41.62743600, -0.88681700, '0101000020E6100000BA2D910BCE60ECBFA22AA6D24FD04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14807693009.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14807693009.webp', 'https://www.flickr.com/photos/zaragozaantigua/14807693009/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23638, 'Câ”œأ­rcel de Torrero 1977', 'Foto: Arturo Burgos. "Sobre las seis de la tarde del dâ”œآ،a 19 de Julio de 1977 unos cuarenta presos comunes se subieron al tejado de uno de los pabellones con pancartas en las que pedâ”œآ،an Amnistâ”œآ،a y Libertad. Permanecieron en el tejado durante toda la noche y al mediodâ”œآ،a siguiente depusieron la protesta. Igualmente hubo motines en otras câ”œأ­rceles del estado, como Carabanchel y Puerto de Santa Marâ”œآ،a, donde hubo un muerto. Aquel dâ”œآ،a hubo una autâ”œآ®ntica batalla campal entre las fuerzas antidisturbios y los vecinos del barrio y de otras zonas de Zaragoza que subâ”œآ،an a Torrero a demostrar su solidaridad con los presos. Aquella tarde-noche fueron frecuentes las carreras, las cargas policiales que dispararon pelotas de goma, mientras los ciudadanos se defendâ”œآ،an de â”œآ®stos tirâ”œأ­ndoles piedras. Todas las calles cercanas a la prisiâ”œâ”‚n estaban tomadas por los grises, resultando heridos de pelotas de goma algunos jâ”œâ”‚venes. Estas manifestaciones fueron convocadas por la COPEL (Coordinadora de Presos en Lucha)." Del libro "Torrero. Un paseo por el recuerdo". Transcrito por Raâ”œâ•‘l Bernal. Fuente visual: Heraldo de Aragâ”œâ”‚n.', 1977, 1977, 1977, 'Anos 70', 'TORRERO', 41.62757800, -0.88677200, '0101000020E6100000BB4560AC6F60ECBF34D8D47954D04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15103438336.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15103438336.webp', 'https://www.flickr.com/photos/zaragozaantigua/15103438336/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23642, 'Misa en Torrero 1940', 'Archivo Municipal. Gerardo Sancho Ramo. 1940. "Misa en la Prisiâ”œâ”‚n Provincial de Torrero." Imagen de una de las "Comuniones Pascuales" impartidas con un carâ”œأ­cter voluntariamente obligatorio, en las que por medio de sermones sacerdotales se buscaba la re-catolizaciâ”œâ”‚n y re-ideologizaciâ”œâ”‚n de los presos. Tras el sermâ”œâ”‚n, la comuniâ”œâ”‚n, el himno nacional musicado, y nutridos vivas a Espaâ”œâ–’a y al Generalâ”œآ،simo. Al sonar la mâ”œâ•‘sica los reclusos tenâ”œآ،an que saludar con la mano derecha levantada y bien abierta, realizando el saludo fascista, y vitorear tres veces a Franco. Despuâ”œآ®s de esto, los presos eran أ”أ‡آ£recompensadosأ”أ‡أک con una raciâ”œâ”‚n doble de rancho. Desde julio de 1936, hasta setiembre de 1945, (dâ”œآ،as despuâ”œآ®s de la firma de la rendiciâ”œâ”‚n incondicional del Japâ”œâ”‚n), el saludo fascista fue obligatorio en todos los actos sociales pâ”œâ•‘blicos, institucionales, etc, de la Espaâ”œâ–’a franquista. Las câ”œأ­rceles no fueron una excepciâ”œâ”‚n, ya fuera el penado "comâ”œâ•‘n", o "polâ”œآ،tico". El saludo perdurâ”œâ”‚ hasta dâ”œآ®cadas despuâ”œآ®s, y mâ”œأ­s.', 1940, 1940, 1940, 'Anos 40', 'TORRERO', 41.62731500, -0.88698400, '0101000020E6100000906802452C62ECBF27A5A0DB4BD04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15711127491.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15711127491.webp', 'https://www.flickr.com/photos/zaragozaantigua/15711127491/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23655, 'Polvorines Torrero 1895', '"LA CATâ”œأ¼STROFE DE ZARAGOZA. Honda consternaciâ”œâ”‚n causâ”œâ”‚ en toda Espaâ”œâ–’a la desgracia acaecida en la capital aragonesa el 23 del pasado (mes de febrero). Hallâ”œأ­banse cinco pobres muchachas descargando cartuchos en las cuevas prâ”œâ”‚ximas al polvorâ”œآ،n de Torrero, habilitadas para dicho objeto, cuando al terminar la faena, â”œأ­ eso de la una de la tarde, explotaron seis cajas de aquâ”œآ®llos, sistema Berdan. Habâ”œآ،a reventado un cartucho en manos de una de las infelices operarias, y prendiâ”œâ”‚ fuego en las cajas. Las vâ”œآ،ctimas, con los vestidos ardiendo, se lanzaron fuera de la cueva; al ruido de la explosiâ”œâ”‚n, acudieron los soldados que prestaban servicio en los puestos inmediatos, y socorrieron â”œأ­ las vâ”œآ،ctimas, al mismo tiempo que trataban de localizar el incendio, el cual, de haberse propagado â”œأ­ los polvorines inmediatos, hubiera causado estragos muchâ”œآ،simo mâ”œأ­s horribles aâ”œâ•‘n. Han fallecido ya tres mujeres, despuâ”œآ®s de agudâ”œآ،simos sufrimientos." Este dibujo ilustraba la noticia, referida a un accidente en los polvorines que el Ejâ”œآ®rcito tenâ”œآ،a al sur del cementerio de Torrero, en una zona de casi 13 hectâ”œأ­reas de extensiâ”œâ”‚n. Tras la "Operaciâ”œâ”‚n Cuarteles" de finales de los aâ”œâ–’os 70 del pasado siglo, el desalojo de estos polvorines sirviâ”œâ”‚ para ampliar el cementerio hasta el Barranco de la Muerte. Fuente: "La Ilustraciâ”œâ”‚n Ibâ”œآ®rica", Barcelona.', 1895, 1895, 1895, 'Siglo XIX', 'TORRERO', 41.61749500, -0.88884100, '0101000020E610000086014BAE6271ECBFC5387F130ACF4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20494670764.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20494670764.webp', 'https://www.flickr.com/photos/zaragozaantigua/20494670764/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23657, 'Câ”œأ­rcel de Torrero c.1970', 'Vista aâ”œآ®rea centrada en la Câ”œأ­rcel de Torrero de Zaragoza. Abajo, edificio de acceso por la avenida de Amâ”œآ®rica 109. Fue inaugurada en 1928 como Prisiâ”œâ”‚n Provincial y demolida parcialmente en 2005. Fuente visual: www.rolde.org/', 1970, 1970, 1970, 'Anos 70', 'TORRERO', 41.62731500, -0.88698400, '0101000020E6100000906802452C62ECBF27A5A0DB4BD04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22141895038.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22141895038.webp', 'https://www.flickr.com/photos/zaragozaantigua/22141895038/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23660, 'Câ”œأ­rcel 2005', 'Comienzo de la demoliciâ”œâ”‚n de la câ”œأ­rcel de Torrero, dejando sâ”œâ”‚lo en pie el edificio de acceso, en julio de 2005. Fuente: Agencia EFE.', 2005, 2005, 2005, 'Siglo XXI', 'TORRERO', 41.62731500, -0.88698400, '0101000020E6100000906802452C62ECBF27A5A0DB4BD04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24382413739.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24382413739.webp', 'https://www.flickr.com/photos/zaragozaantigua/24382413739/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23681, 'Canal Imperial c.1905', 'Inâ”œآ®dita imagen capturada a orillas del Canal Imperial tras el recto tramo de la Playa de Torrero, donde se desvâ”œآ،a bruscamente, casi 90 grados, y se encamina en paralelo al camino del Cabezo Cortado y de la quinta de Julieta Sagols. En primer tâ”œآ®rmino, algunas de las grandes barcazas de transporte canalino de mercancâ”œآ،as con un posado colectivo de sus manejadores, ademâ”œأ­s de algâ”œâ•‘n ocasional tancredo. Justo detrâ”œأ­s y en la margen derecha, choperas de los viveros del Canal. En la margen izquierda, de fondo, el paseo de la Playa de Torrero con algunos de los pabellones e instalaciones del Cuartel de Torrero, y de los talleres y almacenes del Canal Imperial. Se destaca por su altura y caracterâ”œآ،stica figura, entre los chopos, la câ”œâ•‘pula de la neoclâ”œأ­sica iglesia de San Fernando,', 1905, 1905, 1905, 'Anos 1900', 'TORRERO', 41.63235600, -0.88166300, '0101000020E6100000E3FBE2529536ECBFF6B6990AF1D04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/48015320327.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/48015320327.webp', 'https://www.flickr.com/photos/zaragozaantigua/48015320327/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24035, 'Cementerio 1943', 'El 21 de abril de 1943 tuvo lugar una bizarra escenificaciâ”œâ”‚n en el cementerio de Torrero, coincidiendo con la oficial celebraciâ”œâ”‚n fascista del "aniversario" de la fundaciâ”œâ”‚n de la ciudad de Roma, en tiempos en que las cosas imperiales estaban muy en boga en ambos paâ”œآ،ses. Estirando la visita a las obras del "Sacrario Militare" que entonces se estaba erigiendo en Cuâ”œآ®llar, como homenaje a los italianos "muertos en la Cruzada espaâ”œâ–’ola", tuvo lugar una visita al cementerio de la "Aviazione Legionaria" de Torrero, inaugurado en 1940, donde los generales Augusto Grassi (saludando, a la izquierda, sic), Arriani, y el coronel Carnevale, depositaron flores a sus paisanos fallecidos, oyeron misa, y estuvieron acompaâ”œâ–’ados de una nutrida comparsa de jerarcas y autoridades militares y civiles locales, algunas de las cuales fueron luego condecoradas como "caballeros de la orden de la Corona de Italia". En la imagen, parafernalia fascista del referido homenaje, bajo los estandartes de la Italia y Espaâ”œâ–’a del momento, ademâ”œأ­s de las de Falange, y los carlistas, en el legionario recinto habilitado en una parcela de la ampliaciâ”œâ”‚n de 1936 del cementerio. En 1946, cuando el contexto sociopolâ”œآ،tico italiano era uno muy distinto del de 1943, y acabado el nuevo-viejo "Sacrario Militare", comenzâ”œâ”‚ la inhumaciâ”œâ”‚n de los restos de esta parcela, y su traslado a Cuâ”œآ®llar. Extramuros del Sacrario, todo seguâ”œآ،a igual. Fuente visual: Archivo Municipal de Zaragoza.', 1943, 1943, 1943, 'Anos 40', 'TORRERO', 41.62312800, -0.88256300, '0101000020E6100000D61BB5C2F43DECBF679C86A8C2CF4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/29211917616.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/29211917616.webp', 'https://www.flickr.com/photos/zaragozaantigua/29211917616/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24951, 'Puente nuevo sobre el Huerva 1928', 'Imagen capturada desde la prolongaciâ”œâ”‚n de la Gran Vâ”œآ،a poco antes de finalizar la obra de construcciâ”œâ”‚n del nuevo puente sobre el râ”œآ،o Huerva, que serâ”œآ،a inaugurado al aâ”œâ–’o siguiente con la presencia del dictador Primo de Rivera, por lo que el puente fue denominado del Trece de Septiembre (fecha del golpe de estado de 1923 encabezado por â”œآ®l con el consentimiento y respaldo del rey Alfonso XIII y del bloque hegemâ”œâ”‚nico de poder). Al fondo, el nuevo parque de Buenavista, y a la derecha, la chimenea de la fâ”œأ­brica de harinas la Imperial de Aragâ”œâ”‚n, junto al Canal Imperial. Fuente visual: Zaragoza, dos milenios de agua.', 1928, 1928, 1928, 'Anos 20', 'UNIVERSIDAD', 41.63730400, -0.89775100, '0101000020E610000004711E4E60BAECBF14CE6E2D93D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/36591084032.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/36591084032.webp', 'https://www.flickr.com/photos/zaragozaantigua/36591084032/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24943, 'Cabezo de Buenavista c.1920', 'Desde la altura del Cabezo de Buenavista, un vistazo en direcciâ”œâ”‚n a la zanja del râ”œآ،o Huerva y la antigua carretera de Zaragoza a Teruel, antes de que el previsto y nuevo parque de Buenavista fuera una realidad. Hasta entonces, entre el Huerva y el Cabezo, se extendâ”œآ،a un notable conjunto de huertas y campos de labor, apenas vertebrado por el Camino del Sâ”œأ­bado y el antiguo Camino de Cuarte, y estaba surcado por acequias fluyendo desde el Canal, como la de las Adulas, y riegos derivados y subsidiarios de ella, como el del Tuerto, y el de Fortea. Al fondo, despuntan elevados los macizos pabellones seriados del "Manicomio", en el Terminillo. Pocos aâ”œâ–’os despuâ”œآ®s, las expropiaciones y obras transformarâ”œآ،an este bucâ”œâ”‚lico lugar de forma destacada, convirtiâ”œآ®ndolo en el humanizado Parque Buenavista. Fuente visual: Archivo fotogrâ”œأ­fico histâ”œâ”‚rico del SIPA (DARA-AHPZ).', 1920, 1920, 1920, 'Anos 20', 'UNIVERSIDAD', 41.63359100, -0.89335200, '0101000020E61000003F1EFAEE5696ECBF1D05888219D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23995412136.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23995412136.webp', 'https://www.flickr.com/photos/zaragozaantigua/23995412136/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24092, 'Cabezo de Buenavista 1985', 'Imagen capturada en el Cabezo de Buenavista del Parque de Primo de Rivera durante la inauguraciâ”œâ”‚n del "Monumento a los aragoneses en campos de concentraciâ”œâ”‚n alemanes" el 22 de septiembre de 1985. Con motivo de la celebraciâ”œâ”‚n de la asamblea anual de la "Amical de Mauthausen" en Zaragoza, se organizaron varias actividades vinculadas con la entonces minoritaria reivindicaciâ”œâ”‚n de la Memoria histâ”œâ”‚rica vinculada a este atroz episodio de la represiâ”œâ”‚n nazi-fascista: la exposiciâ”œâ”‚n "Exilio y Deportaciâ”œâ”‚n" en dependencias de la DPZ, una recepciâ”œâ”‚n oficial del presidente de la Diputaciâ”œâ”‚n General de Aragâ”œâ”‚n, Santiago Marraco, un pleno extraordinario en el Ayuntamiento, y la inauguraciâ”œâ”‚n de este monumento con presencia del alcalde accidental, Antonio Gonzâ”œأ­lez Triviâ”œâ–’o. La Amical de Mauthausen es una asociaciâ”œâ”‚n que agrupa desde 1962 a los exdeportados republicanos (los "espaâ”œâ–’oles rojos") de los campos de concentraciâ”œâ”‚n del nazismo, asâ”œآ، como a los familiares y amigos, tanto de los supervivientes como de los deportados asesinados en los campos. El monumento fue diseâ”œâ–’ado por Fernando Fernâ”œأ­ndez Lâ”œأ­zaro, con unas decrecientes y fracturadas barras en hormigâ”œâ”‚n armado que representan la bandera de Aragâ”œâ”‚n a cuya derecha continuaba un cuerpo sobre el que se colocâ”œâ”‚ una placa con el texto "El Ayuntamiento de Zaragoza en homenaje a los aragoneses confinados en los campos de concentraciâ”œâ”‚n alemanes durante la segunda guerra mundial. Septiembre 1985". Los ajustados plazos de tiempo con que se realizâ”œâ”‚ esta obra impidieron que pudiera completarse con algunos elementos diseâ”œâ–’ados para la misma, que ya no se aâ”œâ–’adieron despuâ”œآ®s. Las reiteradas agresiones fascistas y neonazis a este monumento, pues no permiten mâ”œأ­s memoria histâ”œâ”‚rica que la sectaria y apologâ”œآ®tica suya propia, exclusiva durante mâ”œأ­s de 40 aâ”œâ–’os, ya destruyeron la original placa, que hubo de ser repuesta. Ademâ”œأ­s, y de forma periâ”œâ”‚dica, el monumento debe ser higienizado y limpiado de tâ”œâ”‚xicas pintadas y sâ”œآ،mbolos nazis por el Servicio de Parques y Jardi', 1985, 1985, 1985, 'Anos 80', 'TORRERO', 41.63085700, -0.89434500, '0101000020E610000074EACA67799EECBFF1B913ECBFD04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/48765621818.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/48765621818.webp', 'https://www.flickr.com/photos/zaragozaantigua/48765621818/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24859, 'Av. Amâ”œآ®rica 1978', 'Imagen de la avenida de Amâ”œآ®rica entre la calle Antonio Adrados (antigua de Marcos Sevil, desde 2009 de Juan Francisco Andrâ”œآ®s de Uztarroz), al fondo, y la calle Sancho Ramâ”œآ،rez, en un tramo todavâ”œآ،a caracterizado por antiguas y seriadas parcelas en el lado de los impares (luego mayormente desaparecidas) con sus traseras recayentes a la calle San Josâ”œآ® de Pignatelli (a la izquierda, fuera de plano). Flanquean a los dos carriles habilitados para la circulaciâ”œâ”‚n rodada de bajada, dos carriles para aparcamiento, en zona aparentemente peatonal delimitada por un bordillo, por la cual tambiâ”œآ®n transitaba, de cuando en cuando, algâ”œâ•‘n despistado peatâ”œâ”‚n. Fuente visual: Banco de Imâ”œأ­genes/Asociaciâ”œâ”‚n de Vecinos Barrio de San Josâ”œآ®, amablemente cedida para el', 1978, 1978, 1978, 'Anos 70', 'TORRERO', 41.63135600, -0.88540600, '0101000020E610000063D4B5F63E55ECBF1211FE45D0D04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32458423993.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32458423993.webp', 'https://www.flickr.com/photos/zaragozaantigua/32458423993/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24924, 'Mausoleo de Costa 1912', 'Boceto definitivo para el mausoleo de Joaquâ”œآ،n Costa en Zaragoza. Acuarela de Fâ”œآ®lix Lafuente y Manuel Bescâ”œâ”‚s, 1912. Fuente: www.bne.es', 1912, 1912, 1912, 'Anos 10', 'TORRERO', 41.62031800, -0.88575000, '0101000020E6100000F2D24D621058ECBF608F899466CF4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/38978230404.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/38978230404.webp', 'https://www.flickr.com/photos/zaragozaantigua/38978230404/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24968, 'Campo de fâ”œâ•‘tbol de Torrero 1975', 'Archivo Municipal Zaragoza. Gerardo Sancho Ramo. 15/06/1975. "Homenaje a Violeta." Imagen del viejito campo de fâ”œâ•‘tbol de Torrero, las traseras de la porterâ”œآ،a que daba a la calle Monzâ”œâ”‚n. Al fondo, detrâ”œأ­s de lo que hoy es la calle Honoroy Garcâ”œآ،a Condoy, y la chavalerâ”œآ،a encaramada en el muro, el Colegio "El Buen Pastor" y, a pocos metros, el Canal Imperial. Se nota que el campo estâ”œأ­ bastante dejado, a punto de la piqueta, y la naturalizaciâ”œâ”‚n del espacio en forma de vegetaciâ”œâ”‚n es bien aprovechada por su sombra en un dâ”œآ،a de junio ya poco fresco. El evento deportivo es un homenaje al "Leâ”œâ”‚n de Torrero", Josâ”œآ® Luis Violeta, indâ”œآ،gena del barrio y superlativo jugador del Real Zaragoza.', 1975, 1975, 1975, 'Anos 70', 'TORRERO', 41.62984600, -0.88316500, '0101000020E61000005019FF3EE342ECBF1AC231CB9ED04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15260315121.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15260315121.webp', 'https://www.flickr.com/photos/zaragozaantigua/15260315121/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24969, 'Campo de Torrero 1968', 'Archivo Municipal. Gerardo Sancho Ramo. Enero 1968. Imagen del campo de fâ”œâ•‘tbol de Torrero. Los edificios del fondo, parcelitas incluidas, en la calle Lasierra Purroy.', 1968, 1968, 1968, 'Anos 60', 'TORRERO', 41.63069600, -0.88341900, '0101000020E6100000E04735ECF744ECBFE8DB82A5BAD04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15537925898.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15537925898.webp', 'https://www.flickr.com/photos/zaragozaantigua/15537925898/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24970, 'Campo de Torrero 1966', 'Archivo Municipal. Gerardo Sancho Ramo. Setiembre 1966. Imagen parcial del estado del campo de Torrero en la segunda mitad de los aâ”œâ–’os 60 del pasado siglo. La captura ha sido realizada desde el câ”œâ”‚rner del fondo sur (que daba a la calle Monzâ”œâ”‚n), mirando hacia la calle Lasierra Purroy, cuyo nâ”¬â•‘ 64 sobresale por encima de "las gradas". De una forma u otra, este espacio seguâ”œآ،a siendo usado para la prâ”œأ­ctica de deportes varios, incluyendo el de la toma de sol como prolongaciâ”œâ”‚n de la cercana piscina.', 1966, 1966, 1966, 'Anos 60', 'TORRERO', 41.62976600, -0.88366900, '0101000020E610000016A6EF350447ECBFFD101B2C9CD04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15865489700.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15865489700.webp', 'https://www.flickr.com/photos/zaragozaantigua/15865489700/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24977, 'Campo de fâ”œâ•‘tbol de Torrero 1970', 'Foto: Josâ”œآ® Luis Cintora. Aspecto del campo de fâ”œâ•‘tbol de Torrero (izquierda) utilizado para tomar el sol en verano, con la piscina anexa a la derecha. Fuente: rafaelcastillejo.com', 1970, 1970, 1970, 'Anos 70', 'TORRERO', 41.63069600, -0.88341900, '0101000020E6100000E04735ECF744ECBFE8DB82A5BAD04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20692443496.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20692443496.webp', 'https://www.flickr.com/photos/zaragozaantigua/20692443496/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24985, 'Torrero 1974', 'Imagen del antiguo campo de Torrero, como escenario de la final del campeonato de fâ”œâ•‘tbol de equipos de empresas, ganada por la plantilla de la picarraleâ”œâ–’a fâ”œأ­brica "TUSA" a los "Zetaceros". El posado incluye al trâ”œآ،o arbitral, los capitanes de ambos equipos, y una joven de protocolo. Al fondo, la descomunal nueva grada levantada en una parte del lienzo este del campo, recayente a un vial que unos aâ”œâ–’os despuâ”œآ®s serâ”œآ،a denominado Honorio Garcâ”œآ،a Condoy. A la derecha, asoma el colegio "Buen Pastor". Fuente visual: Antonio Calvo Pedrâ”œâ”‚s, AMZ.', 1974, 1974, 1974, 'Anos 70', 'TORRERO', 41.63020100, -0.88288500, '0101000020E61000007120240B9840ECBF0874266DAAD04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30653146521.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30653146521.webp', 'https://www.flickr.com/photos/zaragozaantigua/30653146521/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24944, 'Parque Grande 1969', 'El sâ”œأ­bado 7 de mayo llegâ”œâ”‚ a Zaragoza la serpiente multicolor de la Vuelta Ciclista a Espaâ”œâ–’a de ese aâ”œâ–’o. Tras un primer sector de etapa cubierto entre Barbastro y Zaragoza, de apenas 121 kilâ”œâ”‚metros, ganado por el belga Raymond Steegmans, y tras un descanso de poco mâ”œأ­s de media hora, comenzâ”œâ”‚ el segundo sector de la etapa, consistente en una contrarreloj individual en un circuito urbano de cuatro kilâ”œâ”‚metros. El ganador fue el francâ”œآ®s Roger Pingeon, a la postre vencedor de la Vuelta. En segundo lugar de la clasificaciâ”œâ”‚n general quedarâ”œأ­ el espaâ”œâ–’ol Luis Ocaâ”œâ–’a, que en la imagen es vitoreado durante su participaciâ”œâ”‚n en la zaragozana pugna contra Cronos, en el paseo de los Bearneses del parque Primo de Rivera. Fuente visual: Gerardo Sancho Ramo (Archivo Pâ”œâ•‘blico Municipal).', 1969, 1969, 1969, 'Anos 60', 'UNIVERSIDAD', 41.63297600, -0.89516900, '0101000020E6100000A7936C7539A5ECBF9293895B05D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24086220032.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24086220032.webp', 'https://www.flickr.com/photos/zaragozaantigua/24086220032/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25078, 'Torrero 1976', 'Como Vicepresidente Segundo del Gobierno, y Ministro de la Gobernaciâ”œâ”‚n del Reino de Espaâ”œâ–’a, Manuel Fraga Iribarne mantuvo su viaje programado a Zaragoza, a pesar de la imprevista dimisiâ”œâ”‚n del Presidente del Gobierno, Carlos Arias Navarro. A la visita a los heridos por la catâ”œأ­strofe explosiva en la factorâ”œآ،a de Butano en Utebo, la participaciâ”œâ”‚n en los actos del bimilenario de la romana fundaciâ”œâ”‚n de Zaragoza, se le sumâ”œâ”‚ un cariâ”œâ–’oso y popular acto "organizado" por la Asociaciâ”œâ”‚n de Cabezas de Familia del barrio de Torrero, en el que estuvo acompaâ”œâ–’ado, entre otros, por el Alcalde de la ciudad, Miguel Merino, y el Gobernador Civil, Manuel Marâ”œآ،a Uriarte Zulueta. En la imagen, Fraga, flanqueado por el Alcalde (izquierda) y por el Gobernador Civil (derecha), en su intervenciâ”œâ”‚n en la "Hermandad del Buen Pastor", sede de la Asociaciâ”œâ”‚n de Cabezas de Familia de Torrero. Apenas un par de dâ”œآ،as despuâ”œآ®s, fue cesado en sus gubernativas funciones. Fuente visual: Gerardo Sancho Ramo (Archivo Pâ”œâ•‘blico Municipal).', 1976, 1976, 1976, 'Anos 70', 'TORRERO', 41.62826800, -0.88385100, '0101000020E6100000412E71E48148ECBFC98FF8156BD04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24087399671.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24087399671.webp', 'https://www.flickr.com/photos/zaragozaantigua/24087399671/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25108, 'Batalla de Zaragoza, 1710', 'Schlacht bei Saragossa, 1710 Sieg â”œâ•‌ber die Galli-Spanier bey Saragossa, Anno 1710, den 20. Augusti Dibujo: Paul Decker Grabador: Johann Jakob Kleinschmidt Editor: Jeremias Wolf Batalla de Zaragoza. Episodio bâ”œآ®lico de la Guerra de Sucesiâ”œâ”‚n Espaâ”œâ–’ola, con victoria de los proaustrias (alemanes, austrâ”œآ،acos, ingleses, holandeses, y espaâ”œâ–’oles) dirigidos por Starhemberg y Stanhope, ante los proborbones (espaâ”œâ–’oles) comandados por de Bay, el 20 de agosto de 1710. Se desarrollâ”œâ”‚ en las estribaciones de los montes de Torrero (Turmwâ”œأ±chterberg). El grabado representa, en primer plano, al victorioso rey Carlos de Austria a caballito, seguido de Hâ”œآ®rcules mamporrero, mientras pisotea una malâ”œآ®fica representaciâ”œâ”‚n del enemigo borbâ”œâ”‚nico. A los pies de los caballos, Zaragoza se entrega al nuevo rey mediante el simbolismo de las llaves de la ciudad, mientras unos representantes municipales (no electos), de los estamentos privilegiados, le rinden sentida pleitesâ”œآ،a, como antes habâ”œآ،an hecho con el rey borbâ”œâ”‚n, y como volverâ”œأ­n a hacer en unos pocos meses. Detrâ”œأ­s del rey austrâ”œآ،aco, la Fama enarbola una banderola en la que se describen, en imperial alemâ”œأ­n, los acontecimientos bâ”œآ®licos. Volando alto, un â”œأ­ngel trompetero anuncia el portentoso evento a los cuatro vientos. Al fondo, una escenificaciâ”œâ”‚n de la batalla. Mâ”œأ­s al fondo, entre humo, Zaragoza y sus torres. Fuente: www.rijksmuseum.nl/nl/collectie/BI-B-FM-073-49', 1710, 1710, 1710, 'Siglo XIX', 'TORRERO', 41.61662900, -0.88246800, '0101000020E61000006687F8872D3DECBFF261F6B2EDCE4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14815040117.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14815040117.webp', 'https://www.flickr.com/photos/zaragozaantigua/14815040117/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25117, 'Batalla de Zaragoza 1710', 'Bataille de Saragosse et Plan des environs de Saragosse : [estampe]. Bibliothâ”œآ؟que Nationale de France. Escena bâ”œآ®lica de la Batalla de Zaragoza, en el Barranco de la Muerte, el 20 de agosto de 1710. Al fondo, vista de Zaragoza y la Aljaferâ”œآ،a. En la parte inferior, mapa de Zaragoza y sus alrededores. Mâ”œأ­s informaciâ”œâ”‚n: es.wikipedia.org/wiki/Batalla_de_Zaragoza', 1710, 1710, 1710, 'Siglo XIX', 'TORRERO', 41.61662900, -0.88246800, '0101000020E61000006687F8872D3DECBFF261F6B2EDCE4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15154195528.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15154195528.webp', 'https://www.flickr.com/photos/zaragozaantigua/15154195528/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25119, 'Batalla de Zaragoza 1710', 'Batalla de Zaragoza. Kunsthistorisches Museum. Viena. Autor desconocido. La batalla de Zaragoza o batalla del monte Torrero se librâ”œâ”‚ el 20 de agosto de 1710 en el marco de la Guerra de Sucesiâ”œâ”‚n Espaâ”œâ–’ola. En la pintura podemos ver las refriegas en la zona alta del barranco de la Muerte, donde hoy se levanta un centro comercial gigantesco. Fuente visual: es.wikipedia.org/wiki/Batalla_de_Zaragoza', 1710, 1710, 1710, 'Siglo XIX', 'TORRERO', 41.61662900, -0.88246800, '0101000020E61000006687F8872D3DECBFF261F6B2EDCE4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15238187111.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15238187111.webp', 'https://www.flickr.com/photos/zaragozaantigua/15238187111/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25121, 'Batalla de Zaragoza 1710', '"Slag bij Zaragoza, 1710", Romeyn de Hooghe, Amsterdam. "De slag bij Zaragoza. Overwinning van de Geallieerden onder Karel III (aartshertog Karel van Oostenrijk) op de Fransen op 20 augustus 1710". (Relaciâ”œâ”‚n exacta de todo lo que sucediâ”œâ”‚ en la victoria cerca de Zaragoza, conseguida por el rey Carlos III, contra el ejâ”œآ®rcito del duque de Anjou el 20 de agosto de 1710). Fuente visual: www.rijksmuseum.nl', 1710, 1710, 1710, 'Siglo XIX', 'TORRERO', 41.61662900, -0.88246800, '0101000020E61000006687F8872D3DECBFF261F6B2EDCE4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15575839168.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15575839168.webp', 'https://www.flickr.com/photos/zaragozaantigua/15575839168/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25128, 'Batalla de Zaragoza 1710', '"Den 20 Aug. 1710 heeft het Leger van Kon Carel III by Zaragossa in Arragon, een glorieuse Vict ..." et caetera. Autor: Petrus Schenk. Lugar del grabado: Amsterdam. Fecha: posterior a 1710. Reproduce un mapa de la cuenca media del râ”œآ،o Ebro centrado en Zaragoza, trazado con motivo de la batalla sita en el Barranco de la Muerte de esta localidad, el 20 de agosto de 1710, entre los ejâ”œآ®rcitos del austracista Carlos, y el borbâ”œâ”‚nico Felipe. La ciudad ha sido seâ”œâ–’alada como si de un bâ”œâ•‘nker se tratara, aunque es un convencionalismo de la â”œآ®poca. El medieval muro de râ”œآ®jola daba para lo que daba. Debajo, una escena idealizada del combate. El autor ha optado por una prudente bruma que envuelve la batalla para evitar tener que inventarse el aspecto de Zaragoza, salvo un pedazo de fantâ”œأ­stica torre. Como pie de imagen, una explicaciâ”œâ”‚n en holandâ”œآ®s y latâ”œآ،n de lo sucedido. Fuente: www.cortesaragon.es/', 1710, 1710, 1710, 'Siglo XIX', 'TORRERO', 41.61662900, -0.88246800, '0101000020E61000006687F8872D3DECBFF261F6B2EDCE4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/16469146020.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/16469146020.webp', 'https://www.flickr.com/photos/zaragozaantigua/16469146020/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25130, 'Batalla de Zaragoza 1710', '"The Battle of Sarragossa [sic]" Nathaniel Parr, 1739 Grabado que ilustra la batalla del Barranco de la Muerte entre el archiduque Carlos de Austria (coronado en Viena como rey de Espaâ”œâ–’a en 1703), y el duque Felipe de Anjou (coronado en Madrid como rey de Espaâ”œâ–’a en 1701). Al fondo, representaciâ”œâ”‚n muy lejanamente aproximada de la ciudad de "Sarragossa", delante de la cual las tropas borbâ”œâ”‚nicas se baten en retirada ante la acometida de la caballerâ”œآ،a inglesa mercenaria del austria. Apenas son visibles, pero hay unos carmelitas descalzos subidos en los tejados de su convento de San Joseph, junto al arroyo de la Huerba, mirando con atenciâ”œâ”‚n prâ”œأ­ctica el desenlace bâ”œآ®lico para orientar convenientemente su leal fidelidad al ganador de la batalla. El archiduque Carlos, vencedor de la batalla, cabalga en primer plano como si estuviera de paseo por un bien despejado monte de Torrero. Fuente visual: www.britishmuseum.org/', 1710, 1710, 1710, 'Siglo XIX', 'TORRERO', 41.61662900, -0.88246800, '0101000020E61000006687F8872D3DECBFF261F6B2EDCE4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/17693851185.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/17693851185.webp', 'https://www.flickr.com/photos/zaragozaantigua/17693851185/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25156, 'Barranco de la Muerte 1710', 'Pintura recreando una carga de caballerâ”œآ،a realizada por el 10â”¬â•‘ de Dragones durante la batalla de Zaragoza, a finales del mes de agosto de 1710, en el marco de la Guerra de Sucesiâ”œâ”‚n espaâ”œâ–’ola. A pesar de la buena actuaciâ”œâ”‚n de la caballerâ”œآ،a, a la derecha del campo de batalla, la descomposiciâ”œâ”‚n de las alas izquierda y centro del ejâ”œآ®rcito borbâ”œâ”‚nico derivâ”œâ”‚ en clara derrota tâ”œأ­ctica que supuso la recuperaciâ”œâ”‚n de Zaragoza por el archiduque Carlos, que entrâ”œâ”‚ por segunda vez en la ciudad. Apenas cuatro meses despuâ”œآ®s, y con la destaca participaciâ”œâ”‚n del 10â”¬â•‘ de Dragones, en las batallas de Brihuega y Villaviciosa la guerra dio un nuevo vuelco, definitivo, a favor de Felipe V. Este regimiento de caballerâ”œآ،a sobre el pie, reconocible por su llamativo uniforme amarillo, fue creado en 1709 por Jaime Miguel de Guzmâ”œأ­n Dâ”œأ­valos y Spinola, conde de Pezuela y marquâ”œآ®s de la Mina. Desde 1718, este regimiento de caballerâ”œآ،a es denominado "Lusitania". Fuente visual: "El zurdo", â”œâ”‚leo sobre tabla, Marco Ortolan, 2010, en es.pinterest.com/', 1710, 1710, 1710, 'Siglo XIX', 'TORRERO', 41.61662900, -0.88246800, '0101000020E61000006687F8872D3DECBFF261F6B2EDCE4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31913066342.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31913066342.webp', 'https://www.flickr.com/photos/zaragozaantigua/31913066342/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25941, 'Batalla de Zaragoza 1710', 'En Viena puede verse una imagen de la Zaragoza de comienzos del siglo XVIII. Basta con acercarse al convento de los Capuchinos o Cripta Imperial de la Casa Habsburgo, en la Karlsgruft (Cripta de Carlos), donde se halla el sarcâ”œâ”‚fago del emperador Carlos VI. Este Carlos fue pretendiente a la Corona espaâ”œâ–’ola durante la Guerra de Sucesiâ”œâ”‚n Espaâ”œâ–’ola (1700-1711), hasta que la muerte de su hermano le convirtiâ”œâ”‚ en emperador alemâ”œأ­n, dejando el trono espaâ”œâ–’ol expedido a Felipe V. En la imagen, esplendoroso sarcâ”œâ”‚fago de Carlos VI, fallecido en 1740, en cuyo frontal fue tallado en relieve la "Batalla de Zaragoza" de agosto de 1710. A pesar de la relativa importancia de esta batalla, que fue ganada por el ejâ”œآ®rcito del pretendiente austriaco, apenas le dio el control de Zaragoza durante cuatro meses. Esta batalla aparece reseâ”œâ–’ada en el frontal del sepulcro junto a los grandes sâ”œآ،mbolos del Sacro Imperio Romano Germâ”œأ­nico (cetro, espada, Toisâ”œâ”‚n de Oro, Orbe...), y custodiado por cuatro calaveras que portan la corona hâ”œâ•‘ngara de San Wenceslao, la Imperial Germana, la del Sacro Imperio Romano Germâ”œأ­nico, y... la corona de Castilla. El gran relieve frontal recoge el despliegue de tropas en la batalla que tuvo lugar al sureste de Zaragoza el 21 de agosto de 1710, y cuya acciâ”œâ”‚n bâ”œآ®lica mâ”œأ­s destacada transcurriâ”œâ”‚ en el Barranco de la Muerte. Al fondo, amurallada, la ciudad con su extensa colecciâ”œâ”‚n de torres. Fuente visual: www.cuk.ch/articles/5028', 1710, 1710, 1710, 'Siglo XIX', 'TORRERO', 41.61662900, -0.88246800, '0101000020E61000006687F8872D3DECBFF261F6B2EDCE4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/16229583918.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/16229583918.webp', 'https://www.flickr.com/photos/zaragozaantigua/16229583918/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25948, 'Cementerio c.1920', 'Puerta de acceso, desde el exterior del cementerio de Torrero. Fuente: Foto Jesâ”œâ•‘s Cormâ”œأ­n. AMZ.', 1920, 1920, 1920, 'Anos 20', 'TORRERO', 41.62386200, -0.88765100, '0101000020E6100000D05FE811A367ECBFCC9BC3B5DACF4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24888246306.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24888246306.webp', 'https://www.flickr.com/photos/zaragozaantigua/24888246306/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25949, 'Batalla de Zaragoza 1710', 'Imagen con la representaciâ”œâ”‚n de la batalla de Zaragoza de 1710, evento bâ”œآ®lico de la guerra de Sucesiâ”œâ”‚n espaâ”œâ–’ola cuyo desenlace marcâ”œâ”‚ el retorno de la ciudad a la fidelidad del archiduque Carlos de Austria. Este relieve forma parte del frontal del sarcâ”œâ”‚fago del "Kaiser Karl VI", que fue en lo que se convirtiâ”œâ”‚ el archiduque poco tiempo despuâ”œآ®s de esta batalla, cuando las obligaciones familiares le convirtieron en emperador del Sacro Imperio Romano Germâ”œأ­nico, y dejâ”œâ”‚ la aventura espaâ”œâ–’ola en que fue embarcado cuando apenas tenâ”œآ،a 15 aâ”œâ–’os de edad. Se encuentra en la Cripta Imperial de la Casa de Habsburgo, en el convento de los Capuchinos de Viena. La talla recoge el despliegue de tropas austrâ”œآ،acas y borbâ”œâ”‚nicas al sureste de la ciudad a finales de agosto de 1710, en las inmediaciones del antiguo Barranco de la Muerte. Al fondo, a la derecha, en una vista idealizada, la muralla de la ciudad de Zaragoza, tras la que se representa una colecciâ”œâ”‚n de torres de ensueâ”œâ–’o onâ”œآ،rico: la intenciâ”œâ”‚n no era retratar la ciudad, siempre en segundo plano, sino destacar hazaâ”œâ–’as bâ”œآ®licas varias, a mayor gloria del pretendiente austrâ”œآ،aco. Para la realizaciâ”œâ”‚n de esta obra se tomâ”œâ”‚ como referencia la pintura "Batalla de Zaragoza", de autor incierto, hoy en el Kunsthistorisches Museum de Viena. Fuente visual: Bildarchiv Foto Marburg', 1710, 1710, 1710, 'Siglo XIX', 'TORRERO', 41.61662900, -0.88246800, '0101000020E61000006687F8872D3DECBFF261F6B2EDCE4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26019518720.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26019518720.webp', 'https://www.flickr.com/photos/zaragozaantigua/26019518720/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25953, 'Cementerio de Torrero 1895', 'Plano de la ampliaciâ”œâ”‚n del Cementerio de Torrero. Ricardo Magdalena, 1895. Fuente: AMZ.', 1895, 1895, 1895, 'Siglo XIX', 'TORRERO', 41.62277600, -0.88844200, '0101000020E61000001492CCEA1D6EECBFEA5DBC1FB7CF4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32127587996.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32127587996.webp', 'https://www.flickr.com/photos/zaragozaantigua/32127587996/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25954, 'Cementerio de Torrero 1896', 'Plano del Cementerio de Torrero. Ricardo Magdalena, Zaragoza, septiembre de 1896. Fuente: AMZ.', 1896, 1896, 1896, 'Siglo XIX', 'TORRERO', 41.62306500, -0.88827000, '0101000020E6100000CD920035B56CECBF20240B98C0CF4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32129129076.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32129129076.webp', 'https://www.flickr.com/photos/zaragozaantigua/32129129076/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25955, 'Torrero 1911', 'Imagen capturada durante la construcciâ”œâ”‚n de la sepultura de Joaquâ”œآ،n Costa en el cementerio catâ”œâ”‚lico de Torrero, en la ubicaciâ”œâ”‚n escogida por los tenientes de alcalde Marraco e Isâ”œأ­bal, y tras la preceptiva autorizaciâ”œâ”‚n del arzobispo Juan Soldevila y Romero. Despuâ”œآ®s de haber excavado la sepultura en profundidad, los operarios posan durante la fase de revestimiento interno con ladrillo y cemento. Tras ellos, la calle central del campo santo, con una vista parcial del notorio panteâ”œâ”‚n de los canâ”œâ”‚nigos del Cabildo, diseâ”œâ–’ado por Fernando de Yarza. Aunque inicialmente estaba previsto levantar aquâ”œآ، mismo un "magnâ”œآ،fico" mausoleo diseâ”œâ–’ado por el arquitecto municipal Fâ”œآ®lix Navarro Pâ”œآ®rez, su efectiva realizaciâ”œâ”‚n llevâ”œâ”‚ otros derroteros, y ubicaciâ”œâ”‚n. Fuente visual: reportaje fotogrâ”œأ­fico "Entierro de Joaquâ”œآ،n Costa en Zaragoza", de Aurelio Grasa, en Archivo Barboza-Grasa (www.aureliograsa.es/).', 1911, 1911, 1911, 'Anos 10', 'TORRERO', 41.62190900, -0.88814200, '0101000020E61000006E8786C5A86BECBF460BD0B69ACF4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34379245162.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34379245162.webp', 'https://www.flickr.com/photos/zaragozaantigua/34379245162/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24959, 'Velâ”œâ”‚dromo de Torrero 1934', '1934. Los terrenos del "Iberia Sport Club", junto a la calle Lasierra Purroy, muy cerca del Canal Imperial, las "graveras", y la Avenida de Amâ”œآ®rica, eran unas instalaciones deportivas de gran nivel que desde 1923 incluâ”œآ،an la â”œâ•‘nica piscina de Zaragoza, ademâ”œأ­s del recordado campo de fâ”œâ•‘tbol de Torrero. En 1928 se sumâ”œâ”‚ una nueva e importante instalaciâ”œâ”‚n: el Velâ”œâ”‚dromo de Torrero, a cuya inauguraciâ”œâ”‚n asistiâ”œâ”‚ el presidente de la "Uniâ”œâ”‚n Velocipâ”œآ®dica Espaâ”œâ–’ola", que asâ”œآ، se llamaba entonces la actual Federaciâ”œâ”‚n Espaâ”œâ–’ola de Ciclismo. En este velâ”œâ”‚dromo tuvieron lugar decenas de pruebas de todo tipo: por supuesto, de pista, pero tambiâ”œآ®n pruebas de carreteras que concluâ”œآ،an allâ”œآ،. Pero la creciente popularidad del balompiâ”œآ® zaragozano influyâ”œâ”‚ negativamente en el ciclismo, de forma que el velâ”œâ”‚dromo empezâ”œâ”‚ a ser utilizado como campo de entrenamiento del primer equipo de balompiâ”œآ® y, desde 1934, el equipo filial del Real Zaragoza (el "Atlâ”œآ®tico Zaragoza") llegâ”œâ”‚ a utilizar el velâ”œâ”‚dromo para jugar allâ”œآ، sus encuentros "de casa". El velâ”œâ”‚dromo, por la fuerza de los acontecimientos, abandonâ”œâ”‚ poco a poco la funciâ”œâ”‚n para la que fue ideado, optando el ciclismo federado por centrarse en el "excursionismo" (actual cicloturismo). La imagen, cortesâ”œآ،a de Sorolla padre, de "Velocâ”œآ،pedos Sorolla", captura un posado en las instalaciones del velâ”œâ”‚dromo de Torrero, cuando aâ”œâ•‘n era usado por los amantes de las dos ruedas de la ciudad. Al fondo, tras la pista y el perimâ”œآ®trico muro (con espectadores encaramados, a modo de tribunas), los â”œأ­rboles de la ribera del cercano Canal Imperial. En la actualidad, en los terrenos de este Velâ”œâ”‚dromo se levantan bloques de viviendas de las calles Lasierra Purroy, Dr. Pascual Oliver, y Honorio Garcâ”œآ،a Condoy.', 1934, 1934, 1934, 'Anos 30', 'TORRERO', 41.63153000, -0.88353000, '0101000020E6100000BD1DE1B4E045ECBFB0389CF9D5D04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14666914568.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14666914568.webp', 'https://www.flickr.com/photos/zaragozaantigua/14666914568/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25958, 'Câ”œأ­rcel de Torrero 1996', 'El 31 de mayo de 1996 se convocâ”œâ”‚ una manifestaciâ”œâ”‚n a favor de la recuperaciâ”œâ”‚n de los derechos civiles de los insumisos, mientras el grupo preso en la câ”œأ­rcel de Torrero realizaba una أ”أ‡آ£huelga de frâ”œآ،oأ”أ‡أک. En la imagen, insumisos encarcelados, en el patio de la prisiâ”œâ”‚n, pertrechados con mantas. Las movilizaciones y acciones protestaban por la no eliminaciâ”œâ”‚n de las penas de câ”œأ­rcel por insumisiâ”œâ”‚n en el nuevo Câ”œâ”‚digo Penal durante la etapa de ministro de Justicia e Interior de Juan Alberto Belloch.', 1996, 1996, 1996, 'Anos 90', 'TORRERO', 41.62729400, -0.88683400, '0101000020E61000003D635FB2F160ECBF0F7D772B4BD04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50368671706.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50368671706.webp', 'https://www.flickr.com/photos/zaragozaantigua/50368671706/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25959, 'Plaza de las Canteras 1990', 'Imagen de la plaza de las Canteras realizada desde la inmediata calle de Fray Juliâ”œأ­n Garcâ”œآ®s antes de la reforma de este espacio que aumentâ”œâ”‚ la superficie peatonal, la limitaciâ”œâ”‚n circulatoria a un solo sentido, y la supresiâ”œâ”‚n de la zona de aparcamiento. La reforma incluyâ”œâ”‚, ademâ”œأ­s, un conjunto monumental en memoria del maestro Manuel de Villanueva para dignificar la plaza, que fue ampliado con una escultura en piedra negra de Calatorao que rinde homenaje a la profesiâ”œâ”‚n del cantero, pues la denominaciâ”œâ”‚n de la plaza hacâ”œآ،a referencia precisamente a las canteras que abastecâ”œآ،an a una cercana fâ”œأ­brica de yeso. A la derecha, desaparecido inmueble en el acceso a la calle de Câ”œâ”‚rdoba, donde la antigua barriada de la Esperanza. Al fondo y tras los â”œأ­rboles de la plaza, la avenida de Amâ”œآ®rica. A la izquierda, inicio de la calle de Alicante.', 1990, 1990, 1990, 'Anos 90', 'TORRERO', 41.63160200, -0.88610500, '0101000020E61000007B4E7ADFF85AECBF4A0B9755D8D04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50371262277.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50371262277.webp', 'https://www.flickr.com/photos/zaragozaantigua/50371262277/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25960, 'Pinares de Venecia c.1996', 'Imagen de una de las numerosas movilizaciones vecinales convocadas por la Coordinadora Venecia-Torrero-La Paz contra el Tercer Cinturâ”œâ”‚n consistente en el colorido pintado de algunos de los pinos que habrâ”œآ،a que talar en terrenos de los Pinares de Venecia por donde estaba proyectado que pasase el trazado del Tercer Cinturâ”œâ”‚n de ronda. Aunque este tramo del pinar fue denominado "bosque encantado" en referencia del bosque de Oma creado por Agustâ”œآ،n Ibarrola, no hubo magia que detuviera a las excavadoras de la obra.', 1996, 1996, 1996, 'Anos 90', 'TORRERO', 41.62543500, -0.89527800, '0101000020E610000056815A0C1EA6ECBF0B630B410ED04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50516287196.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50516287196.webp', 'https://www.flickr.com/photos/zaragozaantigua/50516287196/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25961, 'Cementerio de Torrero 1980', 'Tras el 18 de julio de 1936 mâ”œأ­s 600 varones desafectos con el golpe militar y originarios de pueblos de Aragâ”œâ”‚n, Navarra, La Rioja y Soria ribereâ”œâ–’os del râ”œآ،o Ebro se alistaron en el legionario Tercio General Sanjurjo como forma de tratar de escapar a una mâ”œأ­s que probable muerte. Sin embargo, las autoridades militares nacionalistas, ante el riesgo de una posible deserciâ”œâ”‚n masiva decidieron aplicar un castigo ejemplarizante y preventivo: fueron conducidos al campo de maniobras de San Gregorio y, en los primeros dâ”œآ،as del mes de octubre un nâ”œâ•‘mero todavâ”œآ،a sin determinar de ellos fueron asesinados. Sus cuerpos fueron luego trasladados en camiones al cementerio de Torrero, enterrados en una gran fosa comâ”œâ•‘n y sin dejar constancia de ello en los libros de inhumaciones. Cuarenta y tres aâ”œâ–’os despuâ”œآ®s, descendientes navarros y riojanos solicitaron al Ayuntamiento tardofranquista de Zaragoza que se exhumaran sus cuerpos para devolverlos a sus pueblos natales. Se les dio permiso, aunque por sus propios medios y bajo su responsabilidad, y comenzaron la tarea en la manzana 4 del cementerio de Torrero, en una de las conocidas como "zanjas de fusilados". Durante los trabajos, saliâ”œâ”‚ a la luz una zona de zanjas con cerca de 3.000 cadâ”œأ­veres, apilados con y sin caja. Tras las elecciones municipales celebradas pocos meses despuâ”œآ®s, el nuevo Ayuntamiento democrâ”œأ­tico iniciâ”œâ”‚ el estudio de este asunto. En la imagen, familiares de los navarros y riojanos asesinados en esta fosa comâ”œâ•‘n, durante un homenaje fotografiado y publicado en la revista "Interviâ”œâ•‘", en tiempos en que la memoria democrâ”œأ­tica era un asunto privado y con muy poco apoyo institucional y mediâ”œأ­tico.', 1980, 1980, 1980, 'Anos 80', 'TORRERO', 41.62242800, -0.88179200, '0101000020E610000059FB3BDBA337ECBFAE0E80B8ABCF4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52246629046.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52246629046.webp', 'https://www.flickr.com/photos/zaragozaantigua/52246629046/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25962, 'Cementerio 1911', 'Imagen capturada en el cementerio catâ”œâ”‚lico de Torrero el dâ”œآ،a en que se trasladaron allâ”œآ، los restos mortales de Joaquâ”œآ،n Costa. Muchas personas que formaban parte de la multitudinaria comitiva que participâ”œâ”‚ en este evento, aprovecharon esa circunstancia para hacer de ese dâ”œآ،a un remedo de la festividad de Todos los Santos, cuando la ciudad de los vivos se vuelca en la ciudad de los muertos. Ese dâ”œآ،a estaba marcado en el calendario como una jornada centrada en el recuerdo a los fallecidos, comenzando con la ceremonia religiosa en la parroquia de referencia, para luego encaminarse (algunos lo hacâ”œآ،an literalmente asâ”œآ،) a pasar el dâ”œآ،a en el cementerio, desde el punto de la maâ”œâ–’ana y hasta la hora de cierre. Allâ”œآ، se procedâ”œآ،a a limpiar la tumba, se la adornaba con flores, coronas y luminarias, y se realizaban las preceptivas oraciones y sufragios en recuerdo de los fallecidos. Al anochecer, la gente regresaba a Zaragoza y algunos terminaban la jornada asistiendo a la representaciâ”œâ”‚n de "Don Juan Tenorio", ese drama religioso-fantâ”œأ­stico tambiâ”œآ®n asociado a la fecha del 1 de noviembre.', 1911, 1911, 1911, 'Anos 10', 'TORRERO', 41.62185800, -0.88733900, '0101000020E610000019E42EC21465ECBFC460FE0A99CF4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/53459502006.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/53459502006.webp', 'https://www.flickr.com/photos/zaragozaantigua/53459502006/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (26059, 'Lasierra Purroy c.1927', 'Aâ”œآ®rea visual centrada en el entorno del reciente campo de fâ”œâ•‘tbol de la Sociedad Iberia F.C, sito en la calle de Lasierra Purroy, y complementado con una reglamentaria piscina descubierta, y un velâ”œâ”‚dromo. A la izquierda, parcelas de las antiguas calles de Navarro (luego Doctor Ibâ”œأ­â”œâ–’ez), Vega (luego Juan Cabrero), y J. Marcos (luego, Antonio Adrados), que arrancan en la avenida de Amâ”œآ®rica. A la derecha, eriales y eras varias, en descenso hasta la ribera del Canal Imperial, significativamente reseâ”œâ–’ada por una lineal foresta de plâ”œأ­tanos de sombra y acacias. Fuente visual: "Zaragoza 1908-2008. Arquitectura y Urbanismo".', 1927, 1927, 1927, 'Anos 20', 'TORRERO', 41.62984600, -0.88316500, '0101000020E61000005019FF3EE342ECBF1AC231CB9ED04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33782629286.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33782629286.webp', 'https://www.flickr.com/photos/zaragozaantigua/33782629286/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21757, 'Casa Bergua 1933', 'Imagen de la racionalista y excepcional "casa particular" de Matâ”œآ،as Bergua Olivâ”œأ­n, obra del arquitecto Rafael Bergamâ”œآ،n, en la achaflanada esquina entre el paseo de Ruiseâ”œâ–’ores y el paseo del Canal. La vista ha sido capturada desde el paseo del Canal. Al fondo, a la izquierda, la fâ”œأ­brica de harinas "La Imperial de Aragâ”œâ”‚n". Fuente visual: "Arquitectura" (Madrid).', 1933, 1933, 1933, 'Anos 30', 'TORRERO', 41.63423200, -0.89016700, '0101000020E6100000514F1F813F7CECBFD009A1832ED14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22616016916.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22616016916.webp', 'https://www.flickr.com/photos/zaragozaantigua/22616016916/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23121, 'Embarcadero del Canal 2006', 'Foto: Marâ”œآ،a Torres-Solanot. Fin de la construcciâ”œâ”‚n de un embarcadero en el Canal Imperial de Aragâ”œâ”‚n, junto a la calle â”œأ¼frica, en junio de 2006. Fue una iniciativa de la Asociaciâ”œâ”‚n de Vecinos de Torrero. En el solar donde estâ”œأ­n almacenados los materiales de construcciâ”œâ”‚n, se inaugurâ”œâ”‚ en mayo de 2011 un pequeâ”œâ–’o edificio diseâ”œâ–’ado por Alejandro San Felipe, que alberga la terraza-bar El corazâ”œâ”‚n verde. Fuente: Heraldo de Aragâ”œâ”‚n.', 2006, 2006, 2006, 'Siglo XXI', 'TORRERO', 41.63111000, -0.89163200, '0101000020E6100000742502D53F88ECBFDB166536C8D04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31122424394.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31122424394.webp', 'https://www.flickr.com/photos/zaragozaantigua/31122424394/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25002, 'Residencia Estudiantes 1926', 'La innovadora Residencia de Estudiantes de la Universidad de Zaragoza, con proyecto del arquitecto Teodoro Râ”œآ،os, comenzâ”œâ”‚ a funcionar en el curso 1924-25, aunque su inauguraciâ”œâ”‚n oficial fue retrasada hasta febrero de 1925, para incluirla en los actos del "Dâ”œآ،a de la Universidad" y hacerlo coincidir con la presencia real de Alfonso XIII. Asâ”œآ، se hacâ”œآ،an las cosas durante la dictadura de Primo de Rivera. Poco despuâ”œآ®s se le dio el acadâ”œآ®mico nombre de "Colegio Mayor del Fundador Don Pedro Cerbuna", con Miguel Alluâ”œآ® como su primer director (hasta 1927). Esta Residencia fue construida en el Paseo de Ruiseâ”œâ–’ores nâ”¬â•‘ 23, justo donde la bifurcaciâ”œâ”‚n con el Camino Viejo de Cuarte. Su edificio principal era de planta rectangular en tres alturas, junto al Jardâ”œآ،n Botâ”œأ­nico. Entre sus instalaciones habâ”œآ،a frontâ”œâ”‚n para juego de pelota, piscina, pista de "tennis", campo de "Foot-ball"... Fue clausurado en 1936, y ya no se recuperâ”œâ”‚. En los aâ”œâ–’os 60 fue derribado y sobre su solar se construirâ”œأ­ el nuevo Instituto Femenino Miguel Servet, con proyecto de Regino Borobio, que serâ”œأ­ inaugurado en 1965. En la imagen, aspecto de la "fachada del mediodâ”œآ،a", destacando el poderoso torreâ”œâ”‚n que permitâ”œآ،a unas vistas muy apreciables. El paseo de Ruiseâ”œâ–’ores queda a la izquierda, donde estaba la entrada. El Jardâ”œآ،n Botâ”œأ­nico queda detrâ”œأ­s del edificio. Fuente visual: Revista "Aragâ”œâ”‚n", nâ”¬â•‘ 4.', 1926, 1926, 1926, 'Anos 20', 'TORRERO', 41.63538700, -0.88994600, '0101000020E6100000AF97A608707AECBFDBA6785C54D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20541642466.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20541642466.webp', 'https://www.flickr.com/photos/zaragozaantigua/20541642466/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25006, 'P.â”¬â•‘ de los Ruiseâ”œâ–’ores 1931', 'Vista parcial del edificio de la Residencia de Estudiantes de la Universidad de Zaragoza, oficialmente denominada "Colegio Mayor de Cerbuna", en una imagen capturada desde su ingreso en el nâ”œâ•‘mero 23 del paseo de los Ruiseâ”œâ–’ores, donde estaba radicada.', 1931, 1931, 1931, 'Anos 30', 'TORRERO', 41.63532000, -0.88995600, '0101000020E610000092205C01857AECBF533F6F2A52D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/25788523007.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/25788523007.webp', 'https://www.flickr.com/photos/zaragozaantigua/25788523007/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25939, 'Plano topogrâ”œأ­fico del monte de Torrero ca. 1865', 'Plano topogrâ”œأ­fico del monte de Torrero de Zaragoza. Antonio Berbegal, ca. 1865. Archivo Municipal de Zaragoza. Representaciâ”œâ”‚n grâ”œأ­fica del monte de Torrero de Zaragoza, con indicaciâ”œâ”‚n detallada de sus hitos, como el cementerio (marcado con una calavera), el barranco de la Muerte, el Canal Imperial al sur, junto al cuartel "Artillero", y fuera del monte, mâ”œأ­s abajo, la indicaciâ”œâ”‚n de la situaciâ”œâ”‚n de las torres Nueva y de la Seo.', 1865, 1865, 1865, 'Siglo XIX', 'TORRERO', 41.63268200, -0.88987200, '0101000020E61000001C0934D8D479ECBF4A6249B9FBD04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15468508227.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15468508227.webp', 'https://www.flickr.com/photos/zaragozaantigua/15468508227/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23079, 'Azud del Ebro 2007', 'El azud "Manuel Lorenzo Pardo" (fundador de la CHE) es denominado tambiâ”œآ®n como "Azud del Ebro", si bien su utilidad social es la de "Pasarela peatonal". Fue ideado y construido con motivo de la ExpoZaragoza 2008, y tenâ”œآ،a como primer objetivo garantizar una pelâ”œآ،cula estable de agua para la navegaciâ”œâ”‚n de ocio entre Vadorrey y el meandro de Ranillas. Incluâ”œآ،a, como segunda funciâ”œâ”‚n, una pasarela peatonal entre Vadorrey y Las Fuentes. La navegabilidad del Ebro asociada a este proyecto ha hecho aguas, como no podâ”œآ،a ser de otra forma. La secundaria pasarela peatonal es desde hace tiempo su mâ”œأ­s destacada funciâ”œâ”‚n social, como no podâ”œآ،a ser de otra forma. En la imagen, los enormes pilares hormigonados donde encajar luego las siete compuertas abatibles de 23,85 metros de largo c/u. Al fondo, los bloques ribereâ”œâ–’os de Vadorrey-Nobleza Baturra. Foto: Ana Muller. Fuente: "Razâ”œâ”‚n y sed", Colegio de Ingenieros de Caminos, Canales y Puertos, 2008.', 2007, 2007, 2007, 'Siglo XXI', 'LAS FUENTES', 41.65193500, -0.85745900, '0101000020E6100000CC2555DB4D70EBBF130F289B72D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/16626138720.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/16626138720.webp', 'https://www.flickr.com/photos/zaragozaantigua/16626138720/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22338, 'Piscina SD Arenas 1969', 'En la piscina de la Sociedad Deportiva Arenas (en la denominada Ciudad Deportiva â”¬آ½Martâ”œآ،n-Celimâ”œآ®ndizâ”¬â•—, inaugurada un par de aâ”œâ–’os antes), allâ”œأ­ por el lejano sureste de la ciudad (Barrio de San Josâ”œآ®), en julio de 1969 tuvo lugar una competiciâ”œâ”‚n de nado entre las selecciones "B" de Espaâ”œâ–’a e Italia. Acudiâ”œâ”‚ mucho pâ”œâ•‘blico y autoridades, entre las que se encontraba el Câ”œâ”‚nsul de la Repâ”œâ•‘blica de Italia, Sr. Carlos Baratto. Ganâ”œâ”‚ el seleccionado espaâ”œâ–’ol por el câ”œâ”‚mputo global de 61 a 40. Esta piscina era de las poquitas que en toda la ciudad, en aquellos aâ”œâ–’os, podâ”œآ،an albergar una competiciâ”œâ”‚n de esta categorâ”œآ،a. Este evento se desarrollâ”œâ”‚ a pocos metros del Cabezo Cortado, el Canal Imperial, y las graveras de La Paz. La imagen presenta una panorâ”œأ­mica de las humildes viviendas del entorno a la piscina, en lo que fuera la antigua "Barriada de Argentina", en las actuales calles Argentina, Hermanos Machado, Melilla, Juan XXII... La "Piscina del Arenas" estâ”œأ­ cerrada desde hace bastantes aâ”œâ–’os, a la espera de que alguno de los sucesivos propietarios del suelo arranque a urbanizar una zona anclada en el tiempo que, mientras tanto, ejerce de especulativo barbecho expectante. Eso que se intuye al fondo a la derecha, efectivamente, es el Pilar. Fuente visual: AMZ, Gerardo Sancho Ramo.', 1969, 1969, 1969, 'Anos 60', 'TORRERO', 41.63155400, -0.87287600, '0101000020E610000052D32EA699EEEBBF39D4EFC2D6D04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20047465630.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20047465630.webp', 'https://www.flickr.com/photos/zaragozaantigua/20047465630/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22498, 'Cabezo Cortado c.1963', 'Imagen capturada desde la natural altura del Cabezo Cortado caracterâ”œآ،stica con sus bien pobrecicos pinos, porque la cascajera que lo conforma no da para mâ”œأ­s, con una extraordinaria vista panorâ”œأ­mica de la ciudad desde esta atalaya sita en el sureste e inmediata al Canal Imperial de Aragâ”œâ”‚n. En primer tâ”œآ®rmino, algunos feraces campos de herbâ”œأ­ceas donde pocos aâ”œâ–’os despuâ”œآ®s se ubicarâ”œآ،a la Ciudad Deportiva Martâ”œآ،n-Celimâ”œآ®ndiz, muy popular por la exclusiva y monumental piscina de la SD Arenas, durante unos aâ”œâ–’os la â”œâ•‘nica de gran categorâ”œآ،a en toda la ciudad. Justo detrâ”œأ­s, inmuebles de la antigua barriada de Argentina, vertebrada por las calle de Argentina, Hermanos Machado, Melilla y Juan XXII. Tras ella, diversos entornos del barrio de San Josâ”œآ®, desde la izquierda, donde destaca la fâ”œأ­brica de La Zaragozana, hasta la trinchera del ferrocarril a la derecha, flanqueada por el Grupo de Viviendas Puente Virrey-Rosellâ”œâ”‚n; las parcelicas de las calles de Mario, Nobleza y Alegrâ”œآ،a, junto a al calle de la Cadena de la Granja; el triangular Grupo de Viviendas Agustâ”œآ،n Gericâ”œâ”‚ en la calle de Josâ”œآ® Galiay; y la antigua Granja Agrâ”œآ،cola de Zaragoza. El telâ”œâ”‚n de fondo lo jalonan algunas de las torre y câ”œâ•‘pulas de la antigua ciudad, en este caso ya acompaâ”œâ–’adas de las dos nuevas torres ribereâ”œâ–’as del templo del Pilar, y con la progresiva incorporaciâ”œâ”‚n de los grandes bloques de viviendas que desde finales de la dâ”œآ®cada de los grises aâ”œâ–’os 50 van surgiendo por doquiera les pareciera a sus emprendedores promotores. Al fondo y a la derecha emerge la tambiâ”œآ®n natural atalaya natural del Cascajo. Desde el Gran Archivo Zaragoza antigua hemos volteado horizontalmente la original imagen para que recobrara el sentido de la orientaciâ”œâ”‚n perdida.', 1963, 1963, 1963, 'Anos 60', 'TORRERO', 41.63080000, -0.87297300, '0101000020E6100000F04FA91265EFEBBF8D28ED0DBED04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49029831276.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49029831276.webp', 'https://www.flickr.com/photos/zaragozaantigua/49029831276/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23142, 'Cabezo Cortado 2009', 'De toda la vida, el Cabezo Cortado ha sido uno de los miradores privilegiados desde cuya altura mejor se contemplaba el esplâ”œآ®ndido panorama de Zaragoza. En 1901 asâ”œآ، lo ratificaron los prâ”œآ،ncipes de Asturias, que en su visita a la ciudad no dejaron de peregrinar a este lugar. Mâ”œأ­s tarde, el Desarrollismo de la segunda mitad del siglo XX dejâ”œâ”‚ al lugar progresivamente bastante maltrecho. En el arranque del siglo XXI (2006), las denuncias de "abandono" seâ”œâ–’alaron la responsabilidad municipal, que respondiâ”œâ”‚ aclarando que el Cabezo no sâ”œâ”‚lo no se encontraba en abandono, sino que tenâ”œآ،a en marcha un proceso administrativo para su mejora y completa remodelaciâ”œâ”‚n, como parte de un â”œأ­rea de desarrollo urbano de iniciativa privada que ya tenâ”œآ،a proyecto, en fase de tramitaciâ”œâ”‚n muy avanzada. La extraordinaria ola de la Expo 2008 pasâ”œâ”‚, y el Cabezo permaneciâ”œâ”‚ estable, junto al â”œâ•‘nico tramo del Canal Imperial a su paso por Zaragoza que no conoce, apenas, intervenciones de dignificaciâ”œâ”‚n. La imagen se corresponde con un proyecto de 2009 para la urbanizaciâ”œâ”‚n del sector F-38/1, o zona del Cabezo Cortado segâ”œâ•‘n el vigente PGOU, representada en color verde claro, porque habrâ”œآ،a de ser de "câ”œآ®sped". En verde oscuro, la zona de pronunciados taludes, arbolada. Al norte, el desarrollo urbanâ”œآ،stico previsto hasta el camino de Miraflores. Al este, el alabeado enlace con el Tercer Cinturâ”œâ”‚n. Al sur, el cauce del Canal Imperial. Mientras tanto, hemos llegado al aâ”œâ–’o 2017.', 2009, 2009, 2009, 'Siglo XXI', 'TORRERO', 41.63047200, -0.87235000, '0101000020E6100000984C158C4AEAEBBF9885764EB3D04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31842078500.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31842078500.webp', 'https://www.flickr.com/photos/zaragozaantigua/31842078500/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23224, 'Cabezo Cortado 2017', 'Propuesta de intervenciâ”œâ”‚n urbana en el sector F-38-1 del barrio de San Josâ”œآ® centrado en la realizaciâ”œâ”‚n, en primer tâ”œآ®rmino, de un parque en el Cabezo Cortado y su conexiâ”œâ”‚n con el Jardâ”œآ،n o Parque de la Memoria mediante un "Eje Verde" a travâ”œآ®s de la prolongaciâ”œâ”‚n de la calle de Melilla y el camino de Miraflores. Se incluyen varios bloques de viviendas para completar manzanas incompletas, ademâ”œأ­s de algunas infraestructuras de barrio como una biblioteca o un centro de dâ”œآ،a. Esta propuesta estaba incluida en el Mâ”œأ­ster Universitario en Arquitectura de la Universidad de Zaragoza realizado en el curso 2016-17, y publicado por la colaboraciâ”œâ”‚n entre la municipal Sociedad Municipal Zaragoza Vivienda y la Escuela de Ingenierâ”œآ،a y Arquitectura de la Universidad de Zaragoza. Como otras varias propuestas centradas en la revitalizaciâ”œâ”‚n del entorno del Cabezo Cortado desde que las obras de acompaâ”œâ–’amiento de la Expo 2008 pasaran de largo por aquâ”œآ،, estas musas nunca llegaron al teatro.', 2017, 2017, 2017, 'Siglo XXI', 'TORRERO', 41.63098500, -0.87303700, '0101000020E61000009F55664AEBEFEBBF1FA2D11DC4D04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51359634607.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51359634607.webp', 'https://www.flickr.com/photos/zaragozaantigua/51359634607/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23353, 'Acueducto Barranco de la Muerte 2001', 'Foto Heraldo de Aragâ”œâ”‚n/Guillermo Mestre, 2001. Barranco de la Muerte de Zaragoza. Ronda de la Hispanidad o Tercer Cinturâ”œâ”‚n, inaugurado en 2003. Construcciâ”œâ”‚n del acueducto de Javier Manterola del Canal Imperial de Aragâ”œâ”‚n -finalizado en 2002- con la idea de desviar la vâ”œآ،a acuâ”œأ­tica unos metros para derribar el levantado por Ramâ”œâ”‚n Pignatelli en 1790. Al final no se derribâ”œâ”‚ el anterior, practicâ”œأ­ndole unos ojos por los que discurren los seis carriles carreteros. Lo cual da como resultado dos acueductos para un solo canal: el antiguo, desecado; y el nuevo, con agua.', 2001, 2001, 2001, 'Siglo XXI', 'TORRERO', 41.62310800, -0.87288200, '0101000020E6100000DB8B683BA6EEEBBF20F0C000C2CF4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14940093608.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14940093608.webp', 'https://www.flickr.com/photos/zaragozaantigua/14940093608/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23354, 'Acueducto Barranco de la Muerte 1833', '"Obras del Barranco de la Muerte". En 1790 se levantâ”œâ”‚ el acueducto para que el Canal Imperial de Aragâ”œâ”‚n de Ramâ”œâ”‚n Pignatelli salvase el Barranco de la Muerte de los montes de Torrero de Zaragoza. Fuente visual: "Memoria histâ”œâ”‚rica del Canal imperial de Aragon: noticia sobre las utilidades que produce, y esplicacion de lo que contienen las lâ”œأ­minas que se publican", Madrid, 1833.', 1833, 1833, 1833, 'Siglo XIX', 'TORRERO', 41.62362300, -0.87158300, '0101000020E610000076FC170802E4EBBF4704E3E0D2CF4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14941492129.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14941492129.webp', 'https://www.flickr.com/photos/zaragozaantigua/14941492129/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23358, 'Acueducto del Barranco de la Muerte 2002', 'Foto Ayuntamiento de Zaragoza. Fase final de las obras de acondicionamiento del Acueducto de Pignatelli (Canal Imperial) sobre el Barranco de la Muerte de Zaragoza, abriâ”œآ®ndole dos grandes ojos para el paso de los vehâ”œآ،culos por el Tercer Cinturâ”œâ”‚n de ronda. Despuâ”œآ®s hubo que reforzarle los cimientos porque peligraba la estructura.', 2002, 2002, 2002, 'Siglo XXI', 'TORRERO', 41.62367400, -0.87170400, '0101000020E6100000365B79C9FFE4EBBFC9AEB48CD4CF4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15114442256.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15114442256.webp', 'https://www.flickr.com/photos/zaragozaantigua/15114442256/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23388, 'Embarcadero La Paz 2008', 'Construcciâ”œâ”‚n del embarcadero del Canal Imperial de Aragâ”œâ”‚n en el barrio de La Paz, cerca del campo de fâ”œâ•‘tbol Josâ”œآ® Luis Violeta (al fondo). La obra se enmarcaba en un plan abortado para volver a hacer navegable el Canal en Zaragoza, con cuatro embarcaderos: â”œآ®ste, el de la calle â”œأ¼frica, el de Valdefierro y el de los depâ”œâ”‚sitos de Casablanca, esclusa incluida. Todo ello en el marco del plan de riberas de la Expo 2008. Fuente: Heraldo de Aragâ”œâ”‚n.', 2008, 2008, 2008, 'Siglo XXI', 'TORRERO', 41.62678700, -0.87177300, '0101000020E61000005725917D90E5EBBF6B47718E3AD04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31899460223.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31899460223.webp', 'https://www.flickr.com/photos/zaragozaantigua/31899460223/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23398, 'Vista aâ”œآ®rea 2001', 'Vista aâ”œآ®rea del sureste de Zaragoza donde se resalta el sinuoso terroso trazado del previsto Tercer Cinturâ”œâ”‚n de Ronda ya en obras que a la izquierda y desde el fondo asciende por los Pinares de Venecia hasta el entorno del cementerio de Torrero, desciende luego hasta el cruce con el Canal Imperial de Aragâ”œâ”‚n, donde se estâ”œأ­ procediendo en primer tâ”œآ®rmino a construir un nuevo puente-acueducto del barranco de la Muerte, de trazado mâ”œأ­s rectilâ”œآ،neo que el ilustrado. Esta zona se muestra con un aspecto radicalmente modificado despuâ”œآ®s cuando el desarrollo de Parque Venecia. Finalmente, el trazado del cinturâ”œâ”‚n prosigue separando la frondosa antigua Quinta Julieta del erial donde estuvo el desmantelado gueto de ese mismo nombre, hasta el cruce sobre las vâ”œآ،as del ferrocarril, todavâ”œآ،a pendiente veinte aâ”œâ–’os despuâ”œآ®s de un enlace digno con el barrio de San Josâ”œآ® que no sea el inadecuado camino de Miraflores.', 2001, 2001, 2001, 'Siglo XXI', 'TORRERO', 41.62455300, -0.87216800, '0101000020E61000006EC493DDCCE8EBBF31CF4A5AF1CF4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51495497238.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51495497238.webp', 'https://www.flickr.com/photos/zaragozaantigua/51495497238/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24565, 'Vista de Zaragoza 1908', '1908. "Vista de Zaragoza", â”œâ”‚leo de Juan Josâ”œآ® Gâ”œأ­rate pintado al albur de la Exposiciâ”œâ”‚n Hispano Francesa impulsada, a la par, por la vieja aristocracia financiera y la nueva burguesâ”œآ،a industrial local. Esta "vista" topogrâ”œأ­fica de la ciudad, el pintor la sitâ”œâ•‘a con el caballete montado en la altura del Cabezo Cortado, natural atalaya urbana desde hace milenios. La descripciâ”œâ”‚n canâ”œâ”‚nica de la pintura destaca fundamentalmente la presencia, juntos, pero no revueltos, de tipos populares y baturros joteros al lado de una notable galerâ”œآ،a de prohombres locales y regionales (entre otros, Mariano de Cavia, Basilio Paraâ”œآ،so, Segismundo Moret, Santiago Ramâ”œâ”‚n y Cajal, Francisco Pradilla, y el propio autor, en notable e irrepetible galerâ”œآ،a de prâ”œâ”‚ceres). Una lupa urbana nos aporta algunos elementos caracterâ”œآ،sticos de lo que desde el Cabezo Cortado podâ”œآ،a entonces verse: a la derecha, la mole imponente del edificio de la Granja Agrâ”œآ،cola Experimental, rodeada de sus extensos y experimentales campos de cultivo. Un poco antes, la reciente lâ”œآ،nea de los ferrocarriles directos a Barcelona, con el novâ”œآ،simo apeadero de Miraflores. El espacio aâ”œâ•‘n verde de la huerta de Miraflores, delimitado por la trinchera del ferrocarril, el Camino de las Torres, el Camino de S. Josâ”œآ®. Unos alrededores de aspecto agrâ”œآ،cola, hortelano, perifâ”œآ®rico, tranquilo, silencioso, despejado y anâ”œâ”‚nimo. Tan cerca y tan lejos de la ciudad que, al fondo, reluce al atardecer con su linea del cielo de torres, câ”œâ•‘pulas, y la sombra de alguna chimenea.', 1908, 1908, 1908, 'Anos 1900', 'TORRERO', 41.63039900, -0.87214100, '0101000020E61000000806103E94E8EBBF2E3718EAB0D04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14875626383.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14875626383.webp', 'https://www.flickr.com/photos/zaragozaantigua/14875626383/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24574, 'Cabezo Cortado 1915', 'Imagen panorâ”œأ­mica capturada, hacia 1915, desde el mirador natural del Cabezo Cortado. A la izquierda, inmediatas, las obras de construcciâ”œâ”‚n del "Sanatorio de Nâ”¬آ¬ Sâ”¬آ¬ del Pilar" para niâ”œâ–’os tuberculosos. Un poco mâ”œأ­s abajo, en descenso, las primeras construcciones del "Barrio de la Argentina", y parcelas del "Barrio de Cuber". Los pabellones principales de la Granja quedan a la derecha, entre campos de cultivo y moreras. Al fondo, entre tinieblas, emergen algunas torres de la lejana ciudad. Fuente visual: AVV. San Josâ”œآ®.', 1915, 1915, 1915, 'Anos 10', 'TORRERO', 41.63047200, -0.87235000, '0101000020E6100000984C158C4AEAEBBF9885764EB3D04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20396578695.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20396578695.webp', 'https://www.flickr.com/photos/zaragozaantigua/20396578695/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24575, 'Cabezo Cortado 1927', '"Panorâ”œأ­mica de la ciudad de Zaragoza" capturada desde las alturas del Cabezo Cortado. A la izquierda, construcciones del "Barrio de la Argentina" y del "Barrio de Cuber". En el centro, aterrazados y herbâ”œأ­ceos campos de cultivo de La Granja, y ordenados camino de moreras en las inmediaciones de sus pabellones principales, que quedan a la derecha, fuera de plano. El arbolado Camino del Puente del Virrey, atravesado por la trinchera del ferrocarril a Barcelona. Al fondo, algunas de las torres y câ”œâ•‘pulas de la lejana ciudad. Fuente visual: AHPZ, Archivo Gabriel Faci', 1927, 1927, 1927, 'Anos 20', 'TORRERO', 41.63047200, -0.87235000, '0101000020E6100000984C158C4AEAEBBF9885764EB3D04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21553628792.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21553628792.webp', 'https://www.flickr.com/photos/zaragozaantigua/21553628792/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25719, 'Vista desde el Cabezo Cortado 1969', 'Imagen del progresivo estiramiento vertical de las construcciones de la ciudad o, lo que es lo mismo, de la creciente dificultad en encontrar esas panorâ”œأ­micas urbanas tan diâ”œأ­fanas de apenas unas pocas dâ”œآ®cada antes. La visual desde el Cabezo Cortado sigue siendo espectacular, pero a los tâ”œâ”‚tems "de toda la vida", ergo las torres del Pilar (como mucho, dos de ellas) y de la Seo, les van saliendo competidores por doquiera se mire. Y aâ”œâ•‘n faltan por llegar las construcciones de los 70, de los 80... En primer plano, campos de cultivo que fueron de la Granja Agrâ”œآ،cola, y a su izquierda, los bloques de viviendas de la calle Rosellâ”œâ”‚n. Delante, la trinchera del ferrocarril, y el puentecillo peatonal hacia Luis Aula y Josâ”œآ® Galiay. Las parcelitas de las calle Nobleza, Alegrâ”œآ،a, Emilio-Mario... y las naves industriales de Escultor Moreto y la calle Cadena de la Granja. Las traseras de los bloques de la calle Raquel Meller... La mole del Depâ”œâ”‚sito del Gas, es visible desde casi cualquier parte. Fuente: "Zaragoza viva" (1969)', 1969, 1969, 1969, 'Anos 60', 'TORRERO', 41.63047200, -0.87235000, '0101000020E6100000984C158C4AEAEBBF9885764EB3D04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15239283934.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15239283934.webp', 'https://www.flickr.com/photos/zaragozaantigua/15239283934/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25723, 'Cabezo Cortado c.1877', '"Zaragoza: Vista general tomada desde el Cabezo Cortado". Jean Laurent. Una extraordinaria vista panorâ”œأ­mica, que tal vez merece ser catalogada de "monumento visual" de la ciudad, con las torres y câ”œâ•‘pulas al fondo, por supuesto, perfectamente reconocibles, pero con todo un paisaje y un verdor ubâ”œآ®rrimo que desde la atalaya natural del Cabezo Cortado, y en el momento de capturar esta imagen, alcanzaba hasta la desembocadura del Huerva, y mâ”œأ­s allâ”œأ­. Asâ”œآ، lucâ”œآ،a la periferia del sureste de la ciudad. De izquierda a derecha, una insâ”œâ”‚lita visual del camino del Puente del Virrey, ya con una instalaciâ”œâ”‚n fabril en su parte superior, donde la torre de Cuber, y el alabeado cauce en descenso de la nueva acequia del Plano. Ya en 1892 alguna torre desaparecerâ”œآ،a del horizonte, derribada, y otras construcciones mâ”œأ­s modernas comenzarâ”œآ،an a proliferar. En la segunda mitad del pasado siglo XX, el aquâ”œآ، dominante tono verde fue dejando paso, de forma fulminante, a la urbanizaciâ”œâ”‚n mâ”œأ­s desbocada, que ha modificado de forma radical lo que desde aquâ”œآ، se puede ver hoy. Con todo, mucho tiempo despuâ”œآ®s, el Cabezo Cortado sigue siendo un interesante mirador natural, aunque muy venido a menos por la degradaciâ”œâ”‚n, el abandono, y la poca voluntad municipal a la hora de dignificarlo. Su compaâ”œâ–’ero de Buenavista ha tenido mâ”œأ­s fortuna. Fuente visual: www.mcu.es/ (Archivo Ruiz Vernacci)', 1877, 1877, 1877, 'Siglo XIX', 'TORRERO', 41.63047200, -0.87235000, '0101000020E6100000984C158C4AEAEBBF9885764EB3D04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20041953410.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20041953410.webp', 'https://www.flickr.com/photos/zaragozaantigua/20041953410/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25956, 'Quinta Julieta c.1985', 'Vista aâ”œآ®rea del poblado gitano Quinta Julieta, cuya denominaciâ”œâ”‚n se tomâ”œâ”‚ prestada de la finca de recreo prâ”œâ”‚xima. Fue construido en 1981 con la intenciâ”œâ”‚n de erradicar el chabolismo. En 1982 se trasladaron allâ”œآ، 140 familias, convirtiâ”œآ®ndose en foco de conflictos. En 1986 se constatâ”œâ”‚ el fracaso de la iniciativa, derribâ”œأ­ndose por completo. En la imagen, a la izquierda, el Canal Imperial de Aragâ”œâ”‚n. En el â”œأ­ngulo superior izquierdo, viviendas en la calle de Alhama de Aragâ”œâ”‚n del barrio de Torrero. La configuraciâ”œâ”‚n de este entorno en su zona norte ha cambiado radicalmente con la construcciâ”œâ”‚n del Tercer Cinturâ”œâ”‚n y el desvâ”œآ،o del Canal a su paso por el Barranco de la Muerte, aunque el solar donde se levantaba el gueto continâ”œâ•‘a en barbecho. Fuente visual: Foto: Archivo Taumar (Irene Taules y Rafael Margalâ”œآ®), en www.facebook.com/photo.php?fbid=1797322197158145&set=...', 1985, 1985, 1985, 'Anos 80', 'TORRERO', 41.62262500, -0.87011900, '0101000020E6100000691A14CD03D8EBBF04560E2DB2CF4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/36717050274.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/36717050274.webp', 'https://www.flickr.com/photos/zaragozaantigua/36717050274/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23376, 'Almenara de San Antonio 1833', '"Almenara de San Antonio de Padua", litografâ”œآ،a de Faramundo Blanchard. Esta almenara se encuentra en el actual barrio de San Josâ”œآ® de Zaragoza, junto al escorredero de la Media Legua. Fuente visual: "Memoria histâ”œâ”‚rica del Canal imperial de Aragon: noticia sobre las utilidades que produce, y esplicacion de lo que contienen las lâ”œأ­minas que se publican", Madrid, 1833.', 1833, 1833, 1833, 'Siglo XIX', 'TORRERO', 41.61713300, -0.86410100, '0101000020E6100000D21BEE23B7A6EBBF2524D236FECE4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20342130452.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20342130452.webp', 'https://www.flickr.com/photos/zaragozaantigua/20342130452/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23966, 'Monumento a la Legiâ”œâ”‚n 1974', 'Inauguraciâ”œâ”‚n oficial, el 15 de octubre de 1974, del Monumento Nacional a los muertos de la Legiâ”œâ”‚n, con presencia de Su Alteza Real el Principe Don Juan Carlos de Borbâ”œâ”‚n,al fondo. En la imagen, y tras la bendiciâ”œâ”‚n del monumento y el descubrimiento de la lâ”œأ­pida conmemorativa, ceremonia de la misa oficiada sobre el basamento que alberga una cripta. En posiciâ”œâ”‚n de saludo y en el centro, el Ministro del Ejâ”œآ®rcito, Francisco Coloma Gallegos. Despuâ”œآ®s fue el turno de los discursos, a cargo del coronel Caparrâ”œâ”‚s como presidente de la Hermandad de Antiguos Caballeros Legionarios de Zaragoza, entidad promotora; del alcalde Mariano Horno Liria; y del Ministro del Ejâ”œآ®rcito. Este monumento costâ”œâ”‚ 6 millones de pesetas, sufragado por suscripciâ”œâ”‚n popular, mâ”œأ­s una subvenciâ”œâ”‚n del Estado, y fue erigido en terreno municipal en los Pinares de Venecia, frente al Parque de Atracciones.', 1974, 1974, 1974, 'Anos 70', 'TORRERO', 41.62234000, -0.90071400, '0101000020E61000003A94A12AA6D2ECBF0F7F4DD6A8CF4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15022691281.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15022691281.webp', 'https://www.flickr.com/photos/zaragozaantigua/15022691281/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25193, 'Parque de Atracciones 2007', 'Plano guâ”œآ،a del Parque de Atracciones de Zaragoza, 2007. Este complejo de ocio fue inaugurado en 1974, en los Pinares de Venecia del monte de Torrero de Zaragoza.', 2007, 2007, 2007, 'Siglo XXI', 'TORRERO', 41.62146100, -0.89982100, '0101000020E6100000E620E86855CBECBFA65EB7088CCF4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20703638246.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20703638246.webp', 'https://www.flickr.com/photos/zaragozaantigua/20703638246/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25946, 'Carlos Mejâ”œآ،a Godoy 1977', 'Acuaciâ”œâ”‚n de Carlos Mejâ”œآ،a Godoy y Los de Palacagâ”œâ•‌ina en el Parque de Atracciones de Zaragoza. Fuente: www.facebook.com/photo.php?fbid=10205798525379308&set...', 1977, 1977, 1977, 'Anos 70', 'TORRERO', 41.62146100, -0.89982100, '0101000020E6100000E620E86855CBECBFA65EB7088CCF4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22537242682.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22537242682.webp', 'https://www.flickr.com/photos/zaragozaantigua/22537242682/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25950, 'Parque de Atracciones c.1983', 'Foto para postal del Parque de Atracciones, inaugurado en 1974 en el monte de Torrero. Al fondo, el Monumento a la Legiâ”œâ”‚n y los edificios de la Romareda y Universidad, tras el parque Primo de Rivera. Fuente: www.todocoleccion.net', 1983, 1983, 1983, 'Anos 80', 'TORRERO', 41.62146100, -0.89982100, '0101000020E6100000E620E86855CBECBFA65EB7088CCF4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27233996719.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27233996719.webp', 'https://www.flickr.com/photos/zaragozaantigua/27233996719/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21055, 'Puente de Amâ”œآ®rica c.1870', 'Museo del Prado. Antes de 1880. Imagen del primitivo Puente de Amâ”œآ®rica sobre el Canal Imperial, construido por militares del ejâ”œآ®rcito de Tierra, del Regimiento que llevaba ese nombre ("Amâ”œآ®rica"), en el aâ”œâ–’o 1815, en la Playa de Torrero, en un vado del Canal que se usaba para acceder a las canteras localizadas en lo que hoy es la Avenida de Amâ”œآ®rica. Este puente, de fâ”œأ­brica en piedra, mamposterâ”œآ،a y ladrillo, sin grandes alardes estilâ”œآ،sticos, fue luego restaurado varias veces a lo largo de siglo XIX, hasta que en en 1901 se plantea su demoliciâ”œâ”‚n y la construcciâ”œâ”‚n de un nuevo Puente, metâ”œأ­lico y mâ”œأ­s estiloso. El actual, que se construyâ”œâ”‚ en 1903. El puente de la imagen es el que aparece en la excepcional serie de grabados que en el aâ”œâ–’o 1833 jalona todas las grandes obras de acompaâ”œâ–’amiento (almenaras, puentes, presas, viaductos, esclusas...) del Canal Imperial de Aragâ”œâ”‚n. En la imagen se recoge ademâ”œأ­s, a la izquierda, la enorme entrada al dique de carena del puerto de Miraflores, el estado de las riberas, el camino de sirga, y embarcaciones que recuerdan que esa era una de las funciones principales del Canal: la navegaciâ”œâ”‚n.', 1870, 1870, 1870, 'Siglo XIX', 'TORRERO', 41.63307000, -0.88480700, '0101000020E61000002DB308C55650ECBF130A117008D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14858414484.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14858414484.webp', 'https://www.flickr.com/photos/zaragozaantigua/14858414484/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21164, 'Puente de Amâ”œآ®rica 1894', '"Canal Imperial de Pignatelli y el puente de Amâ”œآ®rica", un dibujo de J. Serra Pausas. En la imagen, el antiguo Puente de Amâ”œآ®rica sobre el Canal Imperial, construido en 1815 y restaurado varias veces a lo largo de siglo XIX. A la izquierda, la monumental entrada al dique de carena del proyectado puerto de Miraflores, y algunas embarcaciones. A la derecha, la "Playa de Torrero" como lugar de paseo, encuentro, y festejo ciudadano. Fuente: "La Ilustraciâ”œâ”‚n Ibâ”œآ®rica", Barcelona.', 1894, 1894, 1894, 'Siglo XIX', 'TORRERO', 41.63330200, -0.88454900, '0101000020E610000042B456B4394EECBFE63E390A10D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20921975008.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20921975008.webp', 'https://www.flickr.com/photos/zaragozaantigua/20921975008/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21174, 'Puente de Amâ”œآ®rica c.1898', 'Imagen del decimonâ”œâ”‚nico puente de Amâ”œآ®rica sobre el Canal Imperial. A la izquierda, la dâ”œأ­rsena para reparaciâ”œâ”‚n de embarcaciones. Al fondo, a la derecha, la harinera de Monares. Fuente visual: www.ebay.es/', 1898, 1898, 1898, 'Siglo XIX', 'TORRERO', 41.63326100, -0.88474300, '0101000020E61000007DAD4B8DD04FECBF876A4AB20ED14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31133290343.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31133290343.webp', 'https://www.flickr.com/photos/zaragozaantigua/31133290343/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21200, 'Puente de Amâ”œآ®rica c.1898', 'Desde la playa de Torrero, imagen del decimonâ”œâ”‚nico Puente de Amâ”œآ®rica sobre el Canal Imperial de Aragâ”œâ”‚n y el anexo dique seco para embarcaciones canalinas. En primer tâ”œآ®rmino y a la derecha, posado de unos simpâ”œأ­ticos personajes. En la rampa de bajada al canal entre le puente y el dique, lavanderas faenando.', 1898, 1898, 1898, 'Siglo XIX', 'TORRERO', 41.63325400, -0.88506400, '0101000020E610000001BEDBBC7152ECBFD50792770ED14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/53535438475.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/53535438475.webp', 'https://www.flickr.com/photos/zaragozaantigua/53535438475/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21203, 'Playa de Torrero 1894', 'Imagen capturada junto al estribo izquierdo recayente a la playa de Torrero del puente de Amâ”œآ®rica, con el objetivo orientado aguas abajo del Canal Imperial de Aragâ”œâ”‚n. A la derecha, barcaza de la empresa canalina estacionada junto a la chopera y viveros que daban continuidad a los diques para embarcaciones. A la izquierda, orilla del canal desprovista de barandilla y zona de paseo delimitada por ilustrados plâ”œأ­tanos de sombra. Al fondo, la gran casa de Pablo Salvador Lâ”œâ”‚pez que con su aspecto monumental cerraba la vista de este tranquilo entorno disfrutable tan lejos y tan cerca de la ciudad.', 1894, 1894, 1894, 'Siglo XIX', 'TORRERO', 41.63319200, -0.88453700, '0101000020E61000003143E389204EECBF5F0B7A6F0CD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54197148116.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54197148116.webp', 'https://www.flickr.com/photos/zaragozaantigua/54197148116/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21210, 'Vista de Zaragoza c.1900', 'Comienzos del siglo XX. Foto coloreada, tomada siguiendo el cauce de la antigua Acequia del Presidio, y la mâ”œأ­s moderna Acequia de El Plano, donde se acababa de instalar "La Zaragozana, Fâ”œأ­brica de Cerveza, Malta y Hielo" (1900). Tenemos una visual inmediata del Camino de las Alcachoferas, de la trinchera del ferrocarril de los directos a Barcelona (el pretil de piedra que recorre los campos de W-E, a mitad de imagen), y los campos de cereal, maâ”œآ،z y herbâ”œأ­ceas regados desde la Acequia de las Adulas, que acompaâ”œâ–’a al camino de las Torres (a la izquierda), y que posibilitâ”œâ”‚ que en esta zona se instalaran varios ingenios fabriles, como molinos de aceite, sierra de mâ”œأ­rmol, harineras, curtidoras, y a la altura de la torre de La Magdalena, las instalaciones de la Fâ”œأ­brica de Gas. El antiguo convento de San Josâ”œآ® de los Carmelitas Descalzos, en esta imagen realizaba las funciones de Penal.', 1900, 1900, 1900, 'Anos 1900', 'TORRERO', 41.63331800, -0.88018200, '0101000020E610000054E41071732AECBFECFB709010D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14958791625.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14958791625.webp', 'https://www.flickr.com/photos/zaragozaantigua/14958791625/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21250, 'Cuartel de Castillejos c.1900', 'Entre 1896 y 1910, el Cuartel de Torrero, o de los Castillejos, fue ocupado por el Regimiento de Lanceros del Rey (1â”¬â•‘ de Caballerâ”œآ،a del Ejâ”œآ®rcito Espaâ”œâ–’ol). En la imagen, algunos de los caballos regimentales abrevan. Al fondo, la iglesia neoclâ”œأ­sica de San Fernando, castrense capilla. Fuente visual: AHPZ-Archivo Coyne.', 1900, 1900, 1900, 'Anos 1900', 'TORRERO', 41.63465600, -0.88291900, '0101000020E6100000768BC058DF40ECBFE71A66683CD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20311560512.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20311560512.webp', 'https://www.flickr.com/photos/zaragozaantigua/20311560512/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21252, 'Puente de Amâ”œآ®rica c.1905', 'Imagen del nuevo Puente de Amâ”œآ®rica y la ribera del Canal Imperial. Tras el puente, la dâ”œأ­rsena para embarcaciones. A este lado del puente, el edificio de viviendas que supervive como nâ”¬â•‘ 1 de la Vâ”œآ،a de Ramâ”œâ”‚n Pignatelli. Fuente visual: TC, Postal "Cecilio Gasca".', 1905, 1905, 1905, 'Anos 1900', 'TORRERO', 41.63315800, -0.88520400, '0101000020E6100000713AC9569753ECBFB39943520BD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20455125812.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20455125812.webp', 'https://www.flickr.com/photos/zaragozaantigua/20455125812/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21293, 'Puente de Amâ”œآ®rica 1903', 'Imagen del Canal Imperial en el lugar del nuevo puente de Amâ”œآ®rica, proyectado por Josâ”œآ® Marâ”œآ،a Royo Villanova, con un gâ”œأ­libo rebajado al nivel de la calle para la circulaciâ”œâ”‚n rodada, lo que supuso que la navegabilidad del Canal para las grandes embarcaciones, primordial funciâ”œâ”‚n de esta ilustrada infraestructura, quedara interrumpida en ese punto. La imagen estâ”œأ­ capturada desde la denominada "playa" del Canal. Inmediata y fuera de plano, a la izquierda, la dâ”œأ­rsena para reparaciâ”œâ”‚n de embarcaciones en seco. Al fondo, edificios del nuevo barrio de "Venecia". En el momento de realizar esta imagen, la modernista decoraciâ”œâ”‚n de barandillas y farolas, diseâ”œâ–’adas por Ricardo Magdalena Tabuenca, aâ”œâ•‘n no habâ”œآ،a sido emplazada en su sitio, porque la estaba realizando el rejero Josâ”œآ® Gonzâ”œأ­lez. Una vez instalada, el puente fue inaugurado en octubre de ese aâ”œâ–’o. Fuente visual: Fototipia de Lucas Escolâ”œأ­, serie "Zaragoza", AMZ.', 1903, 1903, 1903, 'Anos 1900', 'TORRERO', 41.63326100, -0.88474300, '0101000020E61000007DAD4B8DD04FECBF876A4AB20ED14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/29292547262.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/29292547262.webp', 'https://www.flickr.com/photos/zaragozaantigua/29292547262/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21306, 'Canal Imperial c.1903', 'Imagen capturada junto al Canal Imperial de Aragâ”œâ”‚n en la pronunciada curva donde se deriva agua a la acequia del Ontonar. Al fondo, parte de las antiguas instalaciones de la Playa de Torrero reconvertidas en cuartel del ejâ”œآ®rcito. La gâ”œâ”‚ndola denominada Santa Cecilia o del Cisne (por la figura tallada en su proa) permanece amarrada en su posiciâ”œâ”‚n de descenso hacia la Quinta de Julieta Sagols, con un posado de sus pasajeros. A la derecha, posiblemente una vendedora del local periâ”œâ”‚dico independiente de dos ediciones diarias fundado en 1895, en su tradicional formato de sâ”œأ­bana. Fuente visual: Colecciâ”œâ”‚n Montserrat/Sociedad Estereoscâ”œâ”‚pica Espaâ”œâ–’ola (Barcelona), en Zaragoza estereoscâ”œâ”‚pica, fotografâ”œآ،a profesional y comercial 1850-1970, PUZ.', 1903, 1903, 1903, 'Anos 1900', 'TORRERO', 41.63273600, -0.88166400, '0101000020E6100000FAEFC16B9736ECBF3D80457EFDD04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34973623296.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34973623296.webp', 'https://www.flickr.com/photos/zaragozaantigua/34973623296/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21315, 'Playa de Torrero 1905', 'Dibujo anâ”œâ”‚nimo de la Playa de Torrero, entorno en las inmediaciones del Canal Imperial de Aragâ”œâ”‚n donde se erige un cuartel militar. Fuente: www.elmarcoverde.com', 1905, 1905, 1905, 'Anos 1900', 'TORRERO', 41.63363900, -0.88437700, '0101000020E6100000FAB48AFED04CECBF2E3C2F151BD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/37383811586.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/37383811586.webp', 'https://www.flickr.com/photos/zaragozaantigua/37383811586/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21333, 'Canal Imperial c.1900', 'Imagen capturada junto al Canal Imperial de Aragâ”œâ”‚n a la altura de la almenara de Santa Engracia. Al fondo, el antiguo puente de Amâ”œآ®rica bajo cuyo ojo aparece una de las barcazas de transporte de mercancâ”œآ،as por el canal y las casas de Salvador, antecedente de la torre de Dâ”œأ­maso Pina. A la derecha, el embarcadero del canal.', 1900, 1900, 1900, 'Anos 1900', 'TORRERO', 41.63357500, -0.88641600, '0101000020E61000001BD65416855DECBF174850FC18D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50938923578.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50938923578.webp', 'https://www.flickr.com/photos/zaragozaantigua/50938923578/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21348, 'Playa de Torrero 1908', 'Imagen capturada en la playa de Torrero con el fondo del nuevo puente de Amâ”œآ®rica. A la izquierda y en la margen derecha, chopera y vivero del Canal Imperial de Aragâ”œâ”‚n. A la derecha y entre los veteranos plâ”œأ­tanos de sombra, postes de suministro elâ”œآ®ctrico de la efâ”œآ،mera lâ”œآ،nea tranviaria del Arenal, de la que un coche se dirige a la terminal.', 1908, 1908, 1908, 'Anos 1900', 'TORRERO', 41.63287700, -0.88211400, '0101000020E6100000F3FFAA23473AECBFFFB1101D02D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54145726724.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54145726724.webp', 'https://www.flickr.com/photos/zaragozaantigua/54145726724/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21425, 'Merendero del Canal c.1915', 'Posado de Trinidad Cordero Adâ”œأ­n y Francisca Adâ”œأ­n Bayod a la orilla del Canal Imperial, en la llamada Playa de Torrero junto a otras personas, en la puerta del estanco que regentaba en el Merendero del Canal. Puede observarse la placa, que reza "Compaâ”œâ–’â”œآ،a Arrendataria de Tabacos", antecedente de Tabacalera. Estas instalaciones eran complementarias al embarcadero situado en la margen derecha del Canal Imperial de Aragâ”œâ”‚n, junto al puente de Amâ”œآ®rica (a la izquierda, fuera de plano) y frente al cuartel de Castillejos. Fuente: Colecciâ”œâ”‚n Josâ”œآ® Ignacio Larraz Vileta, a travâ”œآ®s de Heraldo de Aragâ”œâ”‚n.', 1915, 1915, 1915, 'Anos 10', 'TORRERO', 41.63331000, -0.88629700, '0101000020E6100000895FB1868B5CECBF691D554D10D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32353502266.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32353502266.webp', 'https://www.flickr.com/photos/zaragozaantigua/32353502266/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21434, 'Canal Imperial c.1915', 'Imagen del Canal Imperial y la playa de Torrero capturada desde el puente de Amâ”œآ®rica y convertida en postal por la fototipia Ediciâ”œâ”‚n Thomas. Centra la imagen la draga del Canal estacionada junto al dique de carena o dâ”œأ­rsena del antiguo puerto de Miraflores. A la izquierda, la playa de Torrero. Al fondo, la imponente torre de Dâ”œأ­maso Pina. A la derecha, los viveros municipales. Fuente visual: www.todocoleccion.net/', 1915, 1915, 1915, 'Anos 10', 'TORRERO', 41.63326100, -0.88474300, '0101000020E61000007DAD4B8DD04FECBF876A4AB20ED14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/37372494200.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/37372494200.webp', 'https://www.flickr.com/photos/zaragozaantigua/37372494200/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21549, 'Canal Imperial c.1925', 'Imagen parcial de la arbolada Playa de Torrero, desde el mirador a la izquierda del Puente de Amâ”œآ®rica. Al fondo, la torre de Dâ”œأ­maso Pina. Fuente visual: F. Mesas, en AMZ.', 1925, 1925, 1925, 'Anos 20', 'TORRERO', 41.63312600, -0.88343300, '0101000020E61000001FA166481545ECBFA71FD4450AD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20469601681.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20469601681.webp', 'https://www.flickr.com/photos/zaragozaantigua/20469601681/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21721, 'San Fernando 1930', 'Imagen de la iglesia neoclâ”œأ­sica de San Fernando.', 1930, 1930, 1930, 'Anos 30', 'TORRERO', 41.63465600, -0.88291900, '0101000020E6100000768BC058DF40ECBFE71A66683CD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20163724879.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20163724879.webp', 'https://www.flickr.com/photos/zaragozaantigua/20163724879/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21722, 'Vâ”œآ،a de San Fernando 1931', 'Una antigua vista de cuando nieva en Zaragoza. Este entorno tan arrabalero de postal, tan centroeuropeo por lo insâ”œâ”‚lito de la blanca cubierta, junto a la neoclâ”œأ­sica fâ”œأ­brica del edificio de la Iglesia de San Fernando. La acequia del Plano, a la izquierda, que toma agua del Canal en la Almenara de Sta. Engracia, daba riego a los huertos de la zona, y alimentaba despuâ”œآ®s al lavadero de La Balseta, y a los molinos de aceite, harina, e incluso temporalmente de aguardiente, en el final del Camino de San Josâ”œآ®. A este camino, mucho despuâ”œآ®s se la denominâ”œâ”‚ "Vâ”œآ،a" porque no fue ni calle hasta bien entrados los aâ”œâ–’os 60 del siglo XX. Hasta entonces fue un tranquilo camino rural que enlazaba la Avenida Siglo XX con el Camino de S. Josâ”œآ®. Apenas a diez minutos del "Centro", otro mundo. Fuente visual: Revista "Aragâ”œâ”‚n", SIPA, diciembre 1931.', 1931, 1931, 1931, 'Anos 30', 'TORRERO', 41.63487400, -0.88315400, '0101000020E6100000569C6A2DCC42ECBF558A1D8D43D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20301250452.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20301250452.webp', 'https://www.flickr.com/photos/zaragozaantigua/20301250452/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21723, 'San Fernando 1930', 'Imagen de la iglesia neoclâ”œأ­sica de San Fernando.', 1930, 1930, 1930, 'Anos 30', 'TORRERO', 41.63465600, -0.88291900, '0101000020E6100000768BC058DF40ECBFE71A66683CD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20324205716.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20324205716.webp', 'https://www.flickr.com/photos/zaragozaantigua/20324205716/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21769, 'Casa Bergua 1933', 'Imagen de la racionalista y singular "casa particular" de Matâ”œآ،as Bergua Olivâ”œأ­n, obra del arquitecto Rafael Bergamâ”œآ،n, en la achaflanada esquina entre el paseo de Ruiseâ”œâ–’ores y el paseo del Canal. Esta vista ha sido capturada desde la confluencia de ambos paseos. Al fondo, a la izquierda, excepcional y parcial vista de los tejados de la original Residencia de Estudiantes de la Universidad de Zaragoza. Fuente visual: "Arquitectura" (Madrid).', 1933, 1933, 1933, 'Anos 30', 'TORRERO', 41.63423200, -0.89016700, '0101000020E6100000514F1F813F7CECBFD009A1832ED14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22642430775.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22642430775.webp', 'https://www.flickr.com/photos/zaragozaantigua/22642430775/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21807, 'Canal Imperial 1935', '"Canal Imperial al seu pas per l''arsenal de Saragossa". Imagen capturada desde la margen izquierda del Canal Imperial en el entorno del antiguo puerto de Miralflores y centrado en una de las grandes barcas de transporte canalino ubicadas (vista parcial a la derecha) junto al dique de carena de reparaciâ”œâ”‚n de embarcaciones que en algunas fuentes es referido como "arsenal". Adaptadas al gâ”œأ­libo del modernista puente de Amâ”œآ®rica, estas barcazas solâ”œآ،an ser utilizadas para traer materiales de construcciâ”œâ”‚n de la nueva barriada de Venecia. Al fondo, tras el "arsenal", luminosa fachada del referencial inmueble del nâ”¬â•‘ 1 de la vâ”œآ،a de Pignatelli, esquinero con la avenida de Amâ”œآ®rica. Fuente visual: Fotografâ”œآ،a de S. Gosâ”œآ® en Arxiu Nacional de Catalunya.', 1935, 1935, 1935, 'Anos 30', 'TORRERO', 41.63319200, -0.88453700, '0101000020E61000003143E389204EECBF5F0B7A6F0CD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/28506821518.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/28506821518.webp', 'https://www.flickr.com/photos/zaragozaantigua/28506821518/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21959, 'San Fernando 1949', '"Fachada de la Iglesia de San Fernando de Torrero. Campanario". Fuente visual: AHPZ, Archivo Coyne', 1949, 1949, 1949, 'Anos 40', 'TORRERO', 41.63465600, -0.88291900, '0101000020E6100000768BC058DF40ECBFE71A66683CD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20177382188.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20177382188.webp', 'https://www.flickr.com/photos/zaragozaantigua/20177382188/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22001, 'Capuchinos 1946', 'Imagen de las traseras del Sacrario Militare Italiano, o "Torre Funeraria, Iglesia y Convento de Capuchinos en Zaragoza para Panteâ”œâ”‚n de italianos muertos en la cruzada espaâ”œâ–’ola y servicios de culto". El conjunto ya ha sido finalizado (Torre e Iglesia, a la izquierda; Convento, a la derecha) y esta zona, recayente a la calle de las Escuelas, redenominada Maestro Estremiana, estaba comenzando a ser urbanizada. La vegetaciâ”œâ”‚n de primer plano, a la izquierda, ribereâ”œâ–’a de un brazal de la acequia de Ontanar. Fuente visual: La arquitectura de Vâ”œآ،ctor Eusa, Fernando Tabuenca Gonzâ”œأ­lez.', 1946, 1946, 1946, 'Anos 40', 'TORRERO', 41.63500400, -0.88744500, '0101000020E610000084F57F0EF365ECBF236AA2CF47D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33689135640.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33689135640.webp', 'https://www.flickr.com/photos/zaragozaantigua/33689135640/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22053, 'Canal Imperial 1956', '1956. Josâ”œآ® Antonio Duce captura un instante del atardecer canicular en la "Playa de Torrero". A la izquierda, en la otra orilla, Torrero, y sus edificios vinculados al Canal Imperial. A este lado, la playa y el acuartelamiento de Castillejos. Pasa un coche y levanta una polvareda. A nadie le importa. Los paseantes van hacia el Puente de Amâ”œآ®rica.', 1956, 1956, 1956, 'Anos 50', 'TORRERO', 41.63333400, -0.88388900, '0101000020E6100000A1698995D148ECBFF1B8A81611D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14897909156.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14897909156.webp', 'https://www.flickr.com/photos/zaragozaantigua/14897909156/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22337, 'Paseo de Cuâ”œآ®llar 1969', 'Cruce de tranvâ”œآ،as de la lâ”œآ،nea 5 (Torrero) en el Paseo Cuâ”œآ®llar a la altura del Acuartelamiento de Castillejos (derecha). Al fondo, la arboleda del Parque Pignatelli. Los tranvâ”œآ،as son de la serie 50-65, construidos en Carde y Escoriaza en 1925, y llevan remolque de la serie 70. Fuente: "Los tranvâ”œآ،as de Zaragoza", J. Peâ”œâ–’a - J. M. Valero, DPZ, 1985.', 1969, 1969, 1969, 'Anos 60', 'TORRERO', 41.63462500, -0.88487100, '0101000020E6100000DCB8C5FCDC50ECBFAC1C5A643BD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20045559389.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20045559389.webp', 'https://www.flickr.com/photos/zaragozaantigua/20045559389/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22346, 'La Balseta 1961', 'Dibujo de "la Balseta" realizado por Luis Basurte como recuerdo del antiguo y desaparecido lavadero de ese nombre al final de la cuesta de Morâ”œâ”‚n, en la avenida de San Josâ”œآ®. Los edificios del fondo, desaparecidos, eran viviendas conocidas como "el Molino Rosa". Ahora hay en su lugar el moderno bloque de viviendas del nâ”¬â•‘ 209 de la avenida. A la derecha, la Salle Torrero. Fuente visual: AVV. San Josâ”œآ®.', 1961, 1961, 1961, 'Anos 60', 'TORRERO', 41.63428900, -0.88155600, '0101000020E610000062F6B2EDB435ECBF359BC76130D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20318416672.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20318416672.webp', 'https://www.flickr.com/photos/zaragozaantigua/20318416672/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22409, 'Calle Maestro Estremiana 1968', 'Imagen de la reciâ”œآ®n inaugurada residencia de la ONCE para seâ”œâ–’oritas invidentes Nuestra Seâ”œâ–’ora del Pilar, en la calle del Maestro Estremiana 25-27, regida por religiosas de la Congregaciâ”œâ”‚n de Hermanas Angâ”œآ®licas. Desde 1989 alojaba ancianos y fue clausurada en 2006. El edificio pervive, reconvertido y recrecido. Fuente: Agencia EFE.', 1968, 1968, 1968, 'Anos 60', 'TORRERO', 41.63524200, -0.88806900, '0101000020E6100000F2ECF2AD0F6BECBFD7851F9C4FD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24587873126.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24587873126.webp', 'https://www.flickr.com/photos/zaragozaantigua/24587873126/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22509, 'La Balseta, c.1965', 'Imagen capturada desde la relativa altura de las casas para empleados del Canal Imperial de la calle del Barâ”œâ”‚n de La Linde, centrada en el antiguo lavadero pâ”œâ•‘blico de La Balseta, al final de la avenida de San Josâ”œآ®. En esta extraordinaria fotografâ”œآ،a se aprecia perfectamente la moderna cobertura para resguardo de sol y lluvia, cuyas muestras de deterioro se fueron agravando por falta de mantenimiento hasta el derribo final de este lavadero a comienzos de la dâ”œآ®cada de los convulsos aâ”œâ–’os 70. Era el lavadero mâ”œأ­s antiguo de la ciudad, realizado cuando a finales del siglo XVIII llegâ”œâ”‚ hasta aquâ”œآ، el agua del Canal Imperial de Aragâ”œâ”‚n. En el momento de realizar la fotografâ”œآ،a se aprecia la sombra junto al agua de una lavandera faenando con ropa. Al fondo, tramo de los nâ”œâ•‘meros 205-211 de la avenida, entre una calle sin nombre que a la izquierda conducâ”œآ،a a la calle de Luis Royo Villanova, y el cauce al aire de la acequia del Plano a la derecha (fuera de plano), que tras surtir del agua a la Balseta hacâ”œآ،a lo propio con el antiguo "Molino Rosa" y, mâ”œأ­s abajo, llegaba a la harinera de la Industrial SAPASA.(antigua de Morâ”œâ”‚n).', 1965, 1965, 1965, 'Anos 60', 'TORRERO', 41.63431300, -0.88157700, '0101000020E610000040FCFCF7E035ECBFBD361B2B31D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50917833316.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50917833316.webp', 'https://www.flickr.com/photos/zaragozaantigua/50917833316/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
